INSERT INTO `habilidades` (`ID_habilidade`, `ID_campeao`, `tecla`, `nome_habilidade`, `descricao`, `imagem_url`) VALUES
('AatroxE', 1, 'E', 'Avanço Umbral', 'Passivamente, Aatrox se cura quando causa dano a Campeões inimigos. Quando ativado, ele avança em uma direção.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AatroxE.png'),
('AatroxQ', 1, 'Q', 'A Espada Darkin', 'Aatrox bate sua espada no chão, causando Dano Físico. Ele pode bater até três vezes, cada vez em uma área de ação diferente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AatroxQ.png'),
('AatroxR', 1, 'R', 'Aniquilador de Mundos', 'Aatrox libera sua forma demoníaca, aterrorizando tropas inimigas próximas, ganhando Dano de Ataque, cura aumentada e Velocidade de Movimento. Se ele conseguir um abate, este efeito é estendido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AatroxR.png'),
('AatroxW', 1, 'W', 'Correntes Infernais', 'Aatrox bate no chão, causando dano ao primeiro inimigo atingido. Campeões e Monstros Grandes precisam sair da área de impacto rapidamente ou serão arrastados para o centro e receberão dano novamente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AatroxW.png'),
('Aatrox_P', 1, 'P', 'Postura do Arauto da Morte', 'Periodicamente, o próximo ataque básico de Aatrox causa Dano Físico adicional e o cura com base na Vida máxima do alvo. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Aatrox_Passive.png'),
('AhriE', 2, 'E', 'Encanto', 'Ahri manda um beijo que causa dano e encanta um inimigo, interrompendo imediatamente qualquer habilidade de movimento em progresso e fazendo com que ele ande inofensivamente em sua direção.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AhriE.png'),
('AhriQ', 2, 'Q', 'Orbe da Ilusão', 'Ahri lança e puxa de volta seu orbe, causando Dano Mágico na ida e Dano Verdadeiro na volta. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AhriQ.png'),
('AhriR', 2, 'R', 'Ímpeto Espiritual', 'Ahri avança e dispara raios de essência, causando dano a inimigos próximos. Ímpeto Espiritual pode ser conjurada até três vezes antes de entrar em Tempo de Recarga e ganha reconjurações adicionais ao eliminar Campeões inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AhriR.png'),
('AhriW', 2, 'W', 'Fogo de Raposa', 'Ahri recebe um breve impulso de Velocidade de Movimento e lança três Fogos de Raposa que perseguem e atacam inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AhriW.png'),
('Ahri_P', 2, 'P', 'Furto de Essência', 'Depois de abater 9 tropas ou monstros, Ahri se cura.Depois de eliminar um Campeão inimigo, Ahri se cura em uma quantidade ainda maior.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Ahri_SoulEater2.png'),
('AkaliE', 3, 'E', 'Investida Shuriken', 'Salta para trás e atira uma shuriken para a frente, causando Dano Mágico. O primeiro inimigo ou nuvem de fumaça que forem atingidos são marcados. Conjure novamente para avançar ao alvo marcado, causando dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AkaliE.png'),
('AkaliQ', 3, 'Q', 'Golpe dos Cinco Pontos', 'Akali atira cinco kunais, causando redução de velocidade e dano com base em seu Dano de Ataque adicional e Poder de Habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AkaliQ.png'),
('AkaliR', 3, 'R', 'Execução Perfeita', 'Akali salta em uma direção, causando dano aos inimigos que atingir. Conjurar novamente: Akali avança em uma direção, executando todos os inimigos que atingir.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AkaliR.png'),
('AkaliW', 3, 'W', 'Proteção do Crepúsculo', 'Akali solta uma proteção de fumaça e recebe Velocidade de Movimento por um curto período. Enquanto estiver dentro da proteção, Akali se torna invisível e não pode ser selecionada como alvo de habilidades e ataques inimigos. Atacar ou usar habilidades fará com que ela seja revelada brevemente.  ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AkaliW.png'),
('Akali_P', 3, 'P', 'Marca do Assassino', 'Causar dano a Campeões com habilidades cria um círculo de energia em volta deles. Sair desse círculo fortalece o próximo Ataque de Akali com alcance e dano adicionais.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Akali_P.png'),
('AkshanE', 4, 'E', 'Impulso Heroico', 'Akshan dispara um arpéu em um terreno e se balança ao redor dele, atirando repetidamente no inimigo mais próximo enquanto estiver se balançando. Ele pode saltar antecipadamente ou ser derrubado ao colidir com Campeões ou terrenos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AkshanE.png'),
('AkshanQ', 4, 'Q', 'Bumerangue Vingativo', 'Akshan arremessa um bumerangue que causa dano na ida e na volta, ganhando alcance a cada vez que atingir um inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AkshanQ.png'),
('AkshanR', 4, 'R', 'Punição', 'Akshan trava a mira em um Campeão inimigo e começa a armazenar balas. Ao terminar, ele dispara todas as balas armazenadas, causando dano com base na Vida perdida do primeiro Campeão, tropa ou estrutura que atingir.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AkshanR.png'),
('AkshanW', 4, 'W', 'Rebeldia', 'Akshan marca Campeões inimigos passivamente como Canalhas quando eles abatem Campeões aliados. Se Akshan abater um Canalha, ressuscita o aliado abatido, recebendo ouro adicional e removendo todas as marcas.Quando a Habilidade é ativada, Akshan fica camuflado, recebendo Velocidade de Movimento e Regeneração de Mana enquanto se move em direção a Canalhas. Akshan perde a camuflagem rapidamente enquanto não estiver em um arbusto ou próximo a um terreno.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AkshanW.png'),
('Akshan_P', 4, 'P', 'Lutando Sujo', 'Os Ataques e Habilidades de Akshan causam dano adicional a cada terceiro acerto e concedem a ele um Escudo se o alvo for um Campeão.Ao Atacar, ele desfere um Ataque adicional que causa dano reduzido. Se cancelar o Ataque adicional, ele recebe Velocidade de Movimento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/akshan_p.png'),
('AlistarE', 5, 'E', 'Atropelar', 'Alistar atropela unidades inimigas próximas, ignorando colisão com unidades e recebendo acúmulos caso cause dano a um Campeão inimigo. O próximo ataque básico com o máximo de acúmulos contra um Campeão inimigo causa Dano Mágico adicional e o atordoa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AlistarE.png'),
('Alistar_P', 5, 'P', 'Urro Triunfante', 'Alistar carrega seu urro ao atordoar, deslocar a posição de Campeões inimigos ou quando inimigos próximos morrem. Quando estiver com o máximo de cargas, ele cura a si mesmo e aos Campeões aliados próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Alistar_E.png'),
('AlphaStrike', 79, 'Q', 'Ataque Alpha', 'Master Yi se teleporta pelo campo de batalha tão rápido que não pode ser visto, causando Dano Físico a várias unidades pelo caminho enquanto fica inalvejável. O Ataque Alpha pode causar Acerto Crítico e Dano Físico adicional contra monstros. Ataques básicos reduzem o Tempo de Recarga de Ataque Alpha.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AlphaStrike.png'),
('Amumu_P', 6, 'P', 'Toque Amaldiçoado', 'Os ataques básicos de Amumu Amaldiçoam seus inimigos, fazendo com que recebam Dano Verdadeiro adicional de qualquer Dano Mágico causado a eles.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Amumu_Passive.png'),
('Anivia_P', 7, 'P', 'Renascimento', 'Ao receber dano letal, Anivia volta à forma de ovo e renasce com a Vida completa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Anivia_P.png'),
('AnnieE', 8, 'E', 'Escudo Fundido', 'Annie concede um Escudo e um impulso de Velocidade de Movimento a si ou a um aliado, causando dano a inimigos que a atingirem com Ataques ou Habilidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AnnieE.png'),
('AnnieQ', 8, 'Q', 'Desintegrar', 'Annie arremessa uma bola de fogo infundida em Mana, causando dano e recuperando o custo de Mana caso o alvo seja destruído.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AnnieQ.png'),
('AnnieR', 8, 'R', 'Invocar: Tibbers', 'Annie dá vida ao urso Tibbers, causando dano a unidades na área. Tibbers pode atacar e também queimar inimigos que ficarem próximos a ele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AnnieR.png'),
('AnnieW', 8, 'W', 'Incinerar', 'Annie conjura um ardente cone de fogo, causando dano em todos os inimigos na área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AnnieW.png'),
('Annie_P', 8, 'P', 'Piromania', 'Após conjurar 4 Habilidades, a próxima Habilidade ofensiva de Annie atordoará o alvo.Annie começa a partida e ressurge com Piromania disponível.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Annie_Passive.png'),
('ApheliosE_ClientTool', 9, 'E', 'Sistema de Ordenação de Armas', 'Aphelios não tem uma terceira habilidade. Este espaço mostra a próxima arma que Alune concederá a ele. A ordem das armas é fixa, mas pode variar ao longo da partida. Quando uma arma estiver sem munição, ela volta para o fim da sequência.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ApheliosE_ClientTooltipWrapper.png'),
('ApheliosQ_ClientTool', 9, 'Q', 'Habilidades da arma', 'Aphelios tem 5 habilidades diferentes que são ativadas com base em sua arma principal:Calibrum (Rifle): Tiro de longo alcance que marca seu alvo para um disparo de longo alcance subsequente.Severum (Pistola-Foice): Corre rapidamente enquanto ataca inimigos próximos com ambas as armas.Gravitum (Canhão): Enraíza todos os inimigos afetados pela redução de velocidade desta arma.Infernum (Lança-chamas): Explode inimigos em área de cone e os ataca com sua arma secundária.Crescendum (Chakram): Posiciona uma atalaia que dispara com sua arma secundária.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ApheliosQ_ClientTooltipWrapper.png'),
('ApheliosR', 9, 'R', 'Vigília do Plenilúnio', 'Dispara uma rajada concentrada de luar que explode ao atingir Campeões inimigos. Aplica o efeito único da arma principal de Aphelios.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ApheliosR.png'),
('ApheliosW', 9, 'W', 'Fase', 'Aphelios troca a arma principal por sua arma secundária, substituindo seu ataque básico e a habilidade ativada.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ApheliosW.png'),
('Aphelios_P', 9, 'P', 'O Assassino e a Profetisa', 'Aphelios empunha 5 Armas Lunari criadas por sua irmã, Alune. Ele tem acesso a duas ao mesmo tempo: uma principal e uma secundária. Cada arma tem um ataque básico e uma Habilidade únicos. Ataques e habilidades consomem uma munição da arma. Quando fica sem munição, Aphelios descarta a arma e Alune invoca a próxima. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/ApheliosP.png'),
('AsheQ', 10, 'Q', 'Concentração', 'Ashe acumula Foco ao atacar. Quando o Foco chega ao máximo, Ashe pode conjurar Concentração para consumir todos os acúmulos de Foco, aumentando temporariamente sua Velocidade de Ataque e transformando seu ataque básico em uma poderosa rajada de ataques pela duração do efeito.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AsheQ.png'),
('AsheSpiritOfTheHawk', 10, 'E', 'Olhar do Falcão', 'Ashe envia seu Espírito do Falcão em uma missão de exploração em qualquer ponto do mapa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AsheSpiritOfTheHawk.png'),
('Ashe_P', 10, 'P', 'Tiro Congelado', 'Os ataques de Ashe reduzem a velocidade do alvo e fazem com que ela cause mais dano a ele.Os Acertos Críticos de Ashe não causam dano adicional, mas reduzem ainda mais a velocidade do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Ashe_P.png'),
('AspectOfTheCougar', 90, 'R', 'Aspecto do Puma', 'Nidalee transforma-se em um puma, recebendo novas habilidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AspectOfTheCougar.png'),
('AuraofDespair', 6, 'W', 'Desespero', 'Tomados pela angústia, inimigos próximos perdem um percentual de sua Vida máxima a cada segundo e suas Maldições são restauradas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AuraofDespair.png'),
('AurelionSolE', 11, 'E', 'Singularidade', 'Aurelion Sol invoca um buraco negro, causando dano aos inimigos e puxando-os lentamente para o centro. A Habilidade concede Poeira Estelar sempre que um inimigo morre dentro do buraco negro e a cada segundo que um Campeão inimigo passar preso dentro dele. O centro do buraco negro executa inimigos que estiverem com a Vida abaixo de uma determinada porcentagem da Vida máxima. Poeira Estelar aumenta a área e o limiar de execução de Singularidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AurelionSolE.png'),
('AurelionSolQ', 11, 'Q', 'Sopro de Luz', 'Aurelion Sol canaliza seu hálito de dragão por alguns segundos, causando dano ao primeiro inimigo atingido e espalhando dano reduzido a inimigos próximos. O hálito causará dano adicional para cada segundo que for canalizado diretamente em um inimigo, ficando mais forte à medida que coleta mais Poeira Estelar. Essa habilidade coleta Poeira Estelar se o alvo for um Campeão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AurelionSolQ.png'),
('AurelionSolR', 11, 'R', 'Estrela Cadente/Os Céus Caem', 'Estrela Cadente: Aurelion Sol faz uma estrela cair na terra. O impacto causa Dano Mágico e atordoa inimigos, além de conceder Poeira Estelar a cada Campeão inimigo atingido. Obter Poeira Estelar suficiente transformará a próxima Estrela Cadente de Aurelion Sol em Os Céus Caem. Os Céus Caem: Aurelion Sol faz cair uma estrela gigante dos céus com zona de impacto e dano aumentados, além de arremessar os inimigos ao ar em vez de atordoá-los. Depois, uma onda de choque se espalha a partir do limite da zona de impacto, causando dano e Lentidão aos inimigos atingidos. Poeira Estelar aumenta a área de impacto tanto de Estrela Cadente quanto de Os Céus Caem.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AurelionSolR.png'),
('AurelionSolW', 11, 'W', 'Voo Astral', 'Aurelion Sol voa sobre terrenos na direção-alvo. Enquanto estiver nesse estado, ele pode conjurar outras habilidades. Sopro de Luz não tem mais Tempo de Recarga ou duração máxima de canalização e causa dano aumentado durante o voo. O Tempo de Recarga restante de Voo Astral é reduzido sempre que um Campeão inimigo que sofreu dano recente de Aurelion Sol morre. Poeira Estelar aumenta o alcance máximo de Voo Astral.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AurelionSolW.png'),
('AurelionSol_P', 11, 'P', 'Criador Cósmico', 'As Habilidades de dano de Aurelion Sol reduzem inimigos a acúmulos de Poeira Estelar, melhorando permanentemente cada uma das Habilidades dele. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/AurelionSolP.png'),
('AzirEWrapper', 12, 'E', 'Areias Oscilantes', 'Azir se protege com um escudo por um momento e avança na direção de um de seus Soldados de Areia, causando dano aos inimigos atingidos. Se Azir acertar um Campeão inimigo, ele prepara instantaneamente um novo Soldado de Areia para mobilização e cessa seu avanço.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AzirEWrapper.png'),
('AzirQWrapper', 12, 'Q', 'Areias da Conquista', 'Azir comanda todos os Soldados de Areia na direção do local-alvo. Eles causam Dano Mágico aos inimigos que atravessam e aplicam redução de velocidade por 1 segundo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AzirQWrapper.png'),
('AzirR', 12, 'R', 'Decreto do Imperador', 'Azir invoca uma parede de soldados que marcha em frente, causando dano e empurrando para trás os inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AzirR.png'),
('AzirW', 12, 'W', 'Surja!', 'Azir invoca um Soldado de Areia para atacar alvos próximos por ele, substituindo seu ataque básico contra alvos dentro do alcance do soldado. Seu ataque causa Dano Mágico a inimigos em linha reta. Surja! também concede Velocidade de Ataque passiva a Azir e seus Soldados de Areia.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/AzirW.png'),
('Azir_P', 12, 'P', 'Legado de Shurima', 'Azir pode invocar o Disco Solar das ruínas de uma torre aliada ou inimiga.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Azir_Passive.png'),
('BandageToss', 6, 'Q', 'Lançar Bandagens', 'Amumu lança uma bandagem pegajosa em seu alvo e se lança em sua direção, causando dano e atordoamento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BandageToss.png'),
('BardE', 13, 'E', 'Jornada Mágica', 'Bardo abre um portal em terreno próximo. Tanto aliados quanto inimigos podem fazer uma viagem de ida através deste terreno ao entrar pelo portal.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BardE.png'),
('BardQ', 13, 'Q', 'Prisão Cósmica', 'Bardo dispara um projétil que causa Lentidão ao primeiro inimigo atingido, mantendo seu trajeto em seguida. Caso atinja uma parede, atordoará o alvo inicial; caso atinja outro inimigo, ambos serão atordoados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BardQ.png'),
('BardR', 13, 'R', 'Têmpera do Destino', 'Bardo desfere um arco de energia espiritual em um local-alvo, colocando todos os Campeões, tropas, monstros e torres atingidos em estase por um curto período de tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BardR.png'),
('BardW', 13, 'W', 'Santuário do Protetor', 'Revela um santuário de Vida que fica mais forte ao longo de um curto período, desaparecendo depois de curar e acelerar o primeiro aliado que o tocar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BardW.png'),
('Bard_P', 13, 'P', 'Chamado do Viajante', 'Mipes: Bardo atrai pequenos espíritos que ajudam em seus ataques básicos e causam Dano Mágico adicional. Quando Bardo coleta sinos o suficiente, os mipes também causam dano em uma área e reduzem a velocidade de inimigos atingidos.Sinos: sinos ancestrais aparecem aleatoriamente para Bardo coletar. Eles concedem experiência, Velocidade de Movimento fora de combate e restauram Mana.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Bard_Passive.png'),
('BelvethE', 14, 'E', 'Turbilhão da Realeza', 'Bel\'Veth se enraíza num lugar, canalizando uma tempestade de golpes ao redor de si, visando o inimigo com a Vida mais baixa, além de receber Roubo de Vida e redução de dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BelvethE.png'),
('BelvethQ', 14, 'Q', 'Impulso do Vazio', 'Bel\'Veth avança na direção escolhida e causa dano a todos os inimigos atravessados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BelvethQ.png'),
('BelvethR', 14, 'R', 'Banquete Eterno', 'Bel\'Veth consome os restos de Coral do Vazio e revela sua Forma Verdadeira, aumentando a própria Vida máxima, Alcance de Ataque, Velocidade de Ataque e Velocidade de Movimento fora de combate. Consumir Coral do Vazio dos restos de um monstro épico concederá a ela uma ultimate de maior duração, assim como a capacidade de invocar rêmoras do Vazio.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BelvethR.png'),
('BelvethW', 14, 'W', 'Acima e Abaixo', 'Bel\'Veth bate a cauda no chão, causando dano e Lentidão, além de Arremessar os inimigos ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BelvethW.png'),
('Belveth_P', 14, 'P', 'Morte em Lavanda ', 'Bel\'Veth recebe acúmulos de Velocidade de Ataque permanente depois de eliminar tropas, monstros grandes e Campeões. Além disso, ela recebe Velocidade de Ataque adicional temporária depois de usar uma Habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Belveth_Passive.png'),
('BlindingDart', 134, 'Q', 'Dardo Ofuscante', 'Obscurece a visão de um inimigo com um poderoso veneno, causando dano à unidade-alvo e cegando-a pela duração do efeito.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BlindingDart.png'),
('BlindMonkEOne', 69, 'E', 'Tempestade / Mutilar', 'Tempestade: Lee Sin golpeia o chão, enviando uma onda de choque que causa Dano Mágico e revela unidades inimigas atingidas. Se Tempestade atingir um inimigo, Lee Sin pode conjurar Mutilar nos próximos 3s.Mutilar: Lee Sin mutila inimigos próximos que tenham sido atingidos por Tempestade, reduzindo a Velocidade de Movimento deles por 4s. A Velocidade de Movimento é recuperada gradualmente ao longo da duração.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BlindMonkEOne.png'),
('BlindMonkQOne', 69, 'Q', 'Onda Sônica / Ataque Ressonante', 'Onda Sônica: Lee Sin projeta uma onda sonora para localizar seus inimigos, causando Dano Físico ao primeiro que encontrar. Se Onda Sônica atingir um inimigo, Lee Sin pode conjurar Ataque Ressonante nos próximos 3 segundos.Ataque Ressonante: Lee Sin avança no inimigo atingido por Onda Sônica, causando Dano Físico baseado na Vida perdida do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BlindMonkQOne.png'),
('BlindMonkRKick', 69, 'R', 'Fúria do Dragão', 'Lee Sin executa um poderoso chute giratório, arremessando seu alvo para trás e causando Dano Físico ao alvo e a qualquer inimigo com quem ele colidir. Esses inimigos são lançados ao ar durante um curto período. Essa técnica foi ensinada a ele por Jesse Perring, mas Lee Sin não chuta os jogadores para fora do mapa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BlindMonkRKick.png'),
('BlindMonkWOne', 69, 'W', 'Proteger / Vontade de Ferro', 'Proteger: Lee Sin avança até um alvo aliado, protegendo a si mesmo do dano. Se o aliado for um Campeão, ele também é protegido. Após usar Proteger, Lee Sin pode conjurar Vontade de Ferro dentre os próximos 3 segundos.Vontade de Ferro: O treinamento intenso de Lee Sin permite que ele fique mais resistente em combate. Por 4 segundos, ele recebe Roubo de Vida e Vampirismo Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BlindMonkWOne.png'),
('Blitzcrank_P', 15, 'P', 'Barreira de Mana', 'Blitzcrank recebe um Escudo com base em seu Mana ao ficar com a Vida baixa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Blitzcrank_ManaBarrier.png'),
('BrandE', 16, 'E', 'Conflagração', 'Brand conjura uma poderosa explosão no alvo que se espalha para inimigos próximos, causando Dano Mágico. Se o alvo estiver incandescente, o alcance de Conflagração será dobrado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BrandE.png'),
('BrandQ', 16, 'Q', 'Cauterizar', 'Brand lança uma bola de fogo que causa Dano Mágico. Se o alvo estiver incandescente, Cauterizar o atordoará por 1,5s.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BrandQ.png'),
('BrandR', 16, 'R', 'Piroclasma', 'Brand desfere uma devastadora torrente de fogo que ressalta 5 vezes, indo de Brand aos inimigos próximos e causando Dano Mágico a cada vez que ressaltar. Os ressaltos priorizam acumular Labareda ao máximo em Campeões. Se o alvo estiver incandescente, Piroclasma causará breve Lentidão a ele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BrandR.png'),
('BrandW', 16, 'W', 'Pilar de Chamas', 'Após um curto intervalo, Brand cria um Pilar de Chamas na área alvo, causando Dano Mágico a unidades inimigas na área. Unidades que estiverem incandescentes sofrem 25% de dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BrandW.png'),
('Brand_P', 16, 'P', 'Labareda', 'As habilidades de Brand deixam seus alvos incandescentes, causando dano ao longo de 4s, acumulando até 3 vezes. Se Brand abate um inimigo que estiver incandescente, ele recupera Mana. Quando Labareda chegar ao máximo de acúmulos em um Campeão ou monstro grande, ela se torna instável. Detona depois de 2s, aplicando efeitos de habilidades e causando muito dano em uma área ao redor da vítima.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/BrandP.png'),
('BraumE', 17, 'E', 'Inquebrável', 'Braum levanta seu escudo em uma direção por muitos segundos, interceptando todos os projéteis e fazendo com que o atinjam e sejam destruídos. Ele nega completamente o dano do primeiro ataque e reduz o dano de todos os ataques seguintes provenientes da mesma direção.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BraumE.png'),
('BraumQ', 17, 'Q', 'Mordida do Inverno', 'Braum dispara rajadas congelantes de seu escudo, causando Dano Mágico e redução de velocidade.Aplica um acúmulo de Golpes Concussivos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BraumQ.png'),
('BraumRWrapper', 17, 'R', 'Fissura Glacial', 'Braum golpeia o chão, arremessando ao ar inimigos próximos e em linha reta à sua frente. Uma fissura é deixada no caminho, causando redução de velocidade nos inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BraumRWrapper.png'),
('BraumW', 17, 'W', 'Eu te Protejo', 'Braum salta à frente de um Campeão ou tropa aliada alvo. Ao aterrissar, ele e o aliado recebem Armadura e Resistência Mágica por alguns segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BraumW.png'),
('Braum_P', 17, 'P', 'Golpes Concussivos', 'Os ataques básicos de Braum aplicam Golpes Concussivos. Uma vez que o primeiro acúmulo é aplicado, os ataques básicos de aliados também acumulam Golpes Concussivos. Ao atingir 4 acúmulos, o alvo é atordoado e sofre Dano Mágico. Pelos próximos segundos, ele não pode receber acúmulos, mas recebe Dano Mágico adicional dos ataques de Braum.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Braum_Passive.png'),
('BriarE', 18, 'E', 'Grito Arrepiante', 'Briar se concentra novamente, removendo Frenesi Sanguinário e canalizando sua energia em um grito poderoso que causa dano e Lentidão a inimigos. Ao carregar, ela recebe dano reduzido e se cura em uma parte de sua Vida máxima. Um grito totalmente carregado empurra inimigos, causando dano adicional e atordoando os que atingirem uma parede.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BriarE.png'),
('BriarQ', 18, 'Q', 'Vertigem', 'Briar salta até uma unidade e atinge inimigos com um golpe giratório, atordoando e fragmentando a Armadura de todos que atingir.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BriarQ.png'),
('BriarR', 18, 'R', 'Morte Certa', 'Briar lança o hemólito da berlinda dela, marcando o primeiro Campeão atingido como sua presa. Depois, ela avança diretamente, causando temor a inimigos próximos ao chegar no alvo e entrando num estado de hemomania total. Ela persegue a presa até a morte, recebendo os benefícios de Frenesi Sanguinário, além de Armadura, Resistência Mágica, Roubo de Vida e Velocidade de Movimento adicionais.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BriarR.png'),
('BriarW', 18, 'W', 'Frenesi Sanguinário/Ataque Faminto', 'Briar salta e quebra sua berlinda, entrando num Frenesi Sanguinário que faz com que ela persiga o inimigo mais próximo (priorizando Campeões). Enquanto estiver no Frenesi, ela ganha Velocidade de Ataque e Velocidade de Movimento aumentadas, e seus ataques causam dano em área perto do alvo.Briar pode reativar esta Habilidade enquanto estiver no Frenesi para dar uma MORDIDA no alvo no próximo ataque dela, causando dano adicional baseado na Vida perdida e cura com base no dano causado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/BriarW.png'),
('Briar_P', 18, 'P', 'Maldição Carmesim', 'Os Ataques e as Habilidades de Briar acumulam sangramento que cura Briar numa quantidade do dano causado. Constantemente faminta, ela ganha cura aumentada com base na Vida perdida, mas não tem Regeneração de Vida inata.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/BriarP.Briar.png'),
('Bushwhack', 90, 'W', 'Arapuca / Investida', 'Na forma humana, Nidalee posiciona uma armadilha para seus oponentes descuidados que, quando ativada, causa dano e os revela. Em forma de puma, ela salta em uma direção, causando dano na área em que aterrissar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Bushwhack.png'),
('CaitlynE', 19, 'E', 'Rede Calibre 90', 'Caitlyn atira uma rede pesada para reduzir a velocidade do seu alvo. O recuo projeta Caitlyn para trás.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CaitlynE.png'),
('CaitlynQ', 19, 'Q', 'Pacificadora de Piltover', 'Caitlyn prepara seu rifle por 1s para fazer um disparo penetrante que causa Dano Físico (causa menos dano a alvos subsequentes).', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CaitlynQ.png'),
('CaitlynR', 19, 'R', 'Ás na Manga', 'Caitlyn se concentra para fazer o disparo perfeito, causando dano drástico em um único alvo a uma longa distância. Campeões inimigos podem interceptar o projétil e tomar dano no lugar de seu aliado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CaitlynR.png'),
('CaitlynW', 19, 'W', 'Armadilha Mecânica Yordle', 'Caitlyn posiciona uma armadilha que, quando ativada, revela e imobiliza o Campeão inimigo por 1,5s e concede a Caitlyn um Bem na Mira fortalecido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CaitlynW.png'),
('Caitlyn_P', 19, 'P', 'Bem na Mira', 'A cada poucos ataques básicos, ou contra um alvo preso em uma armadilha ou rede, Caitlyn fará um disparo Bem na Mira causando dano adicional que escala com sua Chance de Acerto Crítico. Em alvos presos por armadilhas ou pela rede, o alcance de Bem na Mira de Caitlyn é dobrado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Caitlyn_Headshot.png'),
('CamilleE', 20, 'E', 'Disparo de Gancho', 'Camille puxa a si mesma na direção de uma parede, saltando e arremessando ao ar Campeões inimigos ao aterrissar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CamilleE.png'),
('CamilleQ', 20, 'Q', 'Protocolo de Precisão', 'O próximo ataque de Camille causa dano adicional e concede Velocidade de Movimento adicional. Esta habilidade pode ser conjurada novamente por um curto período de tempo, causando dano adicional consideravelmente aumentado se Camille criar um intervalo entre os dois ataques.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CamilleQ.png'),
('CamilleR', 20, 'R', 'Ultimato Hextec', 'Camille avança em direção ao Campeão alvo, ancorando-o à área. Ela também causa Dano Mágico adicional ao alvo com seus ataques básicos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CamilleR.png'),
('CamilleW', 20, 'W', 'Varredura Tática', 'Camille faz um disparo em área de cone após um intervalo, causando dano. Inimigos na metade exterior têm sua velocidade reduzida e recebem dano adicional, ao mesmo tempo em que curam Camille.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CamilleW.png'),
('Camille_P', 20, 'P', 'Defesa Adaptativa', 'Ataques básicos contra Campeões concedem um Escudo equivalente a uma porcentagem da Vida máxima de Camille contra o tipo de dano deles (Físico ou Mágico) por um breve período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Camille_Passive.png'),
('CardmasterStack', 139, 'E', 'Baralho Marcado', 'A cada 4 ataques, Twisted Fate causa dano adicional. Além disso, sua Velocidade de Ataque aumenta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CardmasterStack.png'),
('CarpetBomb', 23, 'W', 'Valquíria', 'Corki sobrevoa uma curta distância, soltando bombas que criam um rastro de fogo, causando dano a oponentes que nele permanecerem.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CarpetBomb.png'),
('CassiopeiaE', 21, 'E', 'Presas Duplas', 'Cassiopeia desfere um ataque que causa dano adicional a alvos envenenados, curando a si mesma com um percentual do dano causado. Se o alvo morrer com este ataque, Cassiopeia recupera Mana.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CassiopeiaE.png'),
('CassiopeiaQ', 21, 'Q', 'Explosão Venenosa', 'Cassiopeia atinge uma área com veneno após um breve intervalo, recebendo Velocidade de Movimento caso atinja um Campeão inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CassiopeiaQ.png'),
('CassiopeiaR', 21, 'R', 'Olhar Petrificador', 'Cassiopeia lança uma espiral de energia mágica de seus olhos, atordoando quaisquer inimigos à sua frente que estiverem de frente para ela e reduzindo a velocidade de quaisquer outros que estiverem de costas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CassiopeiaR.png'),
('CassiopeiaW', 21, 'W', 'Miasma', 'Cassiopeia lança diversas nuvens de veneno que reduzem a velocidade, prendem ao chão e causam dano leve aos inimigos que as atravessarem. Inimigos presos ao chão não podem usar habilidades de movimentação.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CassiopeiaW.png'),
('Cassiopeia_P', 21, 'P', 'Graça Serpentina', 'Cassiopeia recebe Velocidade de Movimento por nível, mas não pode comprar Botas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Cassiopeia_Passive.png'),
('Chogath_P', 22, 'P', 'Carnívoro', 'Sempre que Cho\'Gath abate uma unidade, ele recupera Vida e Mana. Os valores restaurados aumentam com o nível de Cho\'Gath.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/GreenTerror_TailSpike.png'),
('ChronoShift', 165, 'R', 'Alteração Temporal', 'Zilean coloca uma runa protetora do tempo em um Campeão aliado, teletransportando-o de volta no tempo se ele receber um dano letal.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ChronoShift.png'),
('Corki_P', 23, 'P', 'Munição Hextec', 'Uma porcentagem do Dano de Ataque Básico de Corki é convertida em Dano Mágico.Corki pode buscar O Pacote na base, concedendo a ele Velocidade de Movimento e fortalecendo a conjuração de Valquíria.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Corki_RapidReload.png'),
('Crystallize', 7, 'W', 'Cristalizar', 'Anivia condensa a umidade do ar, transformando-a num muro impenetrável de gelo que bloqueia todo o movimento. O muro dura um curto período antes de derreter.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Crystallize.png'),
('CurseoftheSadMummy', 6, 'R', 'A Maldição da Múmia Triste', 'Amumu amarra unidades inimigas ao seu redor com ataduras, aplicando Maldição, causando dano e atordoando-as.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/CurseoftheSadMummy.png'),
('DariusAxeGrabCone', 24, 'E', 'Apreender', 'Darius afia seu machado, fazendo com que seu Dano Físico ignore passivamente um percentual da Armadura do alvo. Quando ativado, Darius ataca seus inimigos com o gancho do seu machado e os puxa em sua direção.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DariusAxeGrabCone.png'),
('DariusCleave', 24, 'Q', 'Dizimar', 'Darius pega impulso e golpeia com seu machado em um movimento circular. Os inimigos atingidos pela lâmina recebem mais dano do que aqueles atingidos pelo cabo. Darius cura a si mesmo com base nos Campeões inimigos e monstros grandes atingidos pela lâmina.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DariusCleave.png'),
('DariusExecute', 24, 'R', 'Guilhotina de Noxus', 'Darius salta na direção de um Campeão inimigo e o atinge com um golpe letal, causando Dano Verdadeiro. Este dano aumenta a cada acúmulo de Hemorragia no alvo. Se Guilhotina de Noxus causar o golpe final, seu Tempo de Recarga é zerado por um breve momento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DariusExecute.png'),
('DariusNoxianTacticsO', 24, 'W', 'Ataque Mutilador', 'O próximo ataque de Darius acerta uma artéria importante do inimigo. Enquanto a vítima sangra, a Velocidade de Movimento dela é reduzida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DariusNoxianTacticsONH.png'),
('Darius_P', 24, 'P', 'Hemorragia', 'Os Ataques e Habilidades de dano de Darius fazem os inimigos sangrarem, causando Dano Físico ao longo de 5s e acumulando até 5 vezes. Darius se enfurece e recebe uma grande quantidade de Dano de Ataque quando o alvo alcança o máximo de acúmulos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Darius_Icon_Hemorrhage.png'),
('Deceive', 117, 'Q', 'Enganar', 'Shaco fica Invisível e se teleporta para o local-alvo.Seu primeiro ataque enquanto está Invisível é fortalecido, causando dano adicional e crítico ao atingir o inimigo por trás.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Deceive.png'),
('DefensiveBallCurl', 103, 'W', 'Bola Curva Defensiva', 'Rammus assume uma posição defensiva, aumentando drasticamente a própria Armadura e Resistência Mágica, amplificando o dano de Casco Espetado e devolvendo o dano de ataques básicos aos inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DefensiveBallCurl.png'),
('Destiny', 139, 'R', 'Destino', 'Twisted Fate prevê o futuro de seus adversários, revelando todos os Campeões inimigos e habilitando o uso de Portal, que o teleporta para qualquer local-alvo em 1,5s.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Destiny.png'),
('DianaOrbs', 25, 'W', 'Cascata Lívida', 'Diana cria três esferas orbitantes que detonam ao contato com inimigos, causando dano em área. Ela também ganha um escudo temporário que absorve dano. Se a terceira esfera detonar, o escudo recebe resistência adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DianaOrbs.png'),
('DianaQ', 25, 'Q', 'Golpe Crescente', 'Faz um disparo de energia lunar em forma de arco, causando Dano Mágico.Afeta os inimigos atingidos com Plenilúnio, revelando-os por 3s se não estiverem furtivos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DianaQ.png'),
('DianaR', 25, 'R', 'Colapso Minguante', 'Diana revela e atrai todos os inimigos próximos e reduz a velocidade deles.Se Diana atrair um ou mais Campeões inimigos, o Plenilúnio cai sobre ela depois de um breve intervalo, causando Dano Mágico em uma área ao seu redor, aumentado a cada alvo atraído além do primeiro.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DianaR.png'),
('DianaTeleport', 25, 'E', 'Zênite Lunar', 'Torna-se a encarnação viva da lua vingativa, avançando contra um inimigo e causando Dano Mágico.Zênite Lunar não tem Tempo de Recarga ao avançar em um inimigo afetado por Plenilúnio. Todos os outros inimigos terão o efeito de Plenilúnio removido independentemente de terem sido o alvo de Zênite Lunar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DianaTeleport.png'),
('Diana_P', 25, 'P', 'Espada de Prata Lunar', 'Cada terceiro ataque atinge os oponentes próximos, causando Dano Mágico adicional. Depois de conjurar uma Habilidade, Diana recebe Velocidade de Ataque em seus próximos 3 Ataques.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Diana_Passive_LunarBlade.png'),
('DravenDoubleShot', 26, 'E', 'Sai da Frente', 'Draven arremessa seus machados, causando Dano Físico aos alvos atingidos e empurrando-os para o lado. Os alvos atingidos sofrem redução de velocidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DravenDoubleShot.png'),
('DravenFury', 26, 'W', 'Adrenalina', 'Draven ganha um aumento de Velocidade de Movimento e de Ataque. O aumento na Velocidade de Movimento decai rapidamente ao longo da duração. Apanhar uma Revolução do Machado fará com que o Tempo de Recarga de Adrenalina seja zerado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DravenFury.png'),
('DravenRCast', 26, 'R', 'Reta da Morte', 'Draven arremessa dois machados gigantes para causar Dano Físico a cada unidade atingida. Reta da Morte lentamente muda de direção e retorna a Draven após atingir um Campeão inimigo. Draven também pode ativar esta habilidade durante o percurso dos machados para fazer com que voltem antecipadamente. Causa menos dano para cada unidade atingida e zera quando os machados mudam de direção. Executa inimigos com Vida inferior ao número de acúmulos de Adoração do Draven.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DravenRCast.png'),
('DravenSpinning', 26, 'Q', 'Revolução do Machado', 'O próximo ataque de Draven causará Dano Físico adicional. O machado ricocheteará do alvo em direção ao ar. Se Draven o apanhar, ele automaticamente irá preparar outra Revolução do Machado. Draven pode ter duas Revoluções do Machado simultaneamente em ação.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DravenSpinning.png'),
('Draven_P', 26, 'P', 'League of Draven', 'Draven ganha Adoração de seus fãs quando apanha uma Revolução do Machado ou abate uma tropa, monstro ou torre. Abater Campeões inimigos concede ouro adicional a Draven, com base em quanta Adoração ele tem.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Draven_passive.png'),
('DrMundoE', 27, 'E', 'Traumatismo', 'Passivo: Dr. Mundo recebe Dano de Ataque adicional (que aumenta com base na própria Vida máxima).Ativo: Dr. Mundo golpeia o inimigo com sua maleta \'\'médica\'\', causando dano adicional com base na própria Vida perdida. Se o inimigo for abatido, será arremessado, causando dano aos inimigos que atravessar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DrMundoE.png'),
('DrMundoQ', 27, 'Q', 'Serra Infectada', 'Dr. Mundo arremessa uma serra infectada, causando dano ao primeiro inimigo atingido com base na Vida atual do alvo e causando Lentidão a ele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DrMundoQ.png'),
('DrMundoR', 27, 'R', 'Dosagem Máxima', 'Dr. Mundo enche-se de produtos químicos, curando instantaneamente uma porcentagem da própria Vida perdida. Depois, ele recebe Velocidade de Movimento e regenera parte da própria Vida máxima ao longo da duração.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DrMundoR.png'),
('DrMundoW', 27, 'W', 'Choquinho Cardíaco', 'Dr. Mundo se eletrocuta, causando dano contínuo aos inimigos próximos e acumulando uma parte do dano sofrido. Ele causa uma explosão de dano aos inimigos próximos ao final da duração ou ao Reconjurar. Se atingir um inimigo, Dr. Mundo se curará em uma porcentagem do dano armazenado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/DrMundoW.png'),
('DrMundo_P', 27, 'P', 'Vai Para Onde Quer', 'Dr. Mundo resiste ao próximo efeito Imobilizador que o atingir, perdendo Vida e derrubando um recipiente químico nas proximidades. Dr. Mundo pode pegar o recipiente ao passar por cima dele, restaurando Vida e reduzindo o Tempo de Recarga da Habilidade.Dr. Mundo também tem Regeneração de Vida significativamente mais alta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/DrMundo_P.png'),
('EkkoE', 28, 'E', 'Mergulho Fásico', 'Ekko faz um rolamento evasivo enquanto carrega seu Revo-Z. Seu próximo ataque causa dano adicional e distorce a realidade, teleportando-o a seu alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EkkoE.png'),
('EkkoQ', 28, 'Q', 'Giratempo', 'Ekko arremessa uma granada que se expande em um campo de distorção temporal ao atingir um Campeão inimigo, causando dano e reduzindo a velocidade de todos dentro de sua área de ação. Após um intervalo, a granada retorna em direção a Ekko, causando dano no trajeto de volta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EkkoQ.png'),
('EkkoR', 28, 'R', 'Cronoquebra', 'Ekko estilhaça sua linha do tempo, tornando-se inalvejável e rebobinando para um ponto mais favorável no tempo. Ele retorna para qualquer ponto que esteve nos últimos segundos e se cura em um percentual do dano recebido nesta duração. Inimigos próximos a sua área de chegada recebem dano massivo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EkkoR.png'),
('EkkoW', 28, 'W', 'Convergência Paralela', 'Os ataques básicos de Ekko causam Dano Mágico adicional aos inimigos com Vida baixa. Ekko pode conjurar Convergência Paralela para separar a linha do tempo, causando uma anomalia após alguns segundos e reduzindo a velocidade de inimigos pegos por ela. Se Ekko adentrar a anomalia, ele receberá um escudo e acionará uma detonação que atordoa os inimigos, colocando-os em estase temporal.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EkkoW.png'),
('Ekko_P', 28, 'P', 'Ressonância Revo-Z', 'Cada terceiro ataque ou habilidade de dano no mesmo alvo causa Dano Mágico adicional e concede a Ekko um impulso de velocidade se o alvo for um Campeão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Ekko_P.png'),
('EliseHumanE', 29, 'E', 'Casulo / Rapel', 'Forma Humana: atordoa a primeira unidade inimiga atingida e a revela se não estiver em furtividade.Forma de Aranha: Elise e suas crias se lançam ao ar, depois descem sobre um alvo inimigo. Após descer sobre o alvo, o dano adicional de Elise e a cura de Aranha Rainha são aumentados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EliseHumanE.png'),
('EliseHumanQ', 29, 'Q', 'Neurotoxina / Mordida Venenosa', 'Forma Humana: Causa dano com base em quão alta está a Vida do alvo.Forma de Aranha: Avança até um inimigo e causa dano com base em quão baixa está a Vida do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EliseHumanQ.png'),
('EliseHumanW', 29, 'W', 'Cria Volátil / Frenesi Aracnídeo', 'Forma Humana: Elise lança uma cria banhada em veneno que explode ao se aproximar de um alvo.Forma de Aranha: Elise e suas Crias recebem Velocidade de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EliseHumanW.png'),
('EliseR', 29, 'R', 'Forma de Aranha', 'Transforma-se em uma ameaçadora aranha, reduzindo seu alcance de ataque em troca de Velocidade de Movimento, novas habilidades e um aglomerado de Crias que atacarão seus inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EliseR.png'),
('Elise_P', 29, 'P', 'Aranha Rainha', 'Forma Humana: Quando as habilidades de Elise atingem um inimigo, ela recebe uma Cria dormente.Forma de Aranha: Ataques básicos causam Dano Mágico adicional e restauram a Vida de Elise.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/ElisePassive.png'),
('EnchantedCrystalArro', 10, 'R', 'Flecha de Cristal Encantada', 'Ashe dispara um projétil de gelo em linha reta. Se a flecha colidir com um Campeão inimigo, ela causa dano e o atordoa. A duração do atordoamento depende da distância percorrida pela flecha. Além disso, unidades inimigas próximas recebem dano e lentidão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EnchantedCrystalArrow.png'),
('EvelynnE', 30, 'E', 'Chicotada', 'Evelynn açoita seu alvo com seu Chicote, causando dano. Depois, ela ganha Velocidade de Movimento por um breve período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EvelynnE.png'),
('EvelynnQ', 30, 'Q', 'Espinho de Ódio', 'Evelynn ataca com seu Chicote, causando dano ao primeiro inimigo atingido. Depois, Evelynn dispara uma linha de espinhos até 3 vezes contra inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EvelynnQ.png'),
('EvelynnR', 30, 'R', 'Última Carícia', 'Evelynn fica inalvejável por um breve período e dizima a área à sua frente antes de se mover uma longa distância para trás.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EvelynnR.png'),
('EvelynnW', 30, 'W', 'Fascinação', 'Evelynn amaldiçoa seu alvo, fazendo com que o próximo ataque ou habilidade dela o encante e reduza sua Resistência Mágica depois um intervalo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EvelynnW.png'),
('Evelynn_P', 30, 'P', 'Sombra Demoníaca', 'Quando está fora de combate, Evelynn entra em Sombra Demoníaca. A Sombra Demoníaca cura Evelynn quando ela está com pouca Vida e concede Camuflagem após o nível 6.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Evelynn_Passive.png'),
('EyeOfTheStorm', 48, 'E', 'Olho da Tempestade', 'Janna conjura uma ventania defensiva que protege um Campeão ou torre aliada do dano recebido e aumenta seu Dano de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EyeOfTheStorm.png'),
('EzrealE', 31, 'E', 'Translocação Arcana', 'Ezreal teleporta-se para um local-alvo próximo e faz um disparo teleguiado na unidade inimiga mais próxima. Prioriza inimigos atingidos com Fluxo Essencial.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EzrealE.png'),
('EzrealQ', 31, 'Q', 'Disparo Místico', 'Ezreal faz um disparo de energia que reduz um pouco o Tempo de Recarga de todas as suas habilidades caso atinja uma unidade inimiga.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EzrealQ.png'),
('EzrealR', 31, 'R', 'Barragem Incendiária', 'Ezreal carrega antes de disparar uma poderosa barragem de energia que causa dano massivo em cada unidade que atravessar (o dano é reduzido contra tropas e monstros não épicos).', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EzrealR.png'),
('EzrealW', 31, 'W', 'Fluxo Essencial', 'Ezreal dispara um orbe que prende-se ao primeiro Campeão ou objetivo atingido. Caso atinja um inimigo preso com o orbe, ele detonará e causará dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/EzrealW.png'),
('Ezreal_P', 31, 'P', 'Feitiço do Poder Crescente', 'Ezreal recebe Velocidade de Ataque crescente a cada vez que acerta uma habilidade, acumulando-se até 5 vezes.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Ezreal_RisingSpellForce.png'),
('Feast', 22, 'R', 'Banquete', 'Devora uma unidade inimiga, causando uma grande quantidade de Dano Verdadeiro. Se o alvo for abatido, Cho\'Gath cresce, recebendo Vida máxima.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Feast.png'),
('FeralScream', 22, 'W', 'Grito Selvagem', 'Cho\'Gath solta um terrível urro em inimigos em área de cone, causando Dano Mágico e Silenciamento a eles por alguns segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FeralScream.png'),
('FerociousHowl', 5, 'R', 'Vontade Indestrutível', 'Alistar solta um urro selvagem, removendo todos os efeitos de Controle de Grupo de si mesmo, além de reduzir o Dano Físico e Mágico enquanto durar o efeito.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FerociousHowl.png');
INSERT INTO `habilidades` (`ID_habilidade`, `ID_campeao`, `tecla`, `nome_habilidade`, `descricao`, `imagem_url`) VALUES
('FiddleSticksE', 32, 'E', 'Ceifar', 'Fiddlesticks ceifa uma área com sua foice, reduzindo a velocidade de movimento de todos os inimigos atingidos e silenciando os atingidos no centro do corte.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FiddleSticksE.png'),
('FiddleSticksQ', 32, 'Q', 'Aterrorizar', 'Ao causar dano a inimigos com habilidades enquanto não estiver sendo visto ou alvejar um inimigo com Aterrorizar, Fiddlesticks inflige medo em uma unidade-alvo inimiga, fazendo com que fuja aterrorizada por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FiddleSticksQ.png'),
('FiddleSticksR', 32, 'R', 'Tempestade de Corvos', 'Uma revoada de corvos assassinos voa em volta de Fiddlesticks, causando dano por segundo a todas as unidades inimigas próximas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FiddleSticksR.png'),
('FiddleSticksW', 32, 'W', 'Colheita Farta', 'Fiddlesticks drena a Vida dos inimigos próximos, causando dano de execução adicional no fim da duração.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FiddleSticksW.png'),
('Fiddlesticks_P', 32, 'P', 'Um Espantalho Inofensivo', 'O amuleto de Fiddlesticks é substituído por efígies do espantalho.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/FiddlesticksP.png'),
('FioraE', 33, 'E', 'Esgrima', 'Fiora ganha aumento na Velocidade de Ataque pelos próximos dois ataques. O primeiro ataque reduz a velocidade do alvo e o segundo ataque causará acerto crítico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FioraE.png'),
('FioraQ', 33, 'Q', 'Estocada', 'Fiora avança em uma direção e golpeia um inimigo próximo, causando Dano Físico e aplicando efeitos de contato.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FioraQ.png'),
('FioraR', 33, 'R', 'Desafio Grandioso', 'Fiora revela todos os quatro Pontos Vitais de um Campeão inimigo e recebe Velocidade de Movimento enquanto estiver perto dele. Se atingir todos os quatro Pontos Vitais ou se o alvo morrer depois que ela atingir pelo menos um deles, Fiora e os aliados que estiverem na área serão curados pelos próximos segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FioraR.png'),
('FioraW', 33, 'W', 'Ripostar', 'Fiora apara todo o dano e desarmes recebidos por um curto período de tempo, golpeando na direção alvo em seguida. Este golpe reduz a velocidade do primeiro campeão inimigo atingido. O golpe pode atordoar caso Fiora tenha bloqueado um efeito imobilizante com esta habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FioraW.png'),
('Fiora_P', 33, 'P', 'Dança da Duelista', 'Fiora revelou um Ponto Vital neste Campeão. Se atingir o Ponto Vital, ela restaurará Vida e receberá Velocidade de Movimento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Fiora_P.png'),
('FizzE', 34, 'E', 'Brincalhão / Trapaceiro', 'Fizz faz acrobacias no ar, aterrissando graciosamente sobre seu tridente e ficando inalvejável. Desta posição, ele pode tanto golpear o chão quanto pular novamente antes de cair de vez.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FizzE.png'),
('FizzQ', 34, 'Q', 'Ataque do Ouriço', 'Fizz avança em direção ao alvo, causando Dano Mágico e aplicando efeitos de contato.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FizzQ.png'),
('FizzR', 34, 'R', 'Lançar Isca', 'Fizz arremessa um peixe em determinada direção, que se prende a qualquer Campeão que tocar, reduzindo a velocidade do alvo. Após um curto intervalo, um tubarão emerge do chão, lançando o alvo ao ar e empurrando outros inimigos para trás. Todos os inimigos atingidos recebem Dano Mágico e têm sua velocidade reduzida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FizzR.png'),
('FizzW', 34, 'W', 'Tridente da Pedra do Mar', 'Os ataques de Fizz fazem seus inimigos sangrarem, causando Dano Mágico por vários segundos. Fizz pode fortalecer seu próximo ataque para causar dano adicional e fortalecer os seguintes por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FizzW.png'),
('Fizz_P', 34, 'P', 'Lutador Ligeiro', 'Fizz pode se mover através de unidades e sofre uma quantidade fixa de dano reduzido de todas as origens.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Fizz_P.png'),
('FlashFrost', 7, 'Q', 'Lampejo Gelado', 'Anivia junta suas asas e invoca uma esfera de gelo que voa em direção ao oponente, congelando e causando dano a qualquer um em seu caminho. Ao explodir, ela causa dano moderado em um raio, atordoando qualquer um dentro da área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/FlashFrost.png'),
('Fling', 120, 'E', 'Lançar', 'Causa dano ao inimigo alvo e o arremessa pelo ar para trás de Singed. Se o alvo que Singed arremessar aterrissar em seu Mega Adesivo, ele ficará enraizado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Fling.png'),
('ForcePulse', 58, 'E', 'Força de Pulso', 'Kassadin drena energia de habilidades conjuradas nas proximidades. Ao estar carregado, Kassadin pode usar Força de Pulso para causar dano e reduzir a velocidade de inimigos em uma área em cone à sua frente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ForcePulse.png'),
('Frostbite', 7, 'E', 'Congelamento', 'Com um bater de asas, Anivia dispara uma rajada congelante de vento no alvo, causando dano. Se o alvo tiver sido atingido recentemente por Lampejo Gelado ou sofrido dano de uma Tempestade Glacial totalmente formada, o dano sofrido é dobrado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Frostbite.png'),
('GalioE', 35, 'E', 'Soco Justiceiro', 'Galio dá um passo para trás e avança, arremessando ao ar o primeiro Campeão com que colidir.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GalioE.png'),
('GalioQ', 35, 'Q', 'Ventos de Guerra', 'Galio dispara duas rajadas de vento que convergem em um grande tornado e causam dano ao longo do tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GalioQ.png'),
('GalioR', 35, 'R', 'Entrada Heroica', 'Galio marca a posição de um aliado como ponto de aterrissagem e concede um escudo mágico a todos os aliados na área. Após um intervalo, ele aterrissa no local, arremessando os inimigos próximos ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GalioR.png'),
('GalioW', 35, 'W', 'Escudo de Durand', 'Galio carrega em postura defensiva, movendo-se lentamente. Ao soltar o carregamento, ele provocará e causará dano a inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GalioW.png'),
('Galio_P', 35, 'P', 'Esmagada Colossal', 'A cada poucos segundos, o próximo ataque básico de Galio causa Dano Mágico adicional em área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Galio_Passive.png'),
('GangplankE', 36, 'E', 'Barril de Pólvora', 'Gangplank posiciona um Barril de Pólvora no local-alvo. Ele explodirá caso seja atacado, causando dano aos inimigos na área e reduzindo a Velocidade de Movimento deles.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GangplankE.png'),
('GangplankQWrapper', 36, 'Q', 'Negociarrr', 'Dispara no alvo, saqueando ouro para cada abate de unidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GangplankQWrapper.png'),
('GangplankR', 36, 'R', 'Barragem de Canhão', 'Gangplank sinaliza para que seu navio bombardeie uma área, causando dano e lentidão aos inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GangplankR.png'),
('GangplankW', 36, 'W', 'Remover Escorbuto', 'Come fruta cítrica para curar efeitos de controle de grupo e restaurar Vida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GangplankW.png'),
('Gangplank_P', 36, 'P', 'Julgamento de Fogo', 'Periodicamente, o ataque corpo a corpo de Gangplank deixará seu inimigo em chamas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Gangplank_Passive.png'),
('GarenE', 37, 'E', 'Julgamento', 'Garen gira rapidamente a espada ao redor do corpo dele, causando Dano Físico a inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GarenE.png'),
('GarenQ', 37, 'Q', 'Acerto Decisivo', 'Garen recebe um impulso de Velocidade de Movimento, libertando-se de todos os efeitos de Lentidão. Seu próximo ataque atinge uma área vital do inimigo, causando dano adicional e silenciando-o.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GarenQ.png'),
('GarenR', 37, 'R', 'Justiça Demaciana', 'Garen evoca o Poder de Demacia para tentar executar um Campeão inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GarenR.png'),
('GarenW', 37, 'W', 'Coragem', 'Garen aumenta sua Armadura e Resistência Mágica passivamente ao abater inimigos. Ele também pode ativar essa habilidade para receber um escudo e Tenacidade por um breve período, seguido de uma quantidade menor de redução de dano com maior duração.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GarenW.png'),
('Garen_P', 37, 'P', 'Perseverança', 'Se Garen não tiver sido atingido recentemente por dano ou habilidades inimigas, ele regenera um percentual de sua Vida total a cada segundo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Garen_Passive.png'),
('GGun', 23, 'E', 'Metralhadora', 'A metralhadora de Corki dispara rapidamente em área de cone à sua frente, causando dano, reduzindo a Armadura e a Resistência Mágica do inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GGun.png'),
('GlacialStorm', 7, 'R', 'Tempestade Glacial', 'Anivia invoca uma chuva torrencial de gelo e granizo para causar dano aos inimigos e atrasar seu avanço.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GlacialStorm.png'),
('GnarE', 38, 'E', 'Pirueta / Encontrão', 'Gnar salta em um local e atinge a cabeça de qualquer unidade em que aterrissar, deslocando-se ainda mais.Mega Gnar é grande demais para saltar e, em vez disso, aterrissa com força para quebrar o chão, causando dano em área ao seu redor.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GnarE.png'),
('GnarQ', 38, 'Q', 'Bumerangue / Pedregulho', 'Gnar lança um bumerangue que causa dano e Lentidão a inimigos que atinge antes de retornar a ele. Caso apanhe o bumerangue, seu Tempo de Recarga é reduzido.Mega Gnar arremessa um pedregulho que para na primeira unidade atingida, causando dano e Lentidão a tudo o que estiver próximo. Em seguida, ele pode ser apanhado para reduzir o Tempo de Recarga.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GnarQ.png'),
('GnarR', 38, 'R', 'GNAR!', 'Mega Gnar joga tudo o que estiver próximo de si em uma direção escolhida, causando dano e Lentidão. Qualquer inimigo que atingir uma parede fica atordoado e recebe dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GnarR.png'),
('GnarW', 38, 'W', 'Hiperativo / Safanão', 'Os ataques e habilidades de Gnar o animam, causando dano adicional e concedendo Velocidade de Movimento.Mega Gnar fica enfurecido demais para ficar hiperativo. Em vez disso, ele pode subir em duas patas e atingir a área à sua frente, atordoando inimigos em área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GnarW.png'),
('Gnar_P', 38, 'P', 'Fúria Genética', 'Enquanto está em combate, Gnar gera Fúria. Quando atinge o máximo de Fúria, sua próxima habilidade o transformará em Mega-Gnar, concedendo mais condições de sobrevivência e acesso a novas habilidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Gnar_Passive.png'),
('GragasE', 39, 'E', 'Barrigada', 'Gragas avança em direção a um local e colide com a primeira unidade inimiga que encontrar, causando dano a todas as unidades inimigas próximas e atordoando-as.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GragasE.png'),
('GragasQ', 39, 'Q', 'Jogar o Barril', 'Gragas rola seu barril até um local, podendo ativá-lo novamente para explodir. Caso isso não aconteça, o barril explodirá sozinho após 4s. A potência da explosão aumenta ao longo do tempo. Os inimigos atingidos pela explosão sofrem Lentidão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GragasQ.png'),
('GragasR', 39, 'R', 'Barril Explosivo', 'Gragas arremessa seu barril em um local, causando dano e afastando os inimigos pegos no raio da explosão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GragasR.png'),
('GragasW', 39, 'W', 'Fúria da Bebedeira', 'Gragas entorna a bebida de seu barril garganta abaixo, canalizando por 1 segundo. Ao terminar, ele fica torpecidamente poderoso, causando mais dano em seu próximo ataque básico e reduzindo o dano recebido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GragasW.png'),
('Gragas_P', 39, 'P', 'Happy Hour', 'Gragas cura a si mesmo periodicamente após utilizar uma habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/GragasPassiveHeal.png'),
('GravesChargeShot', 40, 'R', 'Efeito Colateral', 'Graves atira um projétil explosivo que causa muito dano ao primeiro campeão que acertar. Após atingir um campeão ou chegar ao seu alcance máximo, o projétil explode, causando dano em uma área em cone.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GravesChargeShot.png'),
('GravesMove', 40, 'E', 'Saque Rápido', 'Graves avança em linha reta, recebendo Armadura adicional por muitos segundos. Se Graves avançar em direção a um Campeão inimigo, ele recebe dois acúmulos de Bravura Indômita. Atingir inimigos com ataques básicos reduz o Tempo de Recarga dessa habilidade e redefine o efeito de resistência.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GravesMove.png'),
('GravesQLineSpell', 40, 'Q', 'Fim da Linha', 'Graves dispara um projétil explosivo que detona após 2s, ou 0,2s caso atinja terreno.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GravesQLineSpell.png'),
('GravesSmokeGrenade', 40, 'W', 'Cortina de Fumaça', 'Graves atira uma bomba de fumaça na área-alvo, criando uma nuvem de fumaça que reduz o alcance de visão. Inimigos atingidos no impacto inicial sofrem Dano Mágico e têm sua Velocidade de Movimento reduzida por um curto período de tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GravesSmokeGrenade.png'),
('Graves_P', 40, 'P', 'Nova Destino', 'A escopeta de Graves tem algumas propriedades únicas. Ele precisa recarregar quando sua munição acaba. Ataques disparam 4 projéteis que não podem atravessar unidades. Não Campeões atingidos por mais de um projétil são empurrados para trás.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/GravesTrueGrit.png'),
('GwenE', 41, 'E', 'Avanço Afiado', 'Gwen avança por uma curta distância e ganha Velocidade de Ataque, Alcance de Ataque e Dano Mágico ao contato por alguns segundos. Se ela atingir um inimigo durante esse período, o Tempo de Recarga da Habilidade será parcialmente restituído. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GwenE.png'),
('GwenQ', 41, 'Q', 'Corte e Recorte', 'Gwen corta uma área em cone até seis vezes com a tesoura, causando Dano Mágico. Ela causa Dano Verdadeiro às unidades atingidas no centro e aplica a Passiva a cada corte.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GwenQ.png'),
('GwenR', 41, 'R', 'Ponto-Cruz', 'Gwen arremessa uma agulha que causa Dano Mágico e Lentidão, aplicando Mil Retalhos aos Campeões atingidos. A Habilidade pode ser conjurada mais duas vezes, e cada conjuração arremessa agulhas adicionais e causa mais dano. Gwen deve atingir um inimigo a cada conjuração para habilitar a próxima. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GwenR.png'),
('GwenW', 41, 'W', 'Névoa Sagrada', 'Gwen invoca uma Névoa que a protege dos inimigos que estiverem do lado de fora. Ela só pode ser alvejada por inimigos que entrarem na área da Névoa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/GwenW.png'),
('Gwen_P', 41, 'P', 'Mil Retalhos', 'Os Ataques de Gwen causam Dano Mágico adicional com base na Vida do alvo. Ela se cura em parte do dano causado a Campeões com esse efeito. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Gwen_Passive.png'),
('HallucinateFull', 117, 'R', 'Alucinações', 'Shaco cria uma ilusão de si mesmo próxima a ele, que pode atacar inimigos próximos (causa dano reduzido a torres). Ao morrer, ela explode, fazendo surgir três Caixinhas-Surpresa e causando dano a todos os inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HallucinateFull.png'),
('Headbutt', 5, 'W', 'Cabeçada', 'Alistar atinge o inimigo com sua cabeça, causando dano e jogando o alvo para trás.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Headbutt.png'),
('HecarimRamp', 42, 'E', 'Ataque Devastador', 'Hecarim recebe Velocidade de Movimento crescente e ignora colisão com unidades por um curto período. O próximo Ataque dele empurra o alvo e causa Dano Físico adicional com base na distância percorrida desde a ativação da Habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HecarimRamp.png'),
('HecarimRapidSlash', 42, 'Q', 'Enfurecido', 'Hecarim golpeia inimigos próximos, causando Dano Físico. Caso ele cause dano a ao menos um inimigo, os usos subsequentes da habilidade causam mais dano e têm menor Tempo de Recarga.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HecarimRapidSlash.png'),
('HecarimUlt', 42, 'R', 'Massacre das Sombras', 'Hecarim invoca cavaleiros espectrais e avança, causando Dano Mágico em linha reta. Hecarim desfere uma onda de choque ao terminar o ataque, fazendo com que inimigos próximos se afastem aterrorizados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HecarimUlt.png'),
('HecarimW', 42, 'W', 'Espírito do Pavor', 'Hecarim recebe Armadura e Resistência Mágica. Ele causa Dano Mágico a inimigos próximos e recebe Vida equivalente a um percentual de qualquer dano que esses inimigos receberem.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HecarimW.png'),
('Hecarim_P', 42, 'P', 'Caminho da Guerra', 'Hecarim recebe Dano de Ataque equivalente a um percentual de sua Velocidade de Movimento adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Hecarim_Passive.png'),
('HeimerdingerE', 43, 'E', 'Granada de Tempestade de Elétrons CH-2', 'Heimerdinger lança uma granada em um local, causando dano a unidades inimigas, atordoando todos que forem diretamente atingidos e deixando as unidades próximas lentas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HeimerdingerE.png'),
('HeimerdingerQ', 43, 'Q', 'Torre Evolutiva H-28G', 'Heimerdinger posiciona um canhão-torre automático equipado com um ataque secundário de feixes perfurantes (canhões causam metade do dano a torres).', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HeimerdingerQ.png'),
('HeimerdingerR', 43, 'R', 'MELHORIA!!!', 'Heimerdinger inventa um aprimoramento, fazendo com que sua próxima habilidade tenha efeitos adicionais. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HeimerdingerR.png'),
('HeimerdingerW', 43, 'W', 'Micro-Mísseis Hextec', 'Heimerdinger dispara mísseis de longo alcance que convergem na direção do cursor.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HeimerdingerW.png'),
('Heimerdinger_P', 43, 'P', 'Afinidade Hextec', 'Recebe Velocidade de Movimento enquanto próxima a torres aliadas e torres posicionadas por Heimerdinger.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Heimerdinger_Passive.png'),
('Highlander', 79, 'R', 'Highlander', 'Master Yi se movimenta com extrema agilidade, aumentando temporariamente suas Velocidades de Ataque e de Movimento, tornando-se imune a todos os efeitos de Lentidão. Abates ou assistências de Campeões estendem a duração de Highlander enquanto a habilidade estiver ativa. Reduz passivamente o Tempo de Recarga das outras habilidades a cada abate ou assistência.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Highlander.png'),
('HowlingGale', 48, 'Q', 'Ventania Uivante', 'Através de uma alteração pontual de temperatura e pressão, Janna consegue criar uma pequena tempestade que cresce em tamanho ao longo do tempo. Ela pode ativar a habilidade novamente para desferir a tempestade. Ao ser desferida, a tempestade se desloca em linha reta na direção em que foi conjurada, causando dano e arremessando ao ar quaisquer inimigos em seu caminho.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HowlingGale.png'),
('HweiE', 44, 'E', 'Tema: Tormento', 'Hwei vislumbra uma série de tormentos, o que lhe permite pintar visões controladoras.Substitui as Habilidades de Hwei por Habilidades de Controle de Grupo: Semblante Sinistro, Olhar do Abismo e Gorja Esmagadora.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HweiE.png'),
('HweiQ', 44, 'Q', 'Tema: Desastre', 'Hwei vislumbra uma série de desastres, o que lhe permite pintar um golpe devastador.Substitui as Habilidades de Hwei por Habilidades de dano: Fogo Devastador, Raio Cortante e Fissura Derretida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HweiQ.png'),
('HweiR', 44, 'R', 'Desespero Vertiginoso', 'Hwei pinta uma paisagem de puro desespero. O primeiro Campeão inimigo atingido se torna o centro de uma pintura em expansão que causa dano e Lentidão aos inimigos próximos. A visão explode depois de atingir seu tamanho máximo ou quando o Campeão for abatido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HweiR.png'),
('HweiW', 44, 'W', 'Tema: Serenidade', 'Hwei vislumbra uma série de serenidades, o que lhe permite pintar visões revigorantes.Substitui as Habilidades de Hwei por Habilidades de utilidade: Corrente Fugaz, Lagoa da Reflexão e Luzes Vivas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/HweiW.png'),
('Hwei_P', 44, 'P', 'Assinatura do Visionário', 'Hwei prepara os Campeões inimigos que sofrerem dano de suas Habilidades para deixar sua inconfundível assinatura.Atingir um inimigo com uma segunda Habilidade de dano conclui a assinatura, que fica sob ele. A assinatura detona após um breve intervalo, causando Dano Mágico a todos os inimigos dentro do alcance.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/HweiPassive.png'),
('IllaoiE', 45, 'E', 'Teste de Espírito', 'Illaoi arranca o espírito do corpo de um inimigo, forçando-o a permanecer perante ela. Espíritos ecoam um percentual do dano que recebem ao alvo original. Se abatido, ou caso se afaste muito do espírito, o alvo se transforma em um Recipiente e inicia o surgimento de Tentáculos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IllaoiE.png'),
('IllaoiQ', 45, 'Q', 'Golpe de Tentáculo', 'Aumenta o dano causado por Tentáculos. Quando ativada, Illaoi golpeia com um Tentáculo que causa Dano Físico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IllaoiQ.png'),
('IllaoiR', 45, 'R', 'Salto de Fé', 'Illaoi golpeia o chão com seu ídolo, causando Dano Físico a inimigos próximos. Um Tentáculo surge para cada campeão atingido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IllaoiR.png'),
('IllaoiW', 45, 'W', 'Lição Dura', 'Illaoi salta em direção a seu alvo, causando Dano Físico e fazendo com que Tentáculos próximos também golpeiem o alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IllaoiW.png'),
('Illaoi_P', 45, 'P', 'Profetisa de um Deus Ancião', 'Illaoi e os Recipientes que ela cria fazem surgir Tentáculos em terreno intransponível próximo. Tentáculos golpeiam espíritos, Recipientes e vítimas da Lição Dura de Illaoi. Tentáculos causam Dano Físico a inimigos atingidos e curarão Illaoi caso atinjam um Campeão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Illaoi_P.png'),
('InsanityPotion', 120, 'R', 'Poção da Insanidade', 'Singed bebe uma mistura de compostos químicos potentes que concede a ele atributos de combate aumentados e faz com que o Rastro de Veneno aplique Feridas Dolorosas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/InsanityPotion.png'),
('IreliaE', 46, 'E', 'Dueto Impecável', 'Irelia lança duas lâminas que convergem uma em direção à outra. Inimigos no fogo cruzado sofrem dano, ficam atordoados e são marcados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IreliaE.png'),
('IreliaQ', 46, 'Q', 'Surto da Lâmina', 'Irelia avança para atingir o seu alvo e cura a si mesma. Se ele estiver marcado ou for abatido com Surto da Lâmina, o Tempo de Recarga será restaurado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IreliaQ.png'),
('IreliaR', 46, 'R', 'Lâmina da Vanguarda', 'Irelia lança uma série de lâminas que explodem ao atingir um Campeão inimigo. Inimigos atingidos pelas lâminas sofrem dano e são marcados. Depois, as lâminas formam uma parede que causa dano e reduz a velocidade dos inimigos que a atravessarem.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IreliaR.png'),
('IreliaW', 46, 'W', 'Dança Desafiadora', 'Irelia carrega um golpe que causa mais dano conforme o carregamento. Ela também recebe Dano Físico reduzido durante esse carregamento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IreliaW.png'),
('Irelia_P', 46, 'P', 'Fervor Ioniano', 'Quando Irelia acerta inimigos com suas habilidades, ela ganha acúmulo de Velocidade de Ataque adicional. Ao atingir o máximo de acúmulos, Irelia também ganha dano adicional ao contato.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Irelia_Passive.png'),
('IvernE', 47, 'E', 'Semente Engatilhada', 'Ivern concede a um aliado um Escudo que explode depois de uma breve duração, causando Lentidão e dano aos inimigos. O Escudo é redefinido se não atingir inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IvernE.png'),
('IvernQ', 47, 'Q', 'Encantador de Raízes', 'Ivern conjura uma vinha, causando dano e enraizando os alvos inimigos atingidos. Os aliados de Ivern podem avançar rapidamente em direção ao alvo enraizado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IvernQ.png'),
('IvernR', 47, 'R', 'Margarida!', 'Ivern invoca sua amiga Margarida para lutar ao seu lado. Reconjure para fazer Margarida atacar ou se mover.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IvernR.png'),
('IvernW', 47, 'W', 'Formação de Arbustos', 'Em arbustos, os Ataques de Ivern e seus aliados próximos causam Dano Mágico adicional. Ivern pode ativar a habilidade para criar um arbusto.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/IvernW.png'),
('Ivern_P', 47, 'P', 'Amigo da Floresta', 'Ivern não pode atacar ou ser atacado por monstros não épicos. Ele pode criar bosques mágicos que crescem ao longo do tempo em acampamentos da selva. Quando o bosque estiver em seu tamanho final, Ivern pode libertar os monstros para receber ouro e experiência.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/IvernP.png'),
('JackInTheBox', 117, 'W', 'Caixinha-Surpresa', 'Shaco cria uma Caixinha-Surpresa escondida. Quando ativada, ela causará temor e atacará inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JackInTheBox.png'),
('Janna_P', 48, 'P', 'Brisa de Impulso', 'Os aliados de Janna recebem Velocidade de Movimento ao se moverem em direção a ela. Janna causa uma parte da Velocidade de Movimento adicional como Dano Mágico adicional ao contato com Zéfiro.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Janna_Tailwind.png'),
('JarvanIVCataclysm', 49, 'R', 'Cataclisma', 'Jarvan IV heroicamente salta em direção ao alvo com força o suficiente para deformar o terreno, criando uma arena ao seu redor. Os inimigos próximos recebem dano no momento do impacto.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JarvanIVCataclysm.png'),
('JarvanIVDemacianStan', 49, 'E', 'Estandarte Demaciano', 'Jarvan IV carrega o orgulho de Demacia, recebendo passivamente Velocidade de Ataque adicional. Ativar o Estandarte Demaciano permite a Jarvan IV posicionar uma bandeira demaciana que causa Dano Mágico e concede Velocidade de Ataque a campeões aliados próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JarvanIVDemacianStandard.png'),
('JarvanIVDragonStrike', 49, 'Q', 'Ataque do Dragão', 'Jarvan IV estende sua lança, causando Dano Físico e reduzindo a Armadura de inimigos atingidos. Além disto, ela puxará Jarvan na direção de seu Estandarte Demaciano, arremessando inimigos em seu trajeto ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JarvanIVDragonStrike.png'),
('JarvanIVGoldenAegis', 49, 'W', 'Égide de Ouro', 'Jarvan IV invoca os antigos reis de Demacia para protegê-lo do perigo e atrasar os inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JarvanIVGoldenAegis.png'),
('JarvanIV_P', 49, 'P', 'Cadência Marcial', 'O primeiro ataque básico de Jarvan a um inimigo causa Dano Físico adicional com base na Vida atual dele. Este efeito não ocorrerá no mesmo inimigo novamente por alguns segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/JarvanIVP.png'),
('JavelinToss', 90, 'Q', 'Arremessar Lança / Bote', 'Na forma humana, Nidalee arremessa uma lança perfurante em seu alvo, que acumula dano enquanto está no ar. Como puma, seu próximo ataque irá tentar ferir o inimigo de maneira letal, causando dano inversamente proporcional à Vida do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JavelinToss.png'),
('JaxE', 50, 'E', 'Contra-Ataque', 'A proeza combatente de Jax lhe permite desviar de todos os ataques recebidos por um curto período de tempo, contra-atacando logo em seguida e atordoando os inimigos ao seu redor.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JaxE.png'),
('JaxQ', 50, 'Q', 'Salto Atacante', 'Jax salta em direção a uma unidade. Caso seja um inimigo, ele o atingirá com sua arma.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JaxQ.png'),
('JaxR', 50, 'R', 'Grão-Mestre de Armas', 'Cada terceiro ataque consecutivo causa Dano Mágico adicional. Além disso, Jax pode ativar essa habilidade para causar dano ao redor de si e fortalecer a própria determinação, ganhando mais Armadura e Resistência Mágica por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JaxR.png'),
('JaxW', 50, 'W', 'Energizar', 'Jax acumula energia em sua arma, fazendo com que seu próximo ataque básico ou Salto Atacante cause dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JaxW.png'),
('Jax_P', 50, 'P', 'Investida Implacável', 'Os ataques básicos consecutivos de Jax continuamente aumentam sua Velocidade de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Armsmaster_MasterOfArms.png'),
('JayceStanceHtG', 51, 'R', 'Canhão de Mercúrio / Martelo de Mercúrio', 'Empunhadura de Martelo: Transforma o Martelo de Mercúrio em Canhão de Mercúrio, recebendo novas habilidades e ataques à distância. O primeiro ataque desta forma reduzirá a Armadura e a Resistência Mágica do alvo.Empunhadura de Canhão: Transforma o Canhão de Mercúrio em Martelo de Mercúrio, recebendo novas habilidades, aumentando a Resistência Mágica e a Armadura. O primeiro ataque desta forma causará Dano Mágico adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JayceStanceHtG.png'),
('JayceStaticField', 51, 'W', 'Campo Elétrico / Hipercarga', 'Empunhadura de Martelo: Passivo: Restaura Mana a cada acerto. Ativo: Cria um campo elétrico que causa dano a inimigos próximos por muitos segundos.Empunhadura de Canhão: Recebe um impulso de energia, aumentando a Velocidade de Ataque para seu máximo por diversos ataques.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JayceStaticField.png'),
('JayceThunderingBlow', 51, 'E', 'Golpe Trovejante / Portão Acelerador', 'Empunhadura de Martelo: causa Dano Mágico e empurra inimigos por uma curta distância.Empunhadura de Canhão: posiciona um Portão Acelerador que aumenta a Velocidade de Movimento dos Campeões aliados que o atravessarem. Se Disparo Chocante for usada através do portão, a velocidade, o alcance e o dano do projétil aumentarão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JayceThunderingBlow.png'),
('JayceToTheSkies', 51, 'Q', 'Aos Céus! / Disparo Chocante', 'Empunhadura de Martelo: Salta na direção de um inimigo, causando Dano Físico e Lentidão.Empunhadura de Canhão: Dispara um orbe de eletricidade que detona ao atingir um inimigo (ou ao alcançar o fim de seu trajeto), causando Dano Físico a todos os inimigos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JayceToTheSkies.png'),
('Jayce_P', 51, 'P', 'Capacitor Hextec', 'Quando Jayce troca de arma, ele recebe Velocidade de Movimento por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Jayce_Passive.png'),
('JhinE', 52, 'E', 'Audiência Cativa', 'Jhin posiciona uma armadilha de lótus invisível que floresce ao ser pisada. Ela reduz a velocidade de inimigos próximos antes de causar dano com uma explosão de pétalas serrilhadas. Beleza em Morte - Quando Jhin abate um Campeão inimigo, uma armadilha de lótus florescerá próximo a seu cadáver.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JhinE.png'),
('JhinQ', 52, 'Q', 'Granada Dançante', 'Jhin lança um cartucho mágico em um inimigo. Ele pode atingir até quatro alvos e acumula dano a cada vez que causa um abate.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JhinQ.png'),
('JhinR', 52, 'R', 'Aclamação', 'Jhin canaliza, transformando a Sussurro em um mega-canhão de ombro. Ela é capaz de fazer 4 super disparos com extremo alcance que atravessam tropas e monstros, mas que param no primeiro campeão atingido. A Sussurro mutila os inimigos atingidos, o que reduz sua velocidade e aumenta o dano de execução. O 4º disparo é feito com perfeição, de poder épico e garante um acerto crítico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JhinR.png'),
('JhinW', 52, 'W', 'Florescer Mortal', 'Jhin brande sua bengala, fazendo um disparo único com incrível alcance. Ele atravessa tropas e monstros, mas para no primeiro Campeão atingido. Se o alvo foi recentemente atingido por aliados de Jhin, por Armadilhas de Lótus ou recebeu dano de Jhin, ele será enraizado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JhinW.png'),
('Jhin_P', 52, 'P', 'Sussurro', 'Sussurro, o canhão de mão de Jhin, é um instrumento preciso que foi projetado para causar muito dano. Ele dispara com frequência fixa e carrega apenas quatro projéteis. Jhin encanta o projétil final com magia sombria para causar Acerto Crítico e dano de execução adicional. Sempre que causa um Acerto Crítico, Sussurro inspira Jhin com um impulso de Velocidade de Movimento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Jhin_P.png'),
('JinxE', 53, 'E', 'Mordidinha Flamejante!', 'Jinx arremessa uma fileira de granadas-armadilha que explodem após 5 segundos, deixando os inimigos em chamas. As Mordidinhas Flamejantes morderão campeões inimigos que caminharem sobre elas, enraizando-os no local.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JinxE.png'),
('JinxQ', 53, 'Q', 'Trocando!', 'Jinx modifica seus ataques básicos ao trocar entre Pow-Pow, sua metralhadora, e Fishbones, seu lança-mísseis. Ataques com Pow-Pow concedem Velocidade de Ataque, enquanto ataques com Fishbones causam dano em área de ação e recebem aumento de alcance, mas drenam Mana e reduzem a Velocidade de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JinxQ.png'),
('JinxR', 53, 'R', 'Super Mega Míssil da Morte!', 'Jinx dispara um super-míssil no mapa, que acumula dano ao longo de seu trajeto. O míssil explodirá ao colidir com um campeão inimigo, causando dano a ele e a inimigos ao seu redor, com base em sua Vida removida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JinxR.png'),
('JinxW', 53, 'W', 'Zap!', 'Jinx usa Zapper, sua pistola de choques, para disparar um projétil que causa dano ao primeiro inimigo atingido, reduzindo sua velocidade e revelando-o.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/JinxW.png'),
('Jinx_P', 53, 'P', 'Anime-se!', 'Jinx recebe um aumento drástico de Velocidade de Movimento e de Velocidade de Ataque sempre que ajuda a destruir uma estrutura ou a abater um Campeão inimigo ou monstro épico da selva.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Jinx_Passive.png'),
('KaisaE', 54, 'E', 'Sobrecarga', 'Kai\'Sa aumenta brevemente sua Velocidade de Movimento, depois aumenta sua Velocidade de Ataque.Arma Viva: Sobrecarga é aprimorada e concede Invisibilidade por um breve momento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KaisaE.png'),
('KaisaQ', 54, 'Q', 'Chuva Icathiana', 'Kai\'Sa dispara uma chuva de projéteis que correm atrás de alvos próximos.Arma Viva: Chuva Icathiana é aprimorada e lança mais mísseis.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KaisaQ.png'),
('KaisaR', 54, 'R', 'Instinto Assassino', 'Kai\'Sa avança para perto de um Campeão inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KaisaR.png'),
('KaisaW', 54, 'W', 'Exploradora do Vazio', 'Kai\'Sa lança um projétil de longo alcance, marcando inimigos com sua passiva.Arma Viva: Exploradora do Vazio é aprimorada e aplica mais marcas passivas e tem o Tempo de Recarga reduzido ao acertar um Campeão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KaisaW.png'),
('Kaisa_P', 54, 'P', 'Segunda Pele', 'Os ataques básicos de Kai\'Sa acumulam Plasma, causando Dano Mágico adicional crescente. Efeitos imobilizadores de aliados ajudam a acumular Plasma. Além disso, as aquisições de itens de Kai\'Sa aprimoram suas habilidades básicas, deixando-as mais poderosas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Kaisa_Passive.png'),
('KalistaExpungeWrappe', 55, 'E', 'Lacerar', 'Os ataques empalam seus alvos com lanças. Ative para arrancar as lanças, causando Lentidão e dano crescente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KalistaExpungeWrapper.png'),
('KalistaMysticShot', 55, 'Q', 'Perfurar', 'Arremessa uma lança de movimento rápido que atravessa os inimigos que abate.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KalistaMysticShot.png'),
('KalistaRx', 55, 'R', 'Chamado do Destino', 'Kalista teleporta o aliado em Juramento para si mesma. Eles recebem a capacidade de avançar em uma direção, empurrando para trás os inimigos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KalistaRx.png'),
('KalistaW', 55, 'W', 'Vigia', 'Ganha dano adicional quando Kalista e seu aliado Em Juramento atingem o mesmo alvo. Ative para enviar uma alma para patrulhar um caminho, revelando a área à sua frente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KalistaW.png'),
('Kalista_P', 55, 'P', 'Aprumo Marcial', 'Realize um comando de movimentação enquanto Kalista carrega seu ataque básico ou Perfurar para saltar em uma curta distância quando ela lançar o ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Kalista_Passive.png'),
('KarmaMantra', 56, 'R', 'Mantra', 'Karma fortalece sua próxima habilidade para dar um efeito adicional. Mantra está disponível no nível 1 e não exige um ponto de habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KarmaMantra.png'),
('KarmaQ', 56, 'Q', 'Chama Interior', 'Karma dispara uma esfera de energia espiritual que explode e causa dano ao atingir uma unidade inimiga.Efeito de Mantra: Além da explosão, Mantra aumenta o poder destrutivo de sua Chama Interior, criando um cataclisma que causa dano depois de um breve intervalo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KarmaQ.png'),
('KarmaSolKimShield', 56, 'E', 'Inspiração', 'Karma invoca um escudo protetor que absorve o dano sofrido e aumenta a Velocidade de Movimento do aliado protegido.Efeito de Mantra: o alvo irradia energia, fortalecendo o Escudo inicial e aplicando Inspiração a Campeões aliados próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KarmaSolKimShield.png'),
('KarmaSpiritBind', 56, 'W', 'Decisão Absorta', 'Karma cria um vínculo entre ela e o inimigo-alvo, causando dano e revelando-o. Se o vínculo não for quebrado, o inimigo será enraizado e sofrerá dano novamente.Efeito de Mantra: Karma fortalece o vínculo, se curando e prolongando a duração do enraizamento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KarmaSpiritBind.png'),
('Karma_P', 56, 'P', 'Ímpeto Ardente', 'As habilidades de dano de Karma reduzem o Tempo de Recarga de Mantra.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Karma_Passive.png'),
('KarthusDefile', 57, 'E', 'Perverter', 'Karthus passivamente rouba energia de suas vítimas, recebendo Mana a cada abate. Ele também pode se cercar das almas de suas presas, causando dano a inimigos próximos, mas drenando rapidamente a própria Mana.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KarthusDefile.png'),
('KarthusFallenOne', 57, 'R', 'Réquiem', 'Após canalizar por 3 segundos, Karthus causa dano a todos os Campeões inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KarthusFallenOne.png'),
('KarthusLayWasteA1', 57, 'Q', 'Devastar', 'Karthus desfere uma explosão em um local após um intervalo, causando dano a inimigos próximos. Causa mais dano a inimigos isolados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KarthusLayWasteA1.png'),
('KarthusWallOfPain', 57, 'W', 'Barreira da Dor', 'Karthus cria uma barreira transponível de energia parasita. Qualquer unidade inimiga que atravessá-la tem sua Velocidade de Movimento e Resistência Mágica reduzidas por um período de tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KarthusWallOfPain.png'),
('Karthus_P', 57, 'P', 'Desafio da Morte', 'Ao morrer, Karthus entra em forma de espírito e pode continuar conjurando habilidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Karthus_Passive.png'),
('Kassadin_P', 58, 'P', 'Pedra do Vazio', 'Kassadin sofre Dano Mágico reduzido e ignora colisão com unidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Kassadin_Passive.png'),
('KatarinaEWrapper', 59, 'E', 'Shunpo', 'Katarina desloca-se em direção ao alvo, golpeando-o caso seja inimigo ou golpeando o inimigo mais próximo caso não seja.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KatarinaEWrapper.png'),
('KatarinaQ', 59, 'Q', 'Lâmina Saltitante', 'Katarina arremessa uma Adaga no alvo. Ela salta em inimigos próximos antes de ricochetear e cair no chão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KatarinaQ.png'),
('KatarinaR', 59, 'R', 'Lótus da Morte', 'Katarina gira em torno de si mesma, disparando adagas muito rapidamente e causando muito Dano Mágico nos 3 Campeões inimigos mais próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KatarinaR.png'),
('KatarinaW', 59, 'W', 'Preparação', 'Katarina recebe um impulso de Velocidade de Movimento e joga uma Adaga para cima.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KatarinaW.png'),
('Katarina_P', 59, 'P', 'Voracidade', 'Os Tempos de Recarga de Katarina são reduzidos drasticamente sempre que um Campeão que ela havia causado dano recentemente morrer.Se apanhar uma Adaga, Katarina a usa para cortar todos os inimigos próximos, causando Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Katarina_Passive.png'),
('KayleE', 60, 'E', 'Lâmina de Fogo Estelar', 'Passivo: a espada celestial de Kayle, Virtude, causa Dano Mágico adicional aos inimigos que ela ataca.Ativo: o próximo ataque de Kayle atinge seu alvo com fogo celestial, causando dano adicional proporcional à Vida perdida do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KayleE.png'),
('KayleQ', 60, 'Q', 'Explosão Radiante', 'Kayle conjura um portal, invocando uma espada celestial que atravessa os inimigos, causando dano e reduzindo a velocidade e as resistências de tudo que atingir.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KayleQ.png'),
('KayleR', 60, 'R', 'Sentença Divina', 'Kayle torna um aliado invulnerável e evoca os antigos Aspectos da Justiça para purificarem a área ao redor do seu alvo com uma chuva de espadas sagradas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KayleR.png'),
('KayleW', 60, 'W', 'Bênção Celestial', 'Abençoada pelas divindades, Kayle cura e concede Velocidade de Movimento a si mesma e ao aliado mais próximo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KayleW.png'),
('Kayle_P', 60, 'P', 'Ascensão Divina', 'Os ataques de Kayle são fortalecidos pelos céus conforme ela aumenta de nível de Campeão e de habilidades. Suas asas ficam flamejantes conforme ela progressivamente ganha Velocidade de Ataque, Velocidade de Movimento, Alcance de Ataque e ondas de fogo em seus ataques.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Kayle_P.png'),
('KaynE', 61, 'E', 'Passo das Sombras', 'Kayn pode atravessar terrenos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KaynE.png'),
('KaynQ', 61, 'Q', 'Corte Ceifador', 'Kayn avança, depois ataca. Ambos dão dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KaynQ.png'),
('KaynR', 61, 'R', 'Transgressão do Umbral', 'Kayn se esconde no corpo de um inimigo e causa bastante dano quando rasga sua saída.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KaynR.png'),
('KaynW', 61, 'W', 'Alcance da Lâmina', 'Kayn causa dano e reduz a velocidade dos alvos na linha de fogo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KaynW.png'),
('Kayn_P', 61, 'P', 'A Foice Darkin', 'Kayn empunha uma arma ancestral, lutando contra Rhaast, o darkin que vive dentro dela, pelo controle. Ou o Darkin triunfará ou Kayn dominará Rhaast para se tornar o Assassino das Sombras.Darkin: Cura uma porcentagem do dano de habilidades causado a Campeões.Assassino das Sombras: Causa dano adicional nos primeiros segundos em combate com Campeões inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Kayn_Passive_Primary.png'),
('KennenBringTheLight', 62, 'W', 'Surto Elétrico', 'Kennen passivamente causa dano adicional e adiciona uma Marca da Tormenta a seu alvo a cada certo número de ataques. Ele pode ativar essa habilidade para causar dano e adicionar outra Marca da Tormenta a alvos que já estão marcados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KennenBringTheLight.png'),
('KennenLightningRush', 62, 'E', 'Investida Relâmpago', 'Kennen assume uma forma de relâmpago, permitindo que passe por unidades e aplique a Marca da Tormenta. Ele também ganha Velocidade de Movimento ao assumir essa forma e Velocidade de Ataque ao sair dela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KennenLightningRush.png'),
('KennenShurikenHurlMi', 62, 'Q', 'Shuriken Trovejante', 'Kennen arremessa um shuriken de alta velocidade em um local, causando dano e adicionando uma Marca da Tormenta a qualquer oponente atingido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KennenShurikenHurlMissile1.png'),
('KennenShurikenStorm', 62, 'R', 'Turbilhão Cortante', 'Kennen invoca uma tempestade que atinge campeões inimigos próximos com Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KennenShurikenStorm.png'),
('Kennen_P', 62, 'P', 'Marca da Tormenta', 'Kennen atordoa os inimigos que atingir 3 vezes com suas habilidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Kennen_Passive.png'),
('KhazixE', 63, 'E', 'Pulo', 'Kha\'Zix pula em uma área, causando Dano Físico ao aterrissar. Caso ele escolha Evoluir Asas, o alcance do Pulo é aumentado em 200 e o Tempo de Recarga é zerado com o abate ou assistência de Campeões.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KhazixE.png'),
('KhazixQ', 63, 'Q', 'Sabor de Medo', 'Causa Dano Físico ao alvo. Dano aumentado em alvos Isolados. Caso ele escolha Evoluir Garras Aumentadas, recupera um percentual de seu Tempo de Recarga contra alvos Isolados. Kha\'Zix também recebe aumento de alcance em seus ataques básicos e em Sabor de Medo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KhazixQ.png'),
('KhazixR', 63, 'R', 'Massacre do Vazio', 'Cada nível permite que Kha\'Zix evolua uma de suas habilidades, dando a elas um efeito único adicional. Quando ativada, Kha\'Zix fica Invisível, acionando Ameaça Invisível e aumentando sua Velocidade de Movimento. Caso ele escolha Evoluir Camuflagem Adaptativa, Massacre do Vazio ganha maior duração de Invisibilidade e um uso adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KhazixR.png'),
('KhazixW', 63, 'W', 'Espinho do Vazio', 'Kha\'Zix dispara espinhos explosivos que causam Dano Físico aos inimigos atingidos. Kha\'Zix é curado caso esteja no raio da explosão. Caso escolha Evoluir Fileiras de Espinhos, Espinho do Vazio passa a disparar três espinhos em área de cone, reduz a velocidade dos inimigos atingidos e revela Campeões inimigos atingidos por 2 segundos. Alvos Isolados têm redução adicional de velocidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KhazixW.png'),
('Khazix_P', 63, 'P', 'Ameaça Invisível', 'Inimigos próximos que estiverem isolados de seus aliados são marcados. As habilidades de Kha\'Zix possuem interações com alvos isolados.Quando Kha\'Zix não estiver visível para a equipe inimiga, ele recebe Ameaça Invisível, fazendo com que seu próximo ataque básico contra um Campeão inimigo cause Dano Mágico adicional e reduza a velocidade do alvo por alguns segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Khazix_P.png'),
('KindredEWrapper', 64, 'E', 'Pesar Crescente', 'A Ovelha faz um disparo cuidadoso, reduzindo a velocidade de seu alvo. Se a Ovelha atacar o alvo mais duas vezes, seu próximo ataque fará com que o Lobo salte no inimigo, golpeando-o e causando muito dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KindredEWrapper.png');
INSERT INTO `habilidades` (`ID_habilidade`, `ID_campeao`, `tecla`, `nome_habilidade`, `descricao`, `imagem_url`) VALUES
('KindredQ', 64, 'Q', 'Dança de Flechas', 'Os Kindred rolam e disparam até três flechas em alvos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KindredQ.png'),
('KindredR', 64, 'R', 'Refúgio da Ovelha', 'A Ovelha concede refúgio contra a morte para todos os seres vivos em uma área. Até que seu efeito acabe, nada pode morrer. No fim de sua duração, as unidades são curadas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KindredR.png'),
('KindredW', 64, 'W', 'Frenesi do Lobo', 'O Lobo se enraivece e ataca inimigos à sua volta. A Ovelha ganha acúmulos passivamente ao se mover e atacar. Quando totalmente carregado, o próximo ataque da Ovelha recupera Vida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KindredW.png'),
('Kindred_P', 64, 'P', 'Marca Familiar', 'Os Kindred marcam alvos para Caçar. Concluir uma Caçada fortalece permanentemente as habilidades básicas deles. A cada 4 caçadas concluídas, o Alcance de Ataque também aumenta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Kindred_Passive.png'),
('KledE', 65, 'E', 'Justar', 'Kled avança, causando Dano Físico e recebendo um breve surto de velocidade. Ele pode conjurar esta habilidade novamente para recuar através do alvo inicial, causando a mesma quantidade de dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KledE.png'),
('KledQ', 65, 'Q', 'Armadilha na Corda', 'Kled arremessa uma armadilha de urso que causa dano e se prende a um Campeão inimigo. Caso fique preso por um curto período, o alvo recebe Dano Físico adicional e é puxado em direção a Kled.Quando desmontado, esta habilidade é substituída por Pistola de Bolso, um disparo a distância que empurra Kled para trás e restaura coragem.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KledQ.png'),
('KledR', 65, 'R', 'Avançaaaaaaar!!!', 'Kled e Skaarl avançam em direção a um local, deixando um rastro que concede velocidade e criando um escudo. Skaarl marca e vai de encontro ao primeiro Campeão inimigo encontrado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KledR.png'),
('KledW', 65, 'W', 'Tendências Violentas', 'Kled recebe muita Velocidade de Ataque por quatro ataques. O quarto ataque causa mais dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KledW.png'),
('Kled_P', 65, 'P', 'Skaarl, a Lagarto Covarde', 'Kled fica em sua possante montaria, Skaarl, que toma dano por ele. Quando a Vida dela acaba, Kled desmonta.Enquanto desmontado, as habilidades de Kled mudam e ele causa menos dano a Campeões. Kled pode restaurar a coragem de Skaarl ao enfrentar inimigos. Quando a coragem chega ao máximo, Kled volta a montar em Skaarl com uma parte de sua Vida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Kled_P.png'),
('KogMawBioArcaneBarra', 66, 'W', 'Barragem Bio-Arcana', 'Os ataques de Kog\'Maw recebem alcance estendido e causam um percentual da Vida máxima do alvo como Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KogMawBioArcaneBarrage.png'),
('KogMawLivingArtiller', 66, 'R', 'Artilharia Viva', 'Kog\'Maw dispara uma cápsula de artilharia a uma grande distância, causando Dano Mágico (aumentado drasticamente em inimigos com pouca Vida) e revelando alvos não invisíveis. Além disso, mais de uma Artilharia Viva em um curto período de tempo faz com que custem Mana adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KogMawLivingArtillery.png'),
('KogMawQ', 66, 'Q', 'Cusparada Cáustica', 'Kog\'Maw dispara um projétil corrosivo que causa Dano Mágico, corroendo a Armadura e Resistência Mágica do alvo por um curto período de tempo. Kog\'Maw também recebe Velocidade de Ataque adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KogMawQ.png'),
('KogMawVoidOoze', 66, 'E', 'Gosma do Vazio', 'Kog\'Maw lança uma gosma que causa dano em todos os inimigos pelos quais ela passa, deixando um rastro que reduz a velocidade de inimigos que ficarem sobre ela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KogMawVoidOoze.png'),
('KogMaw_P', 66, 'P', 'Surpresa Icathiana', 'Ao morrer, Kog\'Maw explode depois de 4s, causando Dano Verdadeiro a inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/KogMaw_IcathianSurprise.png'),
('KSanteE', 67, 'E', 'Passo Forte', 'K\'Sante avançará até um aliado e ambos receberão um Escudo. Se não houver aliados por perto, K\'Sante ainda avançará até o local com um alcance reduzido, recebendo um Escudo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KSanteE.png'),
('KSanteQ', 67, 'Q', 'Golpes de Ntofo', 'Golpeia à frente com a arma, causando dano e Lentidão a todos os inimigos em uma curta linha reta.Ao contato, ganha um acúmulo por alguns segundos. Com 2 acúmulos, dispara uma onda de choque que puxa os inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KSanteQ.png'),
('KSanteR', 67, 'R', 'Forma Irrestrita', 'K\'Sante empurra um inimigo para longe. Se o inimigo atingir uma parede, ele a atravessa e sofre mais dano. K\'Sante aparece atrás do alvo e usa Forma Irrestrita, fragmentando as próprias defesas, mas aumentando drasticamente o próprio dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KSanteR.png'),
('KSanteW', 67, 'W', 'Criador de Caminhos', 'K\'Sante carrega antes de avançar. K\'Sante fica Imbatível e sofre dano reduzido durante o carregamento. Alvos atingidos pelo avanço são empurrados até o fim do trajeto e atordoados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/KSanteW.png'),
('KSante_P', 67, 'P', 'Instinto Valente', 'As Habilidades de K\'Sante marcam os alvos para que sofram mais dano do próximo Ataque dele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Icons_KSante_P.png'),
('Landslide', 76, 'E', 'Estrondar Terreno', 'Malphite golpeia o chão, enviando uma onda de choque que causa Dano Mágico com base em sua Armadura e reduz a Velocidade de Ataque dos inimigos por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Landslide.png'),
('LeblancE', 68, 'E', 'Correntes Etéreas', 'LeBlanc lança uma corrente que prende a primeira unidade atingida. Se o alvo permanecer preso por 1,5s, ele é enraizado e sofre dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LeblancE.png'),
('LeblancQ', 68, 'Q', 'Sigilo de Malícia', 'LeBlanc projeta um Sigilo, causando dano e marcando o alvo por 3,5s. Causar dano ao alvo marcado com qualquer Habilidade detona o Sigilo, causando dano adicional. Se qualquer parte dessa combinação abater o alvo, LeBlanc restitui o custo de Mana e parte do Tempo de Recarga restante desta Habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LeblancQ.png'),
('LeblancR', 68, 'R', 'Mímica', 'Leblanc conjura uma versão copiada de uma de suas habilidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LeblancR.png'),
('LeblancW', 68, 'W', 'Distorção', 'LeBlanc avança até um local, causando dano aos inimigos próximos de seu destino. Pelos próximos 4s, ativar Distorção novamente faz com que LeBlanc retorne até sua posição inicial.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LeblancW.png'),
('Leblanc_P', 68, 'P', 'Imagem-Espelho', 'Quando a Vida de LeBlanc está abaixo de 40%, ela fica invisível por 1s e cria uma Imagem-Espelho que não causa dano e dura até 8s.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/LeBlancP.png'),
('LeeSin_P', 69, 'P', 'Agitação', 'Após Lee Sin usar uma habilidade, seus próximos 2 ataques básicos recebem Velocidade de Ataque e recuperam Energia.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/LeeSinPassive.png'),
('LeonaShieldOfDaybrea', 70, 'Q', 'Proteção da Aurora', 'Leona usa seu escudo para fazer seu próximo ataque básico, causando Dano Mágico adicional e atordoando o alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LeonaShieldOfDaybreak.png'),
('LeonaSolarBarrier', 70, 'W', 'Eclipse', 'Leona ergue seu escudo para receber redução de dano, Armadura e Resistência Mágica. Quando a duração chegar ao fim, caso haja inimigos próximos, ela causará Dano Mágico a eles e prolongará a duração do efeito.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LeonaSolarBarrier.png'),
('LeonaSolarFlare', 70, 'R', 'Labareda Solar', 'Leona invoca um raio de energia solar do céu, causando dano aos inimigos em uma área. Inimigos no centro da área são atordoados, enquanto inimigos próximos à extremidade sofrem redução de velocidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LeonaSolarFlare.png'),
('LeonaZenithBlade', 70, 'E', 'Lâmina Zênite', 'Leona projeta uma imagem solar da sua espada, causando Dano Mágico a todos os inimigos em uma fila. Quando a imagem some, o último campeão inimigo a ser acertado fica imobilizado por um curto periodo e Leona o ataca.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LeonaZenithBlade.png'),
('Leona_P', 70, 'P', 'Luz do Sol', 'Habilidades que causam dano atingem os inimigos com Luz do Sol por 1,5s. Quando Campeões aliados causam dano a esses alvos, a Luz do Sol é consumida para causar Dano Mágico adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/LeonaSunlight.png'),
('LilliaE', 71, 'E', 'Semente Espiral', 'Lillia lança uma semente que causa dano e reduz a velocidade dos inimigos atingidos. Caso não atinja nada, Semente Espiral continuará avançando até colidir com uma parede ou alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LilliaE.png'),
('LilliaQ', 71, 'Q', 'Golpes Florescentes', 'Lillia ganha acúmulos de Velocidade de Movimento passivamente ao atingir inimigos com habilidades. Ela pode ativar esta habilidade para causar Dano Mágico aos inimigos próximos e Dano Verdadeiro adicional na porção externa do círculo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LilliaQ.png'),
('LilliaR', 71, 'R', 'Cadência de Ninar', 'Todos os inimigos com Pó dos Sonhos são afetados por Sonolência e adormecem em seguida. Esses inimigos sofrem dano adicional se forem acordados de forma abrupta por dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LilliaR.png'),
('LilliaW', 71, 'W', 'Cuidado! Iiip!', 'Lillia causa dano em uma área próxima, com dano amplificado no centro.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LilliaW.png'),
('Lillia_P', 71, 'P', 'Ramo Onírico', 'Atingir um Campeão ou monstro com uma habilidade causa dano adicional com base na Vida máxima do alvo ao longo do tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Lillia_Icon_Passive.png'),
('LissandraE', 72, 'E', 'Caminho Glacial', 'Lissandra cria uma garra de gelo que causa Dano Mágico. Reativar essa habilidade transporta Lissandra ao local atual da garra.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LissandraE.png'),
('LissandraQ', 72, 'Q', 'Estilhaço de Gelo', 'Arremessa uma lança de gelo que se estilhaça ao atingir um inimigo, causando Dano Mágico e reduzindo sua Velocidade de Movimento. Os estilhaços atravessam o alvo, causando o mesmo dano a outros inimigos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LissandraQ.png'),
('LissandraR', 72, 'R', 'Túmulo Congelado', 'Se conjurada em um Campeão inimigo, o alvo será congelado e atordoado. Se conjurada em Lissandra, ela se protege em um bloco de gelo sombrio, curando a si mesma enquanto fica inalvejável e invulnerável. Em seguida, o gelo sombrio emana a partir do alvo, causando Dano Mágico e reduzindo a Velocidade de Movimento de inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LissandraR.png'),
('LissandraW', 72, 'W', 'Círculo Ártico', 'Prende inimigos próximos em gelo, causando-lhes Dano Mágico e enraizando-os.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LissandraW.png'),
('Lissandra_P', 72, 'P', 'Submissão Glacinata', 'Quando um Campeão inimigo morre próximo a Lissandra, ele vira um Servo Congelado. Servos Congelados reduzem a velocidade de inimigos próximos e, depois de um intervalo, estilhaçam devido ao frio intenso, causando Dano Mágico a alvos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Lissandra_Passive.png'),
('LucianE', 73, 'E', 'Perseguição Implacável', 'Lucian avança rapidamente uma curta distância. Disparo Iluminado reduz o Tempo de Recarga de Perseguição Implacável.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LucianE.png'),
('LucianQ', 73, 'Q', 'Luz Perfurante', 'Lucian faz um disparo de luz perfurante através de um alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LucianQ.png'),
('LucianR', 73, 'R', 'O Expurgo', 'Lucian desfere uma torrente de disparos de suas armas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LucianR.png'),
('LucianW', 73, 'W', 'Chama Ardente', 'Lucian dispara um projétil que explode em formato de estrela, marcando e revelando brevemente os inimigos. Ele recebe Velocidade de Movimento por atacar inimigos marcados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LucianW.png'),
('Lucian_P', 73, 'P', 'Disparo Iluminado', 'Sempre que Lucian usa uma Habilidade, seu próximo Ataque se transforma em um disparo duplo. Quando Lucian é curado ou protegido por um aliado, ou quando um Campeão inimigo próximo é imobilizado, os próximos dois Ataques básicos dele causam Dano Mágico adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Lucian_Passive.png'),
('LuluE', 74, 'E', 'Socorro, Pix!', 'Se conjurada em um aliado, ordena para que Pix pule nele e o proteja. Ela em seguida o segue e ajuda com seus ataques. Se conjurada em um inimigo, ordena para que Pix pule nele e o atinja. Ela o segue e lhe concede visão do inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LuluE.png'),
('LuluQ', 74, 'Q', 'Lança-Purpurina', 'Pix e Lulu disparam um raio de energia mágica que causa dano e muita Lentidão aos inimigos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LuluQ.png'),
('LuluR', 74, 'R', 'Crescimento Virente', 'Lulu aumenta o tamanho de um aliado, arremessando ao ar inimigos próximos e concedendo ao aliado uma grande quantidade de Vida adicional. Pelos próximos segundos, tal aliado recebe uma aura que reduz a velocidade de inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LuluR.png'),
('LuluW', 74, 'W', 'Caprichos', 'Se conjurada sobre um aliado, ela lhe concede Velocidade de Movimento por um curto período de tempo. Se lançado sobre um inimigo, ele é transformado em um adorável bichinho que não pode atacar nem lançar feitiços.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LuluW.png'),
('Lulu_P', 74, 'P', 'Pix, o Silfo Companheiro', 'Pix faz disparos de energia mágica sempre que o Campeão que estiver seguindo atacar outra unidade inimiga. Os disparos seguem o inimigo, mas podem ser interceptados por outras unidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Lulu_PixFaerieCompanion.png'),
('LuxLightBinding', 75, 'Q', 'Ligação da Luz', 'Lux atira uma esfera de luz que se prende e causa dano em até duas unidades inimigas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LuxLightBinding.png'),
('LuxLightStrikeKugel', 75, 'E', 'Singularidade Lucente', 'Dispara uma luz irregular em uma área, reduzindo a velocidade de inimigos próximos. Lux pode detoná-la para causar dano aos inimigos na área de ação.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LuxLightStrikeKugel.png'),
('LuxPrismaticWave', 75, 'W', 'Barreira Prismática', 'Lux lança sua varinha e uma luz envolve todos os aliados atingidos, protegendo-os contra dano inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LuxPrismaticWave.png'),
('LuxR', 75, 'R', 'Centelha Final', 'Após acumular energia, Lux dispara um feixe de luz que causa dano a todos os inimigos na área. Além disso, ativa a habilidade passiva de Lux e reinicia a duração do efeito de Iluminação.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/LuxR.png'),
('Lux_P', 75, 'P', 'Iluminação', 'As habilidades de dano de Lux carregam o alvo com energia por alguns segundos. O próximo ataque de Lux incendeia a energia, causando Dano Mágico adicional (com base no nível de Lux) ao alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/LuxIlluminatingFraulein.png'),
('Malphite_P', 76, 'P', 'Escudo de Granito', 'Malphite está protegido por uma camada de rocha que absorve dano equivalente a até 10% de sua Vida máxima. Se Malphite não for atingido por alguns segundos, o efeito é recarregado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Malphite_GraniteShield.png'),
('MalzaharE', 77, 'E', 'Visões Maléficas', 'Malzahar infecta a mente de seu alvo com visões cruéis de sua própria morte, causando dano ao longo do tempo. Usar as outras habilidades de Malzahar no alvo reiniciará o efeito.Se o alvo for abatido enquanto afligido pelas visões, elas são transmitidas para uma unidade inimiga próxima e Malzahar recebe Mana. Os Voidlings de Malzahar são atraídos para as unidades afetadas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MalzaharE.png'),
('MalzaharQ', 77, 'Q', 'Chamado do Vazio', 'Malzahar abre dois portais para o Vazio. Depois de um breve intervalo, eles disparam projéteis que causam Dano Mágico e silenciam Campeões inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MalzaharQ.png'),
('MalzaharR', 77, 'R', 'Aperto Ínfero', 'Malzahar canaliza a essência do Vazio para suprimir o Campeão-alvo sobre uma área de energia negativa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MalzaharR.png'),
('MalzaharW', 77, 'W', 'Enxame do Vazio', 'Malzahar invoca Voidlings para atacar inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MalzaharW.png'),
('Malzahar_P', 77, 'P', 'Oscilação do Vazio', 'Caso não tenha sofrido dano ou efeitos de Controle de Grupo recentemente, Malzahar recebe uma enorme redução de dano e imunidade a Controles de Grupo, que duram um curto período após sofrer dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Malzahar_Passive.png'),
('MaokaiE', 78, 'E', 'Atirar Mudas', 'Maokai arremessa uma muda na área-alvo para ficar de guarda, sendo mais eficiente em arbustos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MaokaiE.png'),
('MaokaiQ', 78, 'Q', 'Esmagamento Espinhoso', 'Maokai empurra inimigos próximos para trás com uma onda de choque, causando Dano Mágico e redução de velocidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MaokaiQ.png'),
('MaokaiR', 78, 'R', 'Garras da Natureza', 'Maokai invoca uma parede colossal de espinhos que avança lentamente, causando dano e enraizando inimigos no caminho.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MaokaiR.png'),
('MaokaiW', 78, 'W', 'Avanço Retorcido', 'Maokai se transforma em uma massa de raízes ambulante, ficando inalvejável e avançando até o alvo. Ao chegar, ele enraíza o alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MaokaiW.png'),
('Maokai_P', 78, 'P', 'Seiva Mágica', 'O ataque básico de Maokai também concede cura a ele e causa dano adicional com um Tempo de Recarga moderado. Sempre que ele conjurar uma habilidade ou for atingido por uma habilidade inimiga, o Tempo de Recarga da cura é reduzido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Maokai_Passive.png'),
('MasterYi_P', 79, 'P', 'Ataque duplo', 'A cada alguns ataques básicos consecutivos, Master Yi ataca duas vezes.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/MasterYi_Passive1.png'),
('Meditate', 79, 'W', 'Meditar', 'Master Yi rejuvenesce seu corpo com a força da mente, restaurando Vida e recebendo dano reduzido por um curto período. Além disso, ele recebe acúmulos de Ataque Duplo e pausa a duração restante de Estilo Wuju e de Highlander para cada segundo de canalização.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Meditate.png'),
('MegaAdhesive', 120, 'W', 'Mega Adesivo', 'Joga um frasco de Mega Adesivo no chão, reduzindo a velocidade e prendendo os inimigos que pisam nele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MegaAdhesive.png'),
('MilioE', 80, 'E', 'Abraços Quentinhos', 'Milio concede um Escudo a um aliado, aumentando temporariamente a Velocidade de Movimento dele. Esta Habilidade tem 2 cargas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MilioE.png'),
('MilioQ', 80, 'Q', 'Ultramega Chute Flamejante', 'Milio chuta uma bola que empurra um inimigo. A bola é lançada para cima ao contato e cai na direção do alvo, causando dano e Lentidão aos inimigos que estiverem na área atingida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MilioQ.png'),
('MilioR', 80, 'R', 'Sopro de Vida', 'Milio libera uma onda de chamas reconfortantes que cura os aliados ao alcance, além de remover efeitos de controle de grupo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MilioR.png'),
('MilioW', 80, 'W', 'Fogueira Aconchegante', 'Cria uma zona fortalecida que cura aliados e aumenta o Alcance de Ataque de quem estiver dentro dela. A zona acompanha o aliado mais próximo do local de conjuração.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MilioW.png'),
('Milio_P', 80, 'P', 'A Todo Vapor!', 'As habilidades de Milio encantam aliados ao toque, fazendo com que o próximo ataque deles cause uma explosão de dano adicional e queime o alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Milio_P.png'),
('MissFortuneBulletTim', 81, 'R', 'Metendo Bala', 'Miss Fortune canaliza uma saraivada de balas em formato de cone à sua frente, causando muito dano aos inimigos. Cada remessa de Metendo Bala pode causar Acerto Crítico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MissFortuneBulletTime.png'),
('MissFortuneRicochetS', 81, 'Q', 'Dois por Um', 'Miss Fortune dispara contra um inimigo, causando dano a ele e a um alvo atrás dele. Ambos os acertos também podem aplicar Batida do Amor.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MissFortuneRicochetShot.png'),
('MissFortuneScattersh', 81, 'E', 'Chuva de Disparos', 'Miss Fortune revela uma área com uma saraivada de balas, causando ondas de dano e reduzindo a velocidade dos oponentes.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MissFortuneScattershot.png'),
('MissFortuneViciousSt', 81, 'W', 'Desfilando', 'Miss Fortune ganha Velocidade de Movimento passivamente quando não está sendo atacada. Esta habilidade pode ser ativada para conceder Velocidade de Ataque adicional por um curto período. Enquanto está em Tempo de Recarga, Batida do Amor reduz o Tempo de Recarga restante de Desfilando.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MissFortuneViciousStrikes.png'),
('MissFortune_P', 81, 'P', 'Batida do Amor', 'Miss Fortune causa Dano Físico adicional sempre que usar um ataque básico em um novo alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/MissFortune_W.png'),
('MissileBarrage', 23, 'R', 'Barragem de Mísseis', 'Corki dispara um míssil em direção ao local alvo, que explode com o impacto, causando dano aos inimigos na área. Corki armazena mísseis ao longo do tempo, com um limite máximo. O 3º míssil armazenado será um Grandão, que causa dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MissileBarrage.png'),
('MonkeyKingDecoy', 82, 'W', 'Guerreiro Trapaceiro', 'Wukong fica Invisível e avança em uma direção, deixando para trás um clone que atacará inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MonkeyKingDecoy.png'),
('MonkeyKingDoubleAtta', 82, 'Q', 'Golpe Destruidor', 'O próximo ataque de Wukong recebe Alcance de Ataque, causa dano adicional e reduz a Armadura do alvo por alguns segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MonkeyKingDoubleAttack.png'),
('MonkeyKingNimbus', 82, 'E', 'Resplendor das Nuvens', 'Wukong avança em direção ao inimigo-alvo e conjura imagens de si próprio para atacar inimigos próximos, causando dano aos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MonkeyKingNimbus.png'),
('MonkeyKingSpinToWin', 82, 'R', 'Ciclone', 'Wukong estende seu cajado e gira repetidamente, recebendo Velocidade de Movimento.Inimigos atingidos sofrem dano e são arremessados ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MonkeyKingSpinToWin.png'),
('MonkeyKing_P', 82, 'P', 'Pele de Pedra', 'Wukong recebe Armadura e Regeneração de Vida máxima cumulativas quando luta contra Campeões e monstros.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/MonkeyKingStoneSkin.png'),
('MordekaiserE', 83, 'E', 'Aperto Mortal', 'Mordekaiser puxa todos os inimigos em uma área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MordekaiserE.png'),
('MordekaiserQ', 83, 'Q', 'Obliterar', 'Mordekaiser golpeia o chão com sua maça, causando dano a cada inimigo atingido. O dano é aumentado quando atingir um único inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MordekaiserQ.png'),
('MordekaiserR', 83, 'R', 'Reino da Morte', 'Mordekaiser arrasta sua vítima com ele para uma dimensão diferente e rouba uma porção de seus atributos. Se abater sua vítima, ele mantém os atributos até que ela ressurja.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MordekaiserR.png'),
('MordekaiserW', 83, 'W', 'Indestrutível', 'Mordekaiser armazena o dano que ele causa e recebe para criar um escudo. Ele pode consumir o escudo para se curar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MordekaiserW.png'),
('Mordekaiser_P', 83, 'P', 'Ascensão das Trevas', 'Mordekaiser recebe uma poderosa aura de dano e Velocidade de Movimento depois de acertar 3 Ataques ou Habilidades contra Campeões inimigos ou monstros.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/MordekaiserPassive.png'),
('MorganaE', 84, 'E', 'Escudo Negro', 'Morgana abençoa um aliado com uma barreira protetora de fogo estelar que absorve Dano Mágico e efeitos de desarme até que quebre.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MorganaE.png'),
('MorganaQ', 84, 'Q', 'Ligação das Trevas', 'Morgana prende um inimigo no lugar com magia sombria, forçando-o a sentir a dor que provocou e causando Dano Mágico. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MorganaQ.png'),
('MorganaR', 84, 'R', 'Grilhões da Alma', 'Morgana libera a força total de seu poder celestial conforme desprende suas asas e flutua acima do chão. Ela lança correntes de dor sombria nos Campeões inimigos próximos, ganhando Velocidade de Movimento em direção a eles. As correntes causam redução de velocidade e um dano inicial e, depois de um intervalo, atordoarão aqueles que não conseguirem quebrá-las.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MorganaR.png'),
('MorganaW', 84, 'W', 'Sombra Atormentada', 'Morgana conjura uma sombra amaldiçoada em uma área, causando dano aos inimigos que ousarem permanecer em seu círculo sombrio. Eles sofrem Dano Mágico ao longo do tempo, que aumenta quanto mais suas Vidas estiverem baixas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MorganaW.png'),
('Morgana_P', 84, 'P', 'Sifão da Alma', 'Morgana drena o espírito dos inimigos, curando-se conforme causa dano a Campeões, tropas grandes e monstros médios e grandes da selva.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/FallenAngel_Empathize.png'),
('MoveQuick', 134, 'W', 'Mover Depressa', 'Teemo corre por aí, aumentando passivamente sua Velocidade de Movimento até que seja atingido por um Campeão ou torre inimiga. Ele pode sair em disparada para receber Velocidade de Movimento adicional que não é interrompida por ataques por um certo período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/MoveQuick.png'),
('NaafiriE', 85, 'E', 'Eviscerar', 'Naafiri avança e causa dano a inimigos em uma área ao seu redor, evocando e curando totalmente sua matilha.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NaafiriE.png'),
('NaafiriQ', 85, 'Q', 'Adagas Darkin', 'Naafiri arremessa até duas adagas; cada uma causa dano de sangramento ou, caso o alvo já esteja sangrando, dano adicional.A matilha avança para atacar Campeões atingidos pela Habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NaafiriQ.png'),
('NaafiriR', 85, 'R', 'Chamado da Matilha', 'Naafiri fortalece a matilha e faz surgir Companheiros adicionais, recebendo instantaneamente um impulso de velocidade e visão, além de um Escudo ao atacar um Campeão pela primeira vez.Depois de abater outro Campeão pela primeira vez, todos os efeitos são redefinidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NaafiriR.png'),
('NaafiriW', 85, 'W', 'Caça dos Cães', 'Naafiri e sua matilha avançam contra um inimigo, colidindo com o primeiro Campeão atingido e causando dano a ele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NaafiriW.png'),
('Naafiri_P', 85, 'P', 'Em Maior Número', 'Uma matilha surge e ataca os alvos dos ataques e habilidades de Naafiri.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Icons_Naafiri_P.png'),
('NamiE', 86, 'E', 'Bênção da Conjuradora', 'Fortalece um Campeão aliado por uma curta duração. Os ataques básicos e habilidades do aliado causam Dano Mágico adicional e reduzem a velocidade do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NamiE.png'),
('NamiQ', 86, 'Q', 'Prisão Aquática', 'Lança uma bolha na área-alvo, causando dano e atordoando todos os inimigos ao impacto.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NamiQ.png'),
('NamiR', 86, 'R', 'Maré Violenta', 'Invoca uma grande Maré Violenta que arremessa ao ar, reduz a velocidade e causa dano aos inimigos atingidos. Aliados atingidos recebem o efeito dobrado de Maré Oscilante.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NamiR.png'),
('NamiW', 86, 'W', 'Vazante e Fluxo', 'Desfere um jato de água que salta entre Campeões aliados e inimigos, curando os aliados e causando dano aos inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NamiW.png'),
('Nami_P', 86, 'P', 'Maré Oscilante', 'Quando as Habilidades de Nami atingem Campeões aliados, eles recebem Velocidade de Movimento por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/NamiPassive.png'),
('NasusE', 87, 'E', 'Fogo Espiritual', 'Nasus libera uma chama espiritual em um local, causando dano e reduzindo a Armadura dos inimigos que pisarem nela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NasusE.png'),
('NasusQ', 87, 'Q', 'Ataque Sifão', 'Nasus ataca seu inimigo, causando dano e aumentando o poder do próximo Ataque Sifão se o alvo for abatido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NasusQ.png'),
('NasusR', 87, 'R', 'Fúria das Areias', 'Nasus libera uma poderosa tempestade de areia que atinge inimigos próximos. Enquanto a tempestade estiver ativa, ele recebe Vida e Alcance de Ataque adicionais, causa dano a inimigos próximos, reduz o Tempo de Recarga de Ataque Sifão e recebe Armadura e Resistência Mágica adicionais.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NasusR.png'),
('NasusW', 87, 'W', 'Murchar', 'Nasus envelhece um Campeão inimigo, reduzindo a Velocidade de Movimento e de Ataque do alvo ao longo do tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NasusW.png'),
('Nasus_P', 87, 'P', 'Devorador de Almas', 'Nasus drena a energia espiritual de seu inimigo, acumulando Roubo de Vida adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Nasus_Passive.png'),
('NautilusAnchorDrag', 88, 'Q', 'Lançar Âncora', 'Nautilus arremessa sua âncora à frente.  Se acertar um inimigo, ele puxa a si mesmo e ao alvo para perto um do outro, causando Dano Mágico.  Se acertar um terreno, Nautilus avança em direção a ele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NautilusAnchorDrag.png'),
('NautilusGrandLine', 88, 'R', 'Carga de Profundidade', 'Nautilus lança uma onda de choque na terra que persegue o oponente. Essa onda rasga a terra em cima dela, arremessando os inimigos ao ar. Quando ela alcança o oponente, a onda de choque explode, arremessando o alvo ao ar e atordoando ele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NautilusGrandLine.png'),
('NautilusPiercingGaze', 88, 'W', 'Ira do Titã', 'Nautilus recebe um Escudo temporário.  Enquanto o Escudo persistir, seus Ataques causam dano ao longo do tempo ao alvo e a inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NautilusPiercingGaze.png'),
('NautilusSplashZone', 88, 'E', 'Correnteza', 'Nautilus cria três ondas explosivas ao redor de si. Cada explosão causa dano e Lentidão aos inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NautilusSplashZone.png'),
('Nautilus_P', 88, 'P', 'Âncora Impactante', 'O primeiro Ataque de Nautilus a um alvo causa Dano Físico aumentado e Enraíza-o brevemente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Nautilus_StaggeringBlow.png'),
('NeekoE', 89, 'E', 'Farpas Emaranhadas', 'Neeko arremessa um emaranhado que causa dano e enraíza tudo o que atravessa. Se o emaranhado abater um inimigo ou atravessar um Campeão, ele aumentará de tamanho, terá mais velocidade e enraizará por mais tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NeekoE.png'),
('NeekoQ', 89, 'Q', 'Explosão Florescente', 'Neeko arremessa uma semente, causando Dano Mágico. A semente floresce novamente ao atingir Campeões ou abater unidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NeekoQ.png'),
('NeekoR', 89, 'R', 'Florescer Repentino', 'Após uma curta preparação, Neeko salta no ar. Ao aterrissar, inimigos próximos sofrem dano e são arremessados ao ar. A preparação fica oculta se Neeko estiver disfarçada.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NeekoR.png'),
('NeekoW', 89, 'W', 'Metamorfa', 'Neeko passivamente causa Dano Mágico adicional a cada terceiro ataque e pode ativar a habilidade para enviar um clone em uma direção.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NeekoW.png'),
('Neeko_P', 89, 'P', 'Encanto Inerente', 'Neeko pode se parecer com um Campeão aliado. Sofrer dano de Campeões inimigos ou conjurar habilidades de dano quebram o disfarce.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Neeko_P.png'),
('NetherBlade', 58, 'W', 'Lâmina Ínfera', 'Passivo: Os ataques básicos de Kassadin causam Dano Mágico adicional. Ativo: O próximo ataque básico de Kassadin causa Dano Mágico adicional significativo e restaura Mana.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NetherBlade.png'),
('Nidalee_P', 90, 'P', 'Espreitar', 'Mover-se pelos arbustos aumenta a Velocidade de Movimento de Nidalee em 10% por 2 segundos, aumentando para 30% em direção a campeões inimigos visíveis dentre 1400 de alcance.Atingir Campeões ou monstros com Arremessar Lança ou Arapuca aciona uma Caçada, que concede Visão Mágica deles por 4 segundos. Durante esse tempo, Nidalee recebe 10% de Velocidade de Movimento (aumentando para 30% em direção ao alvo Caçado) e o uso de Bote ou Investida contra o alvo é aprimorado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Nidalee_Passive.png'),
('NilahE', 91, 'E', 'Turbilhão', 'Nilah avança com muito entusiasmo em direção ao alvo, causando dano a todos os inimigos que atravessar no caminho.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NilahE.png'),
('NilahQ', 91, 'Q', 'Lâmina Sem Forma', 'Com um estalo de sua lâmina-chicote, Nilah causa dano a qualquer inimigo que acertar em linha reta na direção escolhida. A habilidade também aumenta seu Alcance de Ataque por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NilahQ.png'),
('NilahR', 91, 'R', 'Apoteose', 'Girando sua lâmina-chicote com alegre exuberância, Nilah causa dano aos inimigos ao redor antes de puxá-los para perto com a arma.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NilahR.png'),
('NilahW', 91, 'W', 'Véu Jubiloso', 'Nilah se envolve em névoa, aumentando sua Velocidade de Movimento e esquivando-se graciosamente de todos os ataques. Todos os aliados que ela tocar durante a duração da névoa também receberão esse efeito.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NilahW.png'),
('Nilah_P', 91, 'P', 'Alegria Eterna', 'Nilah recebe mais experiência ao abater tropas, além de aprimorar e compartilhar curas e Escudos conjurados por aliados próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/NIlahP.png'),
('NocturneDuskbringer', 92, 'Q', 'Portador do Anoitecer', 'Nocturne lança uma lâmina de sombras que causa dano, deixa um Rastro do Crepúsculo e faz com que os Campeões deixem um Rastro do Crepúsculo. Enquanto estiver no rastro, Nocturne ignora colisões com unidades e ganha aumento de Velocidade de Movimento e de Dano de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NocturneDuskbringer.png'),
('NocturneParanoia', 92, 'R', 'Paranoia', 'Nocturne reduz o raio de visão de todos os Campeões inimigos e ainda remove a visão que eles têm dos aliados. Depois ele pode se arremessar contra um Campeão inimigo que estiver próximo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NocturneParanoia.png'),
('NocturneShroudofDark', 92, 'W', 'Proteção das Trevas', 'Nocturne fortalece suas lâminas, ganhando Velocidade de Ataque passivamente. Ativar Proteção das Trevas permite que Nocturne desapareça em meio às sombras, criando uma barreira mágica que bloqueia uma única habilidade inimiga e dobra a Velocidade de Ataque passiva dele caso bem-sucedida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NocturneShroudofDarkness.png'),
('NocturneUnspeakableH', 92, 'E', 'Horror Indescritível', 'Nocturne coloca um pesadelo na mente de seu alvo, causando dano a cada segundo e aterrorizando-o caso ele não saia de seu alcance enquanto durar a habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NocturneUnspeakableHorror.png'),
('Nocturne_P', 92, 'P', 'Lâminas Sombrias', 'A cada poucos segundos, o próximo ataque de Nocturne atinge os inimigos ao seu redor para causar Dano Físico adicional e curá-lo. Os ataques básicos de Nocturne reduzem esse Tempo de Recarga.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Nocturne_UmbraBlades.png'),
('NullLance', 58, 'Q', 'Esfera Nula', 'Kassadin dispara um orbe de energia do Vazio em um alvo, causando dano e interrompendo canalizações. A energia excedente toma forma ao seu redor, concedendo um escudo temporário que absorve Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NullLance.png'),
('NunuE', 93, 'E', 'Rajada de Bolas de Neve', 'Nunu arremessa múltiplas bolas de neve que causam dano a inimigos. Ao terminar, Willump enraíza quaisquer Campeões ou monstros grandes que foram atingidos por uma delas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NunuE.png'),
('NunuQ', 93, 'Q', 'Consumir', 'Willump dá uma mordida em uma tropa, monstro ou Campeão inimigo, causando dano e se curando.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NunuQ.png'),
('NunuR', 93, 'R', 'Zero Absoluto', 'Nunu e Willump criam uma poderosa nevasca em uma área, causando lentidão aos inimigos e um dano massivo quando se encerrar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NunuR.png'),
('NunuW', 93, 'W', 'A Maior Bola de Neve de Todas!', 'Willump cria uma bola de neve que aumenta em velocidade e tamanho conforme ele a rola. Ela causa dano a inimigos e os arremessa ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/NunuW.png'),
('Nunu_P', 93, 'P', 'Chamado de Freljord', 'Nunu aumenta as Velocidades de Ataque e de Movimento de Willump e de um aliado próximo, além de fazer com que os ataques básicos de Willump causem dano a inimigos ao redor do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/NunuPassive.png'),
('Obduracy', 76, 'W', 'Trovoada', 'Malphite ataca com tamanha força que cria uma onda sônica. Pelos próximos segundos, seus ataques criam ondas de choque em sua frente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Obduracy.png'),
('OlafAxeThrowCast', 94, 'Q', 'Ressaca', 'Olaf arremessa um machado no local-alvo, causando dano e reduzindo a Armadura e a Velocidade de Movimento dos inimigos que atravessar. Se Olaf apanhar o machado, o Tempo de Recarga da habilidade é redefinido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OlafAxeThrowCast.png'),
('OlafFrenziedStrikes', 94, 'W', 'Duro na Queda', 'Olaf recebe aumento de Velocidade de Ataque, reduzindo todo o dano recebido e ganhando um Escudo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OlafFrenziedStrikes.png'),
('OlafRagnarok', 94, 'R', 'Ragnarok', 'Olaf recebe Armadura e Resistência Mágica adicionais passivamente. Ele pode ativar essa habilidade para se tornar imune a desarmes enquanto continuar atacando.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OlafRagnarok.png'),
('OlafRecklessStrike', 94, 'E', 'Balanço Temerário', 'Olaf ataca com tal força que causa Dano Verdadeiro a seu alvo e a si mesmo, recuperando o custo de Vida caso destrua o alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OlafRecklessStrike.png'),
('Olaf_P', 94, 'P', 'Fúria Berserker', 'Olaf recebe Velocidade de Ataque e Roubo de Vida com base na sua Vida perdida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Olaf_Passive.png'),
('OrianaDetonateComman', 95, 'R', 'Comando: Onda de Choque', 'Orianna comanda sua Esfera para desferir uma onda de choque, causando Dano Mágico e deslocando inimigos próximos em direção à Esfera após um curto intervalo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OrianaDetonateCommand.png'),
('OrianaDissonanceComm', 95, 'W', 'Comando: Dissonância', 'Orianna comanda que sua Esfera desfira um pulso de energia, causando Dano Mágico ao seu redor. Isso deixa para trás um campo que aumenta a Velocidade de Movimento de aliados e causa Lentidão aos inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OrianaDissonanceCommand.png'),
('OrianaIzunaCommand', 95, 'Q', 'Comando: Atacar', 'Orianna comanda sua Esfera para avançar no local-alvo, causando Dano Mágico ao longo do caminho (causa menos dano a alvos subsequentes). A Esfera permanece no mesmo lugar após o comando.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OrianaIzunaCommand.png'),
('OrianaRedactCommand', 95, 'E', 'Comando: Proteger', 'Orianna comanda que sua Esfera se prenda a um Campeão aliado, concedendo a ele um Escudo e causando Dano Mágico a qualquer inimigo que ela atravessar em seu trajeto. Além disso, a Esfera concede Armadura e Resistência Mágica adicionais ao Campeão ao qual estiver presa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OrianaRedactCommand.png'),
('Orianna_P', 95, 'P', 'Dando Corda', 'Os Ataques de Orianna causam Dano Mágico adicional. O dano aumenta a cada vez que ela Ataca o mesmo alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/OriannaPassive.png'),
('OrnnE', 96, 'E', 'Investida Calcinante', 'Ornn se lança em investida, causando dano aos inimigos sobre os quais passar. Se Ornn colidir com o terreno enquanto estiver em investida, o impacto criará uma onda de choque que causará dano e arremessará os inimigos ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OrnnE.png'),
('OrnnQ', 96, 'Q', 'Ruptura Vulcânica', 'Ornn bate no chão, dispersando uma fissura que causa dano e reduz a velocidade dos inimigos atingidos. Após um breve intervalo, um pilar de magma se forma no ponto final.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OrnnQ.png'),
('OrnnR', 96, 'R', 'Chamado do Deus da Forja', 'Ornn invoca um elemental gigante em um ponto, que viaja até ele cada vez mais rápido. Inimigos atropelados pelo elemental sofrem dano, têm a velocidade reduzida e ficam Frágeis. Ornn pode reconjurar a habilidade para dar uma investida no elemental para redirecioná-lo na direção em que ele o acertar, fazendo com que o elemental arremesse ao ar todos os inimigos que ele atingir, causando o mesmo dano e reaplicando Frágil.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OrnnR.png'),
('OrnnW', 96, 'W', 'Fôlego do Fole', 'Ornn avança cuspindo fogo. Inimigos atingidos pelo último sopro de fogo tornam-se Frágeis.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/OrnnW.png'),
('Ornn_P', 96, 'P', 'Forja Viva', 'Ornn recebe Armadura e Resistência Mágica adicionais de todas as origens.Ele pode gastar ouro para forjar itens não consumíveis em qualquer lugar.Além disso, ele pode criar itens magistrais para si mesmo e para seus aliados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/OrnnP.png'),
('Overdrive', 15, 'W', 'Turbo', 'Blitzcrank sobrecarrega-se para aumentar drasticamente suas Velocidades de Ataque e de Movimento. Após o fim do efeito, sofre Lentidão temporariamente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Overdrive.png'),
('PantheonE', 97, 'E', 'Égide Impetuosa', 'Pantheon posiciona seu escudo, ficando invulnerável a dano vindo de sua frente e atacando rapidamente com sua lança.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PantheonE.png'),
('PantheonQ', 97, 'Q', 'Lança Meteórica', 'Pantheon pode fazer uma investida com sua lança ou arremessá-la na direção escolhida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PantheonQ.png'),
('PantheonR', 97, 'R', 'Constelação Cadente', 'Pantheon se prepara, salta para o ar e aterrissa como um cometa no local escolhido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PantheonR.png'),
('PantheonW', 97, 'W', 'Escudo-Cometa', 'Pantheon avança em um alvo, causando dano e atordoando-o.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PantheonW.png'),
('Pantheon_P', 97, 'P', 'Determinação Mortal', 'Após algumas habilidades ou ataques, a próxima habilidade de Pantheon será fortalecida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Pantheon_Passive.png'),
('PhosphorusBomb', 23, 'Q', 'Bomba de Fósforo', 'Corki dispara uma bomba luminosa em um local alvo, causando Dano Mágico a inimigos na área. Este ataque também revela unidades na área por uma curta duração.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PhosphorusBomb.png'),
('PickACard', 139, 'W', 'Escolha uma Carta', 'Twisted Fate escolhe uma carta mágica de seu baralho e a usa em seu próximo ataque, causando efeitos adicionais.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PickACard.png'),
('PoisonTrail', 120, 'Q', 'Rastro de Veneno', 'Deixa um rastro de veneno atrás de Singed, causando dano aos inimigos que passam por este caminho.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PoisonTrail.png'),
('PoppyE', 98, 'E', 'Investida Heroica', 'Poppy avança até o alvo e o empurra para trás. Se o alvo colidir com uma parede, ele será atordoado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PoppyE.png'),
('PoppyQ', 98, 'Q', 'Choque do Martelo', 'Poppy golpeia com o martelo, causando dano e criando uma área que reduz a velocidade de inimigos e explode após um intervalo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PoppyQ.png'),
('PoppyR', 98, 'R', 'Veredito da Guardiã', 'Poppy canaliza um golpe com o martelo que empurra inimigos para muito longe.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PoppyR.png'),
('PoppyW', 98, 'W', 'Presença Inabalável', 'Poppy recebe Armadura e Resistência Mágica passivamente, que aumentam quando ela estiver com Vida baixa. Ela pode ativar Presença Inabalável para receber Velocidade de Movimento e impedir avanços inimigos ao seu redor, fazendo com que o inimigo impedido sofra redução de velocidade e fique preso ao chão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PoppyW.png'),
('Poppy_P', 98, 'P', 'Embaixadora de Ferro', 'Poppy arremessa seu broquel, que bate no alvo e cai no chão. Ela pode apanhá-lo para receber um escudo temporário.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Poppy_Passive.png'),
('PowerBall', 103, 'Q', 'Bola do Poder', 'Rammus acelera em forma de bola na direção de seus inimigos, causando dano e lentidão nos alvos afetados pelo impacto.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PowerBall.png'),
('PowerFist', 15, 'E', 'Punho do Poder', 'Blitzcrank carrega seu punho para fazer com que o próximo Ataque cause o dobro de dano e arremesse o alvo ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PowerFist.png'),
('PrimalSurge', 90, 'E', 'Ímpeto Selvagem / Patada', 'Na forma humana, Nidalee canaliza o espírito do puma para curar seus aliados e lhes concede Velocidade de Ataque por um curto período de tempo. Em forma de puma, ela golpeia em uma direção, causando dano aos inimigos à sua frente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PrimalSurge.png'),
('Pulverize', 5, 'Q', 'Pulverizar', 'Alistar golpeia o chão, causando dano a inimigos próximos e arremessando-os ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Pulverize.png'),
('PuncturingTaunt', 103, 'E', 'Provocação Enlouquecedora', 'Rammus provoca um Campeão inimigo ou monstro para um ataque imprudente contra si mesmo. Além disto, ele recebe Velocidade de Ataque adicional por um curto período, embora este efeito seja estendido ao ter qualquer outra habilidade ativa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PuncturingTaunt.png');
INSERT INTO `habilidades` (`ID_habilidade`, `ID_campeao`, `tecla`, `nome_habilidade`, `descricao`, `imagem_url`) VALUES
('PykeE', 99, 'E', 'Ressaca Espectral', 'Pyke avança e deixa para trás um fantasma, que avança até ele e atordoa os Campeões inimigos pelo caminho.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PykeE.png'),
('PykeQ', 99, 'Q', 'Espeto de Osso', 'Pyke esfaqueia um inimigo à sua frente ou puxa um inimigo em direção a si mesmo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PykeQ.png'),
('PykeR', 99, 'R', 'Morte das Profundezas', 'Pyke teleporta até inimigos com Vida baixa e os executa, permitindo que ele conjure a habilidade novamente e concedendo ouro adicional ao aliado que der assistência.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PykeR.png'),
('PykeW', 99, 'W', 'Mergulho Fantasma', 'Pyke entra em camuflagem e ganha Velocidade de Movimento significativa que decai ao longo do tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/PykeW.png'),
('Pyke_P', 99, 'P', 'Dádiva dos Afogados', 'Quando Pyke está escondido dos inimigos, ele regenera o dano recebido recentemente de Campeões. Pyke também não ganha Vida máxima adicional de nenhuma fonte, mas ganha DdA adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/PykePassive.png'),
('QiyanaE', 100, 'E', 'Audácia', 'Qiyana avança em um inimigo e causa dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/QiyanaE.png'),
('QiyanaQ', 100, 'Q', 'Cólera Elemental / Lâmina de Ixtal', 'Qiyana brande sua arma, causando dano com um efeito adicional baseado no seu elemento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/QiyanaQ.png'),
('QiyanaR', 100, 'R', 'Suprema Demonstração de Talento', 'Qiyana lança uma onda de choque que detona quaisquer elementos que ela acertar, atordoando e causando dano a inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/QiyanaR.png'),
('QiyanaW', 100, 'W', 'Terraforme', 'Qiyana avança para um local e encanta sua arma com um elemento. Ataques e habilidades causam dano adicional enquanto sua arma estiver encantada. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/QiyanaW.png'),
('Qiyana_P', 100, 'P', 'Privilégio da Realeza', 'O primeiro ataque básico ou habilidade de Qiyana contra cada inimigo causa dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Qiyana_Passive.png'),
('QuinnE', 101, 'E', 'Salto', 'Quinn avança em direção a um inimigo, causando Dano Físico e reduzindo a Velocidade de Movimento do alvo. Ao alcançar seu alvo, ela salta dele, interrompendo-o brevemente, e aterrissa a uma distância próxima de seu alcance máximo de ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/QuinnE.png'),
('QuinnQ', 101, 'Q', 'Investida Anuviante', 'Quinn chama Valor para marcar um inimigo e prejudicar sua visão antes de causar dano a todos os inimigos na área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/QuinnQ.png'),
('QuinnR', 101, 'R', 'Retaguarda do Inimigo', 'Quinn e Valor se juntam para voar em alta velocidade. Encerrar a habilidade conjura Bombardeio, que causa dano a inimigos próximos e marca Campeões como Vulnerável.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/QuinnR.png'),
('QuinnW', 101, 'W', 'Sentidos Apurados', 'Passivamente concede Velocidade de Ataque e de Movimento a Quinn após ela atacar um alvo Vulnerável. Ative para fazer com que Valor revele uma grande área próxima.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/QuinnW.png'),
('Quinn_P', 101, 'P', 'Rapina', 'Valor, a águia demaciana de Quinn, periodicamente marca inimigos como Vulneráveis. O primeiro ataque básico de Quinn contra alvos Vulneráveis causará Dano Físico adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Quinn_Passive.png'),
('RakanE', 102, 'E', 'Dança da Batalha', 'Voa até um aliado e concede um escudo a ele. Pode ser conjurada novamente sem custo por um breve período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RakanE.png'),
('RakanQ', 102, 'Q', 'Pena Reluzente', 'Lança uma pluma mágica que causa Dano Mágico. Ao atingir um Campeão ou um monstro épico, Rakan pode curar seus aliados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RakanQ.png'),
('RakanR', 102, 'R', 'Rapidez', 'Recebe Velocidade de Movimento, encantando e causando Dano Mágico ao tocar nos inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RakanR.png'),
('RakanW', 102, 'W', 'Entrada Triunfal', 'Avança para um local e, ao chegar, arremessa os inimigos próximos ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RakanW.png'),
('Rakan_P', 102, 'P', 'Plumas Mágicas', 'Rakan recebe um escudo periodicamente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Rakan_P.png'),
('Rammus_P', 103, 'P', 'Casco Espetado', 'Os ataques básicos de Rammus causam Dano Mágico adicional, escalando com sua Armadura.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Armordillo_ScavengeArmor.png'),
('ReapTheWhirlwind', 48, 'R', 'Monção', 'Janna se cerca de uma tempestade mágica, empurrando inimigos para trás. Assim que a tempestade se estabelece, ventos suaves curam os aliados próximos enquanto a habilidade estiver ativa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ReapTheWhirlwind.png'),
('RekSaiE', 104, 'E', 'Mordida Feroz / Túnel', 'Rek\'Sai morde seu alvo, causando Dano Verdadeiro dobrado se tiver o máximo de Fúria.Enquanto escavada, Rek\'Sai cria um Túnel longo, duradouro e reutilizável. Inimigos podem destruí-lo ficando sobre uma das entradas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RekSaiE.png'),
('RekSaiQ', 104, 'Q', 'Ira da Rainha / Sondar Presas', 'Os próximos 3 ataques básicos de Rek\'Sai causam Dano Físico adicional a inimigos próximos.Enquanto está enterrada, Rek\'Sai lança uma rajada de terra carregada com o poder do Vazio que causa Dano Físico e revela os inimigos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RekSaiQ.png'),
('RekSaiRWrapper', 104, 'R', 'Investida do Vazio', 'Rek\'Sai marca seus alvos passivamente ao causar dano. Ela pode ativar essa habilidade para se tornar brevemente inalvejável e saltar até o alvo marcado, causando dano pesado com base na Vida perdida dele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RekSaiRWrapper.png'),
('RekSaiW', 104, 'W', 'Escavar / Emergir', 'Rek\'Sai se enterra no chão, recebendo novas habilidades e Velocidade de Movimento aumentada. O alcance de sua visão é reduzido e ela não pode usar ataques básicos.Enquanto enterrada, Rek\'Sai pode conjurar Emergir para causar dano e arremessar ao ar os inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RekSaiW.png'),
('RekSai_P', 104, 'P', 'Fúria dos Xer\'Sai', 'Rek\'Sai gera Fúria ao Atacar e atingir inimigos com habilidades básicas. Enquanto estiver Escavada, ela consome a Fúria para restaurar Vida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/RekSai_Passive.png'),
('RellE', 105, 'E', 'Investida Absoluta', 'Passivo: Rell recebe Velocidade de Movimento fora de combate.Ativo: Rell e um aliado recebem Velocidade de Movimento crescente, dobrada em direção aos inimigos e entre si. O próximo Ataque dela explode, causando Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RellE.png'),
('RellQ', 105, 'Q', 'Golpe Estilhaçador', 'Rell causa Dano Mágico às unidades em linha reta, destruindo o Escudo delas e atordoando-as. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RellQ.png'),
('RellR', 105, 'R', 'Tempestade Magnética', 'Rell explode em uma fúria magnética, Puxando violentamente os inimigos próximos em sua direção. Ela, então, Arrasta esses inimigos em direção a si por um curto período, causando Dano Mágico ao longo do tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RellR.png'),
('RellW_Dismount', 105, 'W', 'Ferromante: Queda Esmagadora', 'Montaria: Rell Desmonta, caindo com a armadura sobre os inimigos, Arremessando-os ao ar e recebendo um grande Escudo. Sem montaria, ela recebe Armadura, Resistência Mágica, Velocidade de Ataque e Alcance de Ataque, mas sofre Lentidão.Desmontada: Rell forja a Montaria, recebendo um impulso de velocidade e Arremessando ao ar o próximo inimigo que Atacar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RellW_Dismount.png'),
('Rell_P', 105, 'P', 'A Ferro e Fogo', 'Os Ataques e Habilidades de Rell roubam Armadura e Resistência Mágica ao contato.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/RellP.png'),
('RenataE', 106, 'E', 'Programa de Fidelidade', 'Renata envia um par de foguetes quimtec, concedendo Escudo aos aliados e causando dano e Lentidão aos inimigos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RenataE.png'),
('RenataQ', 106, 'Q', 'Negócio Fechado', 'Renata envia um foguete que enraíza o primeiro inimigo atingido. Ela pode reconjurar a habilidade para arremessar a unidade em uma direção.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RenataQ.png'),
('RenataR', 106, 'R', 'Apropriação Agressiva', 'Renata envia uma onda de produtos químicos, fazendo com que inimigos atingidos entrem em estado de Berserk.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RenataR.png'),
('RenataW', 106, 'W', 'Empréstimo', 'Renata fortalece um Campeão aliado para lutar, atrasando a morte dele e salvando-o se ele conseguir uma eliminação.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RenataW.png'),
('Renata_P', 106, 'P', 'Financiamento', 'Os Ataques de Renata causam dano adicional e marcam inimigos. Os aliados de Renata podem atacar inimigos marcados para causar dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Renata_P.png'),
('RenektonCleave', 107, 'Q', 'Abater os Indefesos', 'Renekton brande sua lâmina, causando Dano Físico moderado em todos os alvos ao seu redor e curando-o em uma pequena quantia do dano causado. Caso tenha mais que 50 pontos de Fúria, seu dano e cura aumentam.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RenektonCleave.png'),
('RenektonPreExecute', 107, 'W', 'Predador Desumano', 'Renekton corta seu alvo duas vezes, causado Dano Físico moderado e atordoamento por 0,75s. Se Renekton tiver mais de 50 de Fúria, ele corta o inimigo três vezes, destruindo escudos de dano no alvo, causando Dano Físico alto e atordoando por 1,5s.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RenektonPreExecute.png'),
('RenektonReignOfTheTy', 107, 'R', 'Dominus', 'Renekton transforma-se em sua forma Tirana, recebendo Vida adicional e causando dano a inimigos ao seu redor. Enquanto estiver nessa forma, ele recebe Fúria periodicamente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RenektonReignOfTheTyrant.png'),
('RenektonSliceAndDice', 107, 'E', 'Fatiar e Picar', 'Renekton avança, causando dano a unidades em seu caminho. Fortalecido, Renekton causa dano adicional e reduz a Armadura das unidades atingidas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RenektonSliceAndDice.png'),
('Renekton_P', 107, 'P', 'Domínio da Ira', 'Os ataques de Renekton geram Fúria, que aumenta quando ele estiver com a Vida baixa. Essa Fúria pode fortalecer suas habilidades com efeitos adicionais.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Renekton_Passive.png'),
('RengarE', 108, 'E', 'Boleadeiras', 'Rengar arremessa sua boleadeira, reduzindo a velocidade do primeiro alvo atingido por um curto período.Efeito de Ferocidade: enraíza o alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RengarE.png'),
('RengarQ', 108, 'Q', 'Selvageria', 'O próximo ataque de Rengar desfere uma punhalada brutal que causa dano adicional.Efeito de Ferocidade: causa dano aumentado e concede Velocidade de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RengarQ.png'),
('RengarR', 108, 'R', 'Furor da Caçada', 'Rengar ativa seus instintos predatórios, ficando Camuflado e revelando o campeão inimigo mais próximo a ele em um amplo raio ao seu redor. Durante o Furor da Caçada, Rengar recebe Velocidade de Movimento e pode saltar no inimigo perseguido para reduzir sua armadura, mesmo sem estar no arbusto.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RengarR.png'),
('RengarW', 108, 'W', 'Rugido de Batalha', 'Rengar solta um rugido de batalha, causando dano aos inimigos e curando parte do dano que ele tenha recebido recentemente.Efeito de Ferocidade: quebra efeitos de Controle de Grupo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RengarW.png'),
('Rengar_P', 108, 'P', 'Predador Oculto', 'Enquanto estiver em um arbusto, Rengar salta até seu alvo ao usar um ataque básico.Rengar gera Ferocidade sempre que conjura uma habilidade. Ao atingir Ferocidade máxima, sua próxima Habilidade é fortalecida.Abater Campeões inimigos acrescenta troféus ao Colar de Presas de Rengar, concedendo Dano de Ataque adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Rengar_P.png'),
('RiftWalk', 58, 'R', 'Caminhar na Fenda', 'Kassadin se teleporta para um local próximo, causando dano a unidades inimigas próximas. Múltiplas conjurações de Caminhar na Fenda em um curto período custam Mana adicional e também causam dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RiftWalk.png'),
('RivenFeint', 109, 'E', 'Valentia', 'Riven avança uma curta distância e bloqueia o dano recebido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RivenFeint.png'),
('RivenFengShuiEngine', 109, 'R', 'Lâmina do Exílio', 'Riven fortalece sua arma de recordação com energia, recebendo Dano de Ataque e alcance. Durante este período, ela também pode usar Golpe de Vento, um poderoso ataque à distância, uma vez.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RivenFengShuiEngine.png'),
('RivenMartyr', 109, 'W', 'Explosão de Ki', 'Riven emite uma Explosão de Ki, causando dano e atordoamento a inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RivenMartyr.png'),
('RivenTriCleave', 109, 'Q', 'Asas Quebradas', 'Riven faz uma série rápida de acertos. Esta habilidade pode ser reativada três vezes em um curto período de tempo. O terceiro golpe empurra para trás os inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RivenTriCleave.png'),
('Riven_P', 109, 'P', 'Lâmina Rúnica', 'As habilidades de Riven carregam sua lâmina, e seus ataques básicos consomem cargas para causar dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/RivenRunicBlades.png'),
('RocketGrab', 15, 'Q', 'Puxão Biônico', 'Blitzcrank dispara a mão direita para pegar um inimigo no trajeto, causando dano e puxando-o em sua direção.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RocketGrab.png'),
('RumbleCarpetBomb', 110, 'R', 'O Equalizador', 'Rumble dispara um grupo de mísseis, criando uma parede de fogo que causa dano e Lentidão a inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RumbleCarpetBomb.png'),
('RumbleFlameThrower', 110, 'Q', 'Cospe-Fogo', 'Rumble incinera os inimigos à sua frente, causando Dano Mágico em área de cone por 3 segundos. O dano aumenta enquanto ele estiver na Zona de Perigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RumbleFlameThrower.png'),
('RumbleGrenade', 110, 'E', 'Arpão Elétrico', 'Rumble lança um arpão, eletrocutando o alvo com Dano Mágico, causando Lentidão e reduzindo a Resistência Mágica dele. Ele pode carregar 2 arpões por vez. O dano e o percentual de Lentidão aumentarão dentro da Zona de Perigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RumbleGrenade.png'),
('RumbleShield', 110, 'W', 'Escudo de Sucata', 'Rumble puxa um escudo que o protege de dano e lhe concede um rápido aumento de velocidade. Enquanto estiver na Zona de Perigo, a resistência do escudo e a velocidade adicional aumentam.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RumbleShield.png'),
('Rumble_P', 110, 'P', 'Titã do Ferro-Velho', 'Cada habilidade que Rumble conjura lhe concede Aquecimento. Ao chegar em 50% de Aquecimento, ele entra na Zona de Perigo, concedendo efeitos adicionais a todas as suas habilidades. Ao chegar a 100% de Aquecimento, ele começa a superaquecer, recebendo Velocidade de Ataque adicional e dano adicional em seus ataques básicos, mas fica incapaz de conjurar habilidades por alguns segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Rumble_JunkyardTitan1.png'),
('Rupture', 22, 'Q', 'Ruptura', 'Rompe o chão num local-alvo, lançando unidades inimigas ao ar e causando dano e redução de velocidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Rupture.png'),
('RyzeE', 111, 'E', 'Fluxo de Feitiço', 'Ryze lança um orbe de puro poder mágico que causa dano a um inimigo e um efeito negativo em todos os inimigos próximos. As habilidades de Ryze têm efeitos adicionais contra a unidade afetada.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RyzeE.png'),
('RyzeQWrapper', 111, 'Q', 'Sobrecarregar', 'Passivamente, as outras habilidades básicas de Ryze redefinem o Tempo de Recarga de Sobrecarregar e carregam uma runa. Quando Ryze conjura Sobrecarregar com 2 runas carregadas, ele recebe um breve surto de Velocidade de Movimento.Ao conjurar, Ryze arremessa uma carga de energia pura em linha reta, causando dano ao primeiro inimigo atingido. Se o alvo estiver afetado por Fluxo, Sobrecarregar causa dano adicional e rebate para inimigos próximos atingidos por Fluxo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RyzeQWrapper.png'),
('RyzeR', 111, 'R', 'Portal de Reinos', 'Passivamente, Sobrecarregar causa ainda mais dano contra alvos afetados por Fluxo.Ao conjurar, Ryze cria um portal para um local próximo. Após alguns segundos, aliados próximos ao portal são teleportados ao local alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RyzeR.png'),
('RyzeW', 111, 'W', 'Prisão de Runa', 'Ryze prende um alvo em uma prisão de runas, causando dano e reduzindo sua Velocidade de Movimento. Se o alvo estiver afetado por Fluxo, ele é enraizado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/RyzeW.png'),
('Ryze_P', 111, 'P', 'Maestria Arcana', 'As habilidades de Ryze causam dano adicional com base em seu Mana adicional. Ele recebe um percentual de aumento de Mana máximo com base em seu Poder de Habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Ryze_P.png'),
('SamiraE', 112, 'E', 'Ímpeto Indomável', 'Samira avança e atravessa um inimigo (incluindo estruturas), cortando os inimigos atravessados e recebendo Velocidade de Ataque. Abater um Campeão inimigo reinicia o Tempo de Recarga da habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SamiraE.png'),
('SamiraQ', 112, 'Q', 'Talento Natural', 'Samira dispara um projétil ou golpeia com a espada, causando dano. Se a habilidade for conjurada durante Ímpeto Indomável, ela atinge todos os inimigos no caminho.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SamiraQ.png'),
('SamiraR', 112, 'R', 'Gatilho Infernal', 'Samira dispara uma saraivada de tiros, atingindo todos os inimigos ao redor dela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SamiraR.png'),
('SamiraW', 112, 'W', 'Voragem Afiada', 'Samira gira a espada ao seu redor, causando dano e destruindo projéteis inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SamiraW.png'),
('Samira_P', 112, 'P', 'Impulso Audacioso', 'Samira gera um combo conforme Ataca ou conjura habilidades de forma alternada. Seus Ataques corpo a corpo causam Dano Mágico adicional. Os Ataques de Samira contra inimigos sob efeitos Imobilizadores a farão avançar ao Alcance de Ataque dela. Se o inimigo estiver afetado por Arremesso ao ar, ela mantém o Arremesso ao ar por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/SamiraP.png'),
('SeismicShard', 76, 'Q', 'Fragmento Sísmico', 'Malphite arremessa um fragmento de terra no inimigo através do chão, causando dano ao impacto e roubando Velocidade de Movimento por 3s.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SeismicShard.png'),
('SejuaniE', 113, 'E', 'Congelamento Permanente', 'Sejuani congela e atordoa um Campeão inimigo que tiver o máximo de acúmulos de Congelar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SejuaniE.png'),
('SejuaniQ', 113, 'Q', 'Ataque do Ártico', 'Sejuani avança em investida, lançando os inimigos pelos ares. A investida cessa após acertar um Campeão inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SejuaniQ.png'),
('SejuaniR', 113, 'R', 'Prisão Glacial', 'Sejuani arremessa sua boleadeira, congelando e atordoando o primeiro Campeão que acertar, criando uma tempestade de gelo que causa lentidão aos demais inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SejuaniR.png'),
('SejuaniW', 113, 'W', 'Ira do Inverno', 'Sejuani usa a maça duas vezes, causando dano e aplicando acúmulos de Congelar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SejuaniW.png'),
('Sejuani_P', 113, 'P', 'Fúria do Norte', 'Após ficar fora de combate, Sejuani recebe Armadura Congelada, que concede Armadura, Resistência Mágica e imunidade a reduções de velocidade. Armadura Congelada persiste por um curto período após Sejuani sofrer dano e  Sejuani pode causar dano a um inimigo atordoado para estilhaçá-la, causando muito Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Sejuani_passive.png'),
('SennaE', 114, 'E', 'Maldição da Névoa Negra', 'Senna reúne a Névoa que ela armazenou em sua arma e a transforma em uma tempestade ao seu redor, abraçando a escuridão e se tornando um espectro. Os aliados que entram na área são camuflados e também tomam a forma de espectros enquanto a Névoa os envolve. Espectros têm sua Velocidade de Movimento aumentada, são inalvejáveis e escondem a própria identidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SennaE.png'),
('SennaQ', 114, 'Q', 'Escuridão Perfurante', 'Dos canos gêmeos de seu Canhão Relicário, Senna dispara um raio unificado de luz e sombra através do alvo, curando aliados e causando dano a inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SennaQ.png'),
('SennaR', 114, 'R', 'Sombra da Alvorada', 'Senna invoca as pedras relicárias dos Sentinelas caídos, dividindo seu canhão relicário em uma miríade de luz e sombra. Ela, então, dispara um raio global que concede escudo a aliados, enquanto causa dano aos inimigos atingidos no centro.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SennaR.png'),
('SennaW', 114, 'W', 'Abraço Final', 'Senna dispara uma onda de Névoa Negra. Se atingir um inimigo, ela o aprisiona ferozmente, enraizando o alvo e tudo que estiver ao redor dele após um curto intervalo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SennaW.png'),
('Senna_P', 114, 'P', 'Absolvição', 'Quando unidades são abatidas perto de Senna, suas almas são periodicamente aprisionadas na Névoa Negra. Senna pode atacar essas almas para libertá-las, absorvendo a Névoa que as aprisiona na morte. A Névoa é o combustível do poder de seu Canhão Relicário, alimentando-o com Dano de Ataque, Alcance de Ataque e Chance de Acerto Crítico. Ataques do Canhão Relicário de Senna demoram mais para disparar, causam dano adicional e concedem a ela brevemente uma parte da Velocidade de Movimento do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Senna_Passive.png'),
('SeraphineE', 115, 'E', 'Ritmo Contagiante', 'Seraphine causa dano e debilita o movimento dos inimigos em linha reta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SeraphineE.png'),
('SeraphineQ', 115, 'Q', 'Nota Aguda', 'Seraphine causa dano em uma área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SeraphineQ.png'),
('SeraphineR', 115, 'R', 'Bis', 'Seraphine causa dano e Encanta os inimigos atingidos, ampliando o alcance a cada Campeão aliado ou inimigo atingido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SeraphineR.png'),
('SeraphineW', 115, 'W', 'Som Envolvente', 'Seraphine concede Escudo e Aceleração aos aliados próximos. Caso ela já esteja protegida por um Escudo, também Curará os aliados próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SeraphineW.png'),
('Seraphine_P', 115, 'P', 'Presença de Palco', 'Cada terceira habilidade básica será conjurada duas vezes por Seraphine. Conjurar habilidades próximas a aliados também concede dano e alcance adicionais a ela no próximo ataque básico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Seraphine_Passive.png'),
('SettE', 116, 'E', 'Quebra-Crânio', 'Sett puxa todos os inimigos de cada lado seu, causando dano e atordoando. Caso haja inimigos somente de um lado, eles sofrem redução de velocidade em vez de atordoamento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SettE.png'),
('SettQ', 116, 'Q', 'Pancadaria', 'Os próximos dois ataques de Sett causam dano adicional com base na Vida máxima do alvo. Ele também recebe Velocidade de Movimento enquanto se move em direção a Campeões inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SettQ.png'),
('SettR', 116, 'R', 'Hora do Show', 'Sett carrega um Campeão inimigo pelos ares e o arremessa no chão, causando dano e redução de velocidade a todos os inimigos que estiverem próximos ao local de aterrissagem.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SettR.png'),
('SettW', 116, 'W', 'Casca-Grossa', 'O dano que Sett sofre é armazenado passivamente como Ousadia. Ao conjurar a habilidade, Sett consome toda a Ousadia armazenada em troca de um escudo e desfere um soco em uma área, causando Dano Verdadeiro no centro e Dano Físico nas laterais.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SettW.png'),
('Sett_P', 116, 'P', 'Ousadia da Arena', 'Os ataques básicos de Sett alternam entre socos de direita e esquerda. Socos de direita são levemente mais fortes e rápidos. Como Sett odeia perder, recebe Regeneração de Vida adicional com base na Vida perdida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Sett_P.png'),
('Shaco_P', 117, 'P', 'Apunhalar', 'Os ataques básicos de Shaco e Veneno de Dois Gumes causam dano adicional ao atingirem o inimigo por trás.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Jester_CarefulStrikes.png'),
('ShenE', 118, 'E', 'Corrida das Sombras', 'Shen avança em uma direção, provocando inimigos em seu trajeto.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ShenE.png'),
('ShenQ', 118, 'Q', 'Ataque Crepúsculo', 'Shen chama sua espada espiritual para atacar com ela, causando dano com base na Vida máxima do alvo. Os ataques são fortalecidos drasticamente caso ela colida com um Campeão inimigo. Todos os Campeões com quem ela colide têm a velocidade reduzida enquanto fogem de Shen.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ShenQ.png'),
('ShenR', 118, 'R', 'Manter a União', 'Shen protege o Campeão-alvo aliado do dano recebido e, em seguida, teleporta-se para seu local.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ShenR.png'),
('ShenW', 118, 'W', 'Refúgio Espiritual', 'Ataques que atingiriam Shen ou seus aliados próximos à sua espada espiritual são bloqueados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ShenW.png'),
('Shen_P', 118, 'P', 'Barreira de Ki', 'Após conjurar uma habilidade, Shen recebe um escudo. Afetar outros Campeões reduz o Tempo de Recarga desse efeito.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Shen_Passive.png'),
('ShyvanaDoubleAttack', 119, 'Q', 'Mordida Dupla', 'Shyvana golpeia duas vezes no próximo ataque e concede Velocidade de Ataque a si mesma nos próximos ataques. Ataques básicos reduzem o Tempo de Recarga de Mordida Dupla em 0,5s.Forma de Dragão: Mordida Dupla fere todas as unidades na frente de Shyvana.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ShyvanaDoubleAttack.png'),
('ShyvanaFireball', 119, 'E', 'Hálito Flamejante', 'Shyvana desfere uma bola de fogo que causa dano a todos os inimigos que atingir e deixa os alvos em brasa, marcando-os por 5 segundos. Os ataques básicos de Shyvana em alvos marcados causam um percentual de sua Vida máxima como dano ao contato.Forma de Dragão: Hálito Flamejante explode ao impacto ou no local alvo, causando dano adicional e abrasando a terra por um curto período de tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ShyvanaFireball.png'),
('ShyvanaImmolationAur', 119, 'W', 'Combustão', 'Shyvana rodeia-se com fogo, causando Dano Mágico por segundo a inimigos próximos e movimentando-se mais rápido por 3 segundos; parte deste dano é aplicada novamente quando os ataques básicos de Shyvana acertam um inimigo com o efeito de Combustão ativo. A Velocidade de Movimento é reduzida ao longo da duração da habilidade. Ataques básicos prolongam a duração de Combustão. Forma de Dragão: Combustão cresce em tamanho.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ShyvanaImmolationAura.png'),
('ShyvanaTransformCast', 119, 'R', 'Descida do Dragão', 'Shyvana se transforma em dragão e voa em direção ao local alvo. Inimigos em seu caminho recebem dano e são lançados na direção de seu local alvo.Shyvana passivamente recebe Fúria por segundo e recebe 2 de Fúria em ataques básicos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ShyvanaTransformCast.png'),
('Shyvana_P', 119, 'P', 'Fúria da Meio-Dragão', 'Shyvana causa dano adicional a dragões, além de receber Armadura e Resistência Mágica. Conforme Shyvana e seus aliados abatem mais dragões, ela recebe mais Armadura e Resistência Mágica.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/ShyvanaReinforcedScales.png'),
('Singed_P', 120, 'P', 'Corrente de Ar Nociva', 'Ao passar por Campeões próximos, Singed ganha Velocidade de Movimento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Singed_Passive.png'),
('SionE', 121, 'E', 'Urro do Assassino', 'Sion dispara uma onda de choque de curto alcance que causa dano e reduz a velocidade e Armadura do primeiro inimigo atingido. Se ela atingir uma tropa ou monstro, o mesmo será arremessado para trás, causando dano e reduzindo a velocidade e Armadura de todos os inimigos que atravessar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SionE.png'),
('SionQ', 121, 'Q', 'Golpe Demolidor', 'Sion carrega um poderoso golpe em uma área à sua frente que causará dano a inimigos quando lançado. Caso carregue por tempo suficiente, também arremessará ao ar e atordoará os inimigos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SionQ.png'),
('SionR', 121, 'R', 'Investida Incontrolável', 'Sion avança em linha reta, acelerando ao longo do tempo. Ele pode guiar levemente sua investida com o cursor do mouse na posição. Ao colidir com um inimigo, ele causa dano e o arremessa ao ar com base na distância percorrida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SionR.png'),
('SionW', 121, 'W', 'Fornalha da Alma', 'Sion se protege e pode reativar após 3 segundos para causar Dano Mágico a inimigos próximos. Quando Sion abate inimigos, ele recebe Vida máxima passivamente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SionW.png'),
('Sion_P', 121, 'P', 'In Gloria Mori', 'Após ser abatido, Sion será reanimado temporariamente, mas sua Vida decairá rapidamente. Seus ataques ficarão muito rápidos, curando e causando dano adicional com base na Vida máxima do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Sion_Passive1.png'),
('SivirE', 122, 'E', 'Escudo de Feitiço', 'Cria uma barreira mágica que bloqueia a habilidade de um único inimigo lançada em Sivir. Ela recebe Vida e uma explosão de Velocidade de Movimento se uma habilidade for bloqueada.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SivirE.png'),
('SivirQ', 122, 'Q', 'Lâmina Bumerangue', 'Sivir arremessa sua lâmina como um bumerangue, causando dano tanto na ida quanto na volta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SivirQ.png'),
('SivirR', 122, 'R', 'Na Caçada', 'Sivir conduz os aliados até a batalha, concedendo uma explosão de Velocidade de Movimento a eles por um curto período. Além disso, os ataques de Sivir reduzem o Tempo de Recarga das habilidades.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SivirR.png'),
('SivirW', 122, 'W', 'Ricochete', 'Os próximos ataques básicos de Sivir recebem Velocidade de Ataque adicional e ricocheteiam em alvos próximos, causando dano reduzido enquanto rebatem.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SivirW.png'),
('Sivir_P', 122, 'P', 'Pés Ligeiros', 'Sivir ganha um pequeno impulso de Velocidade de Movimento quando ela ataca um campeão inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Sivir_Passive.png'),
('SkarnerExoskeleton', 123, 'W', 'Exoesqueleto Cristalino', 'Skarner recebe um escudo e, enquanto este persiste, sua Velocidade de Movimento aumenta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SkarnerExoskeleton.png'),
('SkarnerFracture', 123, 'E', 'Fratura', 'Skarner invoca uma explosão de energia cristalina que causa dano e lentidão aos inimigos atingidos. Ataques básicos nestes inimigos dentre um curto período de tempo os atordoará.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SkarnerFracture.png'),
('SkarnerImpale', 123, 'R', 'Empalar', 'Skarner suprime um campeão inimigo e causa dano a ele. Durante este período, Skarner pode mover-se livremente e arrastará sua vítima indefesa com ele. Quando o efeito acabar, o alvo receberá dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SkarnerImpale.png'),
('SkarnerVirulentSlash', 123, 'Q', 'Corte de Cristal', 'Skarner ataca com suas garras, causando Dano Físico a todos os inimigos próximos e se carregando com Energia do Cristal por vários segundos caso uma unidade seja atingida. Se ele lançar Corte de Cristal novamente enquanto estiver fortalecido pela Energia do Cristal, causará Dano Mágico adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SkarnerVirulentSlash.png'),
('Skarner_P', 123, 'P', 'Espirais Cristalinas', 'A presença de Skarner faz com que cristais apareçam em locais específicos do mapa, podendo ser capturados por qualquer equipe que ficar sobre eles. Skarner recebe Velocidade de Movimento, Velocidade de Ataque e Regeneração de Mana aumentada quando estiver próximo a cristais capturados por sua equipe.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Skarner_Passive.png'),
('SonaE', 125, 'E', 'Canção da Celeridade', 'Sona toca a Canção da Celeridade, concedendo Velocidade de Movimento adicional a aliados próximos. Sona recebe uma aura temporária que concede Velocidade de Movimento adicional a Campeões aliados marcados pela área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SonaE.png'),
('SonaQ', 125, 'Q', 'Hino do Valor', 'Sona toca o Hino do Valor, conjurando rajadas de som, causando Dano Mágico a dois inimigos próximos, priorizando Campeões e monstros. Sona recebe uma aura temporária que concede dano adicional no próximo ataque de aliados próximos contra inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SonaQ.png'),
('SonaR', 125, 'R', 'Crescendo', 'Sona toca o seu melhor acorde, causando Dano Mágico, atordoando Campeões inimigos e forçando-os a dançar. Cada nível dessa habilidade reduz o Tempo de Recarga base das habilidades básicas de Sona.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SonaR.png'),
('SonaW', 125, 'W', 'Ária da Perseverança', 'Sona toca a Ária da Perseverança, conjurando melodias protetoras, curando a si mesma e a um aliado ferido próximo. Sona recebe uma aura temporária que concede um escudo momentâneo a aliados marcados pela área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SonaW.png'),
('Sona_P', 125, 'P', 'Power Chord', 'Accelerando: Sona recebe Aceleração permanentemente para as Habilidades básicas (exceto a ultimate), caso use-as corretamente, até um limite. Depois disso, o uso bem-sucedido reduz o Tempo de Recarga restante da ultimate.Power Chord: depois de algumas Habilidades conjuradas, o próximo Ataque de Sona causará Dano Mágico adicional e um efeito extra com base na última Habilidade básica ativada por ela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Sona_Passive_Charged.png'),
('SorakaE', 126, 'E', 'Equinócio', 'Cria uma área em um local, silenciando todos os inimigos dentro dela. Quando a área expira, os que ainda estiverem dentro são enraizados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SorakaE.png'),
('SorakaQ', 126, 'Q', 'Chamado Estelar', 'Uma estrela cai do céu no local-alvo, causando Dano Mágico e reduzindo a velocidade de inimigos. Se um Campeão inimigo for atingido por Chamado Estelar, Soraka regenera Vida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SorakaQ.png'),
('SorakaR', 126, 'R', 'Desejo', 'Soraka enche seus aliados de esperança, instantaneamente restaurando Vida para si mesma e todos os Campeões aliados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SorakaR.png'),
('SorakaW', 126, 'W', 'Infusão Astral', 'Soraka sacrifica parte de sua própria Vida para curar outro Campeão aliado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SorakaW.png'),
('Soraka_P', 126, 'P', 'Salvação', 'Soraka corre mais rapidamente em direção a aliados com pouca Vida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Soraka_Passive.png'),
('SowTheWind', 48, 'W', 'Zéfiro', 'Janna invoca um elemental do ar que aumenta passivamente sua Velocidade de Movimento e permite que ela atravesse unidades. Ela também pode ativar essa habilidade para causar dano e Lentidão a um inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SowTheWind.png'),
('StaticField', 15, 'R', 'Campo Estático', 'Inimigos atacados por Blitzcrank são marcados e sofrem dano de eletricidade após 1s. Ele também pode ativar esta habilidade para remover escudos de inimigos próximos, causar dano e silenciá-los brevemente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/StaticField.png'),
('SwainE', 127, 'E', 'Nuncamova', 'Swain lança uma onda de poder demoníaco à frente. Em seguida, a onda retorna para Swain e enraíza os inimigos que atingir. Swain pode escolher puxar todos os Campeões inimigos enraizados para perto. Esta Habilidade tem Tempo de Recarga reduzido durante Ascensão Demoníaca.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SwainE.png'),
('SwainQ', 127, 'Q', 'Mão da Morte', 'Swain dispara vários raios de poder sombrio que perfuram os inimigos. Inimigos atingidos sofrem mais dano para cada raio que os atingir.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SwainQ.png'),
('SwainR', 127, 'R', 'Ascensão Demoníaca', 'Swain se transforma em demônio e drena Vida de Campeões, tropas e monstros neutros próximos. Swain pode conjurar Chama Demoníaca para dizimar e causar Lentidão a inimigos próximos com uma explosão de fogo espiritual. Essa forma é indefinida enquanto Swain drenar Campeões inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SwainR.png'),
('SwainW', 127, 'W', 'Visão do Império', 'Swain abre um olho demoníaco que causa dano e reduz a velocidade dos inimigos. Campeões atingidos são revelados e concedem um Fragmento de Alma a Swain.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SwainW.png'),
('Swain_P', 127, 'P', 'Bando Voraz', 'Os corvos de Swain coletam Fragmentos de Alma que o curam e aumentam permanentemente a Vida máxima dele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Swain_P.png'),
('SylasE', 128, 'E', 'Evasão / Abdução', 'Sylas avança por uma curta distância, podendo reconjurar a habilidade para arremessar suas correntes e se arrastar na direção do inimigo atingido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SylasE.png'),
('SylasQ', 128, 'Q', 'Correntes-Chicote', 'Sylas chicoteia com suas correntes, que se intersectam no local-alvo, causando dano e reduzindo a velocidade dos inimigos. Após um intervalo, há uma explosão de energia mágica no ponto da intersecção, causando dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SylasQ.png'),
('SylasR', 128, 'R', 'Usurpar', 'Sylas rouba a habilidade ultimate do inimigo e pode conjurá-la sem custo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SylasR.png'),
('SylasW', 128, 'W', 'Regicida', 'Sylas avança em um inimigo com uma força mágica, causando dano e curando-se contra Campeões inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SylasW.png'),
('Sylas_P', 128, 'P', 'Explosão de Petricita', 'Após conjurar uma habilidade, Sylas armazena uma carga de Explosão de Petricita. Seus ataques básicos gastam uma carga e agitam as correntes energizadas ao redor dele, causando Dano Mágico adicional a inimigos atingidos. Enquanto Sylas tiver pelo menos uma carga de Explosão de Petricita, ele recebe Velocidade de Ataque. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/SylasP.png'),
('SyndraE', 129, 'E', 'Dispersar os Fracos', 'Syndra afasta inimigos e Esferas Negras, causando Dano Mágico. Inimigos atingidos pelas Esferas Negras ficam atordoados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SyndraE.png'),
('SyndraQ', 129, 'Q', 'Esfera Negra', 'Syndra conjura uma Esfera Negra, causando Dano Mágico. A esfera permanece em seu lugar e pode ser manipulada por seus outros poderes.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SyndraQ.png'),
('SyndraR', 129, 'R', 'Poder Irrestrito', 'Syndra bombardeia um Campeão inimigo com todas as suas Esferas Negras.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SyndraR.png'),
('SyndraW', 129, 'W', 'Força de Vontade', 'Syndra apanha e arremessa uma Esfera Negra ou tropa inimiga, causando Dano Mágico e reduzindo a Velocidade de Movimento de inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/SyndraW.png'),
('Syndra_P', 129, 'P', 'Transcender', 'Syndra coleta Farpas de Ira ao subir de nível ou causar dano a inimigos, aprimorando as próprias habilidades.Esfera Negra: Syndra pode segurar uma carga adicional.Força de Vontade: Dano Verdadeiro adicional.Dispersar os Fracos: largura aumentada e causa Lentidão a todos os alvos.Poder Irrestrito: executa alvos com a Vida baixa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/SyndraPassive.png'),
('TahmKenchE', 130, 'E', 'Pele Grossa', 'Passivo: Tahm Kench armazena uma porcentagem do dano sofrido e se cura com base nela quando fora de combate.Ativo: converte todo o dano armazenado em um Escudo temporário.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TahmKenchE.png'),
('TahmKenchQ', 130, 'Q', 'Língua-chicote', 'Tahm Kench ataca com a língua, causando dano e Lentidão à primeira unidade atingida, além de se curar se a unidade for um Campeão inimigo.Aplica um acúmulo de Um Gosto Adquirido a Campeões inimigos. Se o Campeão já tiver 3 acúmulos de Um Gosto Adquirido, ele será Atordoado e os acúmulos serão consumidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TahmKenchQ.png'),
('TahmKenchRWrapper', 130, 'R', 'Devorar', 'Tahm Kench devora um Campeão por alguns segundos, causando Dano Mágico se for um inimigo ou concedendo Escudo se for um aliado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TahmKenchRWrapper.png'),
('TahmKenchW', 130, 'W', 'Mergulho Abissal', 'Mergulha e reaparece no local-alvo, causando dano e Arremessando ao ar todos os inimigos em uma área.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TahmKenchW.png'),
('TahmKench_P', 130, 'P', 'Um Gosto Adquirido', 'Tahm Kench usa o próprio corpo para impulsionar os Ataques, causando dano adicional com base na Vida total dele. Causar dano a Campeões inimigos aumenta os acúmulos de Um Gosto Adquirido. Com três acúmulos, ele pode usar Devorar em um Campeão inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/TahmKenchP.png'),
('TaliyahE', 131, 'E', 'Terra Desfiada', 'Taliyah cria um campo minado de Lentidão. Caso inimigos avancem ou sejam arremessados através dele, as minas explodem, atordoando-os.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TaliyahE.png'),
('TaliyahQ', 131, 'Q', 'Voleio Entrelaçado', 'Taliyah arremessa uma rajada de pedras na direção-alvo, movimentando-se livremente durante a conjuração. Isso cria um Terreno Manipulado sob ela. Se Taliyah conjurar Voleio Entrelaçado em Terreno Manipulado, ela consome o terreno para arremessar um pedregulho fortalecido que causa Lentidão a inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TaliyahQ.png'),
('TaliyahR', 131, 'R', 'Muro da Tecelã', 'Taliyah cria uma parede comprida e desliza sobre ela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TaliyahR.png'),
('TaliyahWVC', 131, 'W', 'Empurrão Sísmico', 'Taliyah faz com que uma área do terreno irrompa e arremesse inimigos na direção de sua escolha.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TaliyahWVC.png'),
('Taliyah_P', 131, 'P', 'Deslizar em Pedras', 'Taliyah recebe Velocidade de Movimento próxima a paredes.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Taliyah_Passive.png'),
('TalonE', 132, 'E', 'Caminho do Assassino', 'Talon salta sobre quaisquer terrenos ou estruturas, até uma distância máxima. Esta habilidade possui um Tempo de Recarga baixo, mas deixa o terreno inutilizável por um longo período de tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TalonE.png'),
('TalonQ', 132, 'Q', 'Diplomacia Noxiana', 'Talon apunhala a unidade alvo. Caso eles estejam próximos o suficiente para um ataque corpo a corpo, o ataque causa dano crítico. Caso estejam fora do alcance corpo a corpo, Talon saltará no alvo e o apunhalará. Talon recupera um pouco da vida e do Tempo de Recarga caso sua habilidade abata o alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TalonQ.png'),
('TalonR', 132, 'R', 'Ataque das Sombras', 'Talon dispara um anel de lâminas e fica Invisível ao mesmo tempo em que recebe Velocidade de Movimento adicional. Quando Talon surge da Invisibilidade, as lâminas convergem em sua direção. A cada vez que a lâmina se move, Ataque das Sombras causa Dano Físico aos inimigos atingidos por ao menos uma lâmina.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TalonR.png'),
('TalonW', 132, 'W', 'Ancinho', 'Talon envia um voleio de adagas que retorna a ele, causando Dano Físico a cada vez que passar por um inimigo. As lâminas que retornarem causam dano adicional e reduzem a velocidade da unidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TalonW.png'),
('Talon_P', 132, 'P', 'Limiar da Lâmina', 'As habilidades de Talon causam Ferimentos em Campeões e monstros grandes, acumulando até 3 vezes. Quando Talon ataca um Campeão com 3 acúmulos de Ferimento, o alvo sofre intenso dano de sangramento ao longo do tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/TalonP.png'),
('Tantrum', 6, 'E', 'Chilique', 'Reduz permanentemente o Dano Físico que Amumu sofreria. Amumu pode liberar sua fúria, causando dano a inimigos próximos. Sempre que Amumu é atingido, o Tempo de Recarga de Chilique é reduzido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Tantrum.png'),
('TaricE', 133, 'E', 'Deslumbrar', 'Taric prepara um feixe de luz estelar que, após um breve intervalo, causa Dano Mágico e atordoa inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TaricE.png'),
('TaricQ', 133, 'Q', 'Fulgor Estelar', 'Cura Campeões aliados próximos com base nas cargas armazenadas. Ataques fortalecidos por Bravata concedem uma carga de Fulgor Estelar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TaricQ.png'),
('TaricR', 133, 'R', 'Resplendor Cósmico', 'Faz pulsar energia cósmica em Campeões aliados próximos após um intervalo, tornando-os invulneráveis por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TaricR.png'),
('TaricW', 133, 'W', 'Bastião', 'Aumenta passivamente a Armadura de Taric e de qualquer Campeão aliado com Bastião.Protege ativamente um aliado e lhe concede Bastião por todo o tempo que permanecer próximo a Taric. As habilidades de Taric também são conjuradas a partir do aliado com Bastião.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TaricW.png'),
('Taric_P', 133, 'P', 'Bravata', 'Conjurações fortalecem os próximos 2 ataques básicos de Taric, causando Dano Mágico adicional, reduzindo Tempos de Recarga e atacando em rápida sucessão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Taric_Passive.png'),
('TeemoRCast', 134, 'R', 'Armadilha Venenosa', 'Teemo arremessa uma armadilha venenosa explosiva usando um dos cogumelos que guardou na mochila. Se um inimigo pisar na armadilha, ela soltará uma nuvem venenosa que causa dano e reduz a velocidade de inimigos ao longo do tempo. Se Teemo arremessar um cogumelo em cima de outro, ele saltará, recebendo alcance adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TeemoRCast.png'),
('Teemo_P', 134, 'P', 'Técnicas de Guerrilha', 'Se Teemo permanecer imóvel e não fizer nada por um curto período, fica Invisível por tempo indefinido. Caso esteja em um arbusto, Teemo pode manter sua Invisibilidade enquanto se move. Ao sair da Invisibilidade, Teemo ativa Elemento Surpresa, aumentando a própria Velocidade de Ataque por alguns segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Teemo_P.png');
INSERT INTO `habilidades` (`ID_habilidade`, `ID_campeao`, `tecla`, `nome_habilidade`, `descricao`, `imagem_url`) VALUES
('ThreshE', 135, 'E', 'Esfolar', 'Os ataques de Thresh são fortalecidos, causando mais dano quanto mais tempo ele esperar entre ataques. Ao ativar, Thresh arrasta sua corrente e empurra todos os inimigos atingidos na direção do golpe.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ThreshE.png'),
('ThreshQ', 135, 'Q', 'Sentença', 'Thresh prende um inimigo em suas correntes e puxa em sua direção. Ativar essa habilidade uma segunda vez puxa Thresh em direção ao inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ThreshQ.png'),
('ThreshRPenta', 135, 'R', 'A Caixa', 'Uma prisão de paredes que causam dano e Lentidão se quebradas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ThreshRPenta.png'),
('ThreshW', 135, 'W', 'Passagem Sombria', 'Thresh arremessa uma lanterna que protege Campeões aliados próximos contra danos. Aliados podem clicar na lanterna para avançar na direção de Thresh.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ThreshW.png'),
('Thresh_P', 135, 'P', 'Condenação', 'Thresh pode colher a alma de inimigos que morrerem perto dele, recebendo Armadura e Poder de Habilidade permanentemente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Thresh_Passive.png'),
('TimeWarp', 165, 'E', 'Distorção no Tempo', 'Zilean manipula o tempo ao redor de qualquer unidade, causando Lentidão a um inimigo ou concedendo Velocidade de Movimento a um aliado por um curto período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TimeWarp.png'),
('ToxicShot', 134, 'E', 'Tiro Tóxico', 'Cada um dos ataques de Teemo envenenará o alvo, causando dano no impacto e a cada segundo seguinte por 4 segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ToxicShot.png'),
('Tremors2', 103, 'R', 'Colisão Ascendente', 'Rammus salta e se joga com força na área-alvo, causando Dano Mágico e Lentidão aos inimigos atingidos. Se a Habilidade for conjurada enquanto Rammus estiver com Bola do Poder ativa, ele também arremessará ao ar os inimigos próximos ao centro.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Tremors2.png'),
('TristanaE', 136, 'E', 'Carga Explosiva', 'Quando Tristana abate uma unidade, seus projéteis explodem com estilhaços, causando dano a inimigos próximos. Isso pode ser ativado para posicionar uma bomba em um alvo inimigo, que explodirá após uma curta duração, causando dano a unidades ao seu redor.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TristanaE.png'),
('TristanaQ', 136, 'Q', 'Tiro Rápido', 'Tristana dispara rapidamente com seu canhão, aumentando sua Velocidade de Ataque por um curto período de tempo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TristanaQ.png'),
('TristanaR', 136, 'R', 'Tiro Destruidor', 'Tristana carrega uma gigantesca bala de canhão em sua arma e a dispara em uma unidade inimiga. Isso causa Dano Mágico e empurra o alvo para trás. Se o alvo estiver carregando uma bomba da Carga Explosiva, o raio de explosão da bomba é dobrado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TristanaR.png'),
('TristanaW', 136, 'W', 'Salto-foguete', 'Tristana dispara no chão para lançar-se ao local-alvo, causando dano e reduzindo a Velocidade de Movimento das unidades ao seu redor por um breve momento ao aterrissar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TristanaW.png'),
('Tristana_P', 136, 'P', 'Tiro Certeiro', 'Aumenta o Alcance de Ataque de Tristana conforme ela sobe de nível.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Tristana_Passive.png'),
('TrundleCircle', 137, 'E', 'Pilar de Gelo', 'Trundle cria um pilar de gelo no local-alvo, tornando-o um terreno intransponível e causando Lentidão a todas as unidades inimigas próximas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TrundleCircle.png'),
('trundledesecrate', 137, 'W', 'Domínio Congelado', 'Trundle transforma o local-alvo em seu domínio, recebendo Velocidade de Ataque, Velocidade de Movimento e cura aprimorada de todas as fontes enquanto estiver sobre a região.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/trundledesecrate.png'),
('TrundlePain', 137, 'R', 'Subjugar', 'Trundle imediatamente rouba um percentual da Vida, Armadura e Resistência Mágica de seu alvo. Ao longo dos próximos 4 segundos, a quantia de Vida, Armadura e Resistência Mágica roubada é dobrada.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TrundlePain.png'),
('TrundleTrollSmash', 137, 'Q', 'Mordida', 'Trundle morde seu oponente, causando dano, brevemente reduzindo sua Velocidade de Movimento e drenando parte de seu Dano de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TrundleTrollSmash.png'),
('Trundle_P', 137, 'P', 'Tributo do Rei', 'Quando uma unidade inimiga morre perto de Trundle, ele é curado em um percentual da Vida máxima desta unidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Trundle_Passive.png'),
('TryndamereE', 138, 'E', 'Corte Giratório', 'Tryndamere avança em direção a uma unidade-alvo, causando dano aos inimigos em seu trajeto.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TryndamereE.png'),
('TryndamereQ', 138, 'Q', 'Sanguinário', 'Tryndamere prospera com o calor do combate, aumentando seu próprio Dano de Ataque conforme for ficando mais e mais ferido. Ele pode conjurar Sanguinário para consumir sua Fúria e curar a si mesmo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TryndamereQ.png'),
('TryndamereW', 138, 'W', 'Grito Zombador', 'Tryndamere solta um grito insultante, diminuindo o Dano de Ataque dos Campeões próximos. Inimigos que estiverem de costas para Tryndamere também têm sua Velocidade de Movimento reduzida.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TryndamereW.png'),
('Tryndamere_P', 138, 'P', 'Fúria da Batalha', 'Tryndamere recebe Fúria para cada ataque, acerto crítico e golpe fatal que realiza. A Fúria passivamente aumenta a sua Chance de Acerto Crítico e pode ser consumida com a habilidade Sanguinário.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Tryndamere_Passive.png'),
('TwistedFate_P', 139, 'P', 'Dados Viciados', 'Ao abater uma unidade, Twisted Fate rola seu dado da \'\'sorte\'\' e recebe de 1 a 6 de ouro adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Cardmaster_SealFate.png'),
('TwitchExpunge', 140, 'E', 'Contaminar', 'Twitch causa ainda mais destruição em inimigos envenenados com uma explosão de suas pestes.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TwitchExpunge.png'),
('TwitchFullAutomatic', 140, 'R', 'Passando Fogo', 'Twitch desfere o poder total de sua besta, fazendo disparos de longuíssimo alcance que perfuram todos os inimigos pegos em seu trajeto.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TwitchFullAutomatic.png'),
('TwitchHideInShadows', 140, 'Q', 'Emboscada', 'Twitch fica Camuflado por um curto período e recebe Velocidade de Movimento. Ao sair da Camuflagem, Twitch recebe Velocidade de Ataque por um curto período.Quando um Campeão inimigo com Veneno Mortal é abatido, o Tempo de Recarga de Emboscada é reiniciado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TwitchHideInShadows.png'),
('TwitchVenomCask', 140, 'W', 'Tonel de Veneno', 'Twitch joga um tonel de veneno que explode em uma área, causando Lentidão e veneno mortal aos alvos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TwitchVenomCask.png'),
('Twitch_P', 140, 'P', 'Veneno Mortal', 'Os ataques básicos de Twitch infectam o alvo, causando Dano Verdadeiro a cada segundo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Twitch_Passive.png'),
('TwoShivPoison', 117, 'E', 'Veneno de Dois Gumes', 'As facas de Shaco envenenam alvos passivamente ao contato, reduzindo sua Velocidade de Movimento. Ele pode arremessá-las para causar dano e envenenar o alvo. A faca arremessada causa dano adicional se a Vida do alvo estiver abaixo de 30%.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/TwoShivPoison.png'),
('UdyrE', 141, 'E', 'Investida Ardente', 'Udyr recebe Velocidade de Movimento e causa Atordoamento em seu primeiro Ataque a cada alvo. Reconjuração: recebe ainda mais Velocidade de Movimento e imunidade a efeitos imobilizadores por alguns segundos. ', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UdyrE.png'),
('UdyrQ', 141, 'Q', 'Garra Selvagem', 'Udyr recebe Velocidade de Ataque, e seus próximos dois Ataques causam Dano Físico adicional. Reconjuração: recebe ainda mais Velocidade de Ataque, e seus próximos dois Ataques conjuram relâmpagos no alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UdyrQ.png'),
('UdyrR', 141, 'R', 'Tempestade Alada', 'Udyr cerca a si mesmo com uma tempestade glacial, causando dano e Lentidão a inimigos próximos. Reconjuração: fortalece e desencadeia a tempestade, fazendo com que ela siga inimigos e cause dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UdyrR.png'),
('UdyrW', 141, 'W', 'Manto de Ferro', 'Udyr recebe um Escudo e seus próximos dois Ataques o curam. Reconjuração: recebe um Escudo ainda maior e cura com base na Vida máxima pelos próximos segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UdyrW.png'),
('Udyr_P', 141, 'P', 'Ponte Espiritual', 'Udyr tem quatro Habilidades básicas que o fazem alternar entre Posturas e pode Reconjurar uma Habilidade para renová-la com efeitos adicionais. Além disso, após usar uma Habilidade, os próximos dois Ataques de Udyr recebem Velocidade de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Udyr_P.png'),
('UFSlash', 76, 'R', 'Força Incontrolável', 'Malphite se arremessa em alta velocidade até um local, causando dano aos inimigos e Arremessando-os ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UFSlash.png'),
('UndyingRage', 138, 'R', 'Fúria Sem Fim', 'O desejo de Tryndamere pela batalha se torna tão forte que ele fica incapaz de morrer, não importa o quão ferido ele esteja.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UndyingRage.png'),
('UrgotE', 142, 'E', 'Desdém', 'Urgot avança em uma direção, protegendo-se com um escudo e pisoteando inimigos não Campeões. Se atingir um Campeão inimigo, ele para e o arremessa para fora de seu caminho.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UrgotE.png'),
('UrgotQ', 142, 'Q', 'Carga Corrosiva', 'Detona uma carga explosiva no local-alvo, causando Dano Físico e reduzindo a velocidade dos inimigos atingidos pela explosão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UrgotQ.png'),
('UrgotR', 142, 'R', 'Pior que a Morte', 'Urgot dispara uma broca química que perfura o primeiro Campeão inimigo atingido. Se esse Campeão ficar abaixo de um limite mínimo de Vida, Urgot o julgará fraco e o executará.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UrgotR.png'),
('UrgotW', 142, 'W', 'Expurgar', 'Urgot reduz sua velocidade enquanto descarrega sua arma contra inimigos próximos. Prioriza Campeões inimigos que tenha atingido recentemente com outras habilidades e aciona Chamas Ecoantes.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/UrgotW.png'),
('Urgot_P', 142, 'P', 'Chamas Ecoantes', 'Os ataques básicos de Urgot e Expurgar disparam periodicamente explosões de chamas de suas pernas, causando Dano Físico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Urgot_Passive.png'),
('VarusE', 143, 'E', 'Chuva de Flechas', 'Varus dispara uma chuva de flechas que causa Dano Físico e profana o terreno. Terrenos profanados reduzem a Velocidade de Movimento, autocura e regeneração dos inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VarusE.png'),
('VarusQ', 143, 'Q', 'Flecha Perfurante', 'Varus prepara um poderoso disparo, que ganha alcance e dano extra quanto mais demorar para ser lançado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VarusQ.png'),
('VarusR', 143, 'R', 'Corrente da Corrupção', 'Varus lança um tentáculo de corrupção que causa dano e imobiliza o primeiro Campeão inimigo atingido, espalhando-se ainda para os Campeões inimigos próximos que ainda não estiverem infectados, imobilizando-os ao contato.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VarusR.png'),
('VarusW', 143, 'W', 'Aljava da Ruína', 'Passivo: Os ataques básicos de Varus causam Dano Mágico adicional e aplicam Arruinar. As outras habilidades de Varus detonam os acúmulos de Arruinar, causando Dano Mágico com base na Vida máxima do alvo. Ativo: Varus fortalece sua próxima Flecha Perfurante.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VarusW.png'),
('Varus_P', 143, 'P', 'Vingança Viva', 'Ao conseguir um abate ou assistência, Varus recebe Velocidade de Ataque temporariamente. O efeito é maior se o inimigo for um Campeão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/VarusPassive.png'),
('VayneCondemn', 144, 'E', 'Condenar', 'Vayne puxa uma pesada besta de suas costas e dispara um gigantesco projétil em seu alvo, arremessando-o para trás e causando dano. Caso colida com terreno, ele fica empalado, o que lhe causa dano adicional e atordoamento.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VayneCondemn.png'),
('VayneInquisition', 144, 'R', 'Hora Final', 'Preparando-se para um confronto épico, Vayne recebe Dano de Ataque aumentado, invisibilidade durante o Rolamento, Tempo de Recarga do Rolamento reduzido e mais Velocidade de Movimento adicional de Caçadora Noturna', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VayneInquisition.png'),
('VayneSilveredBolts', 144, 'W', 'Dardos de Prata', 'Vayne aprimora suas flechas com um metal raro, tóxico a qualquer coisa maligna. A cada terceiro ataque consecutivo ou habilidade contra o mesmo alvo causa um percentual da Vida máxima do alvo como Dano Verdadeiro adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VayneSilveredBolts.png'),
('VayneTumble', 144, 'Q', 'Rolamento', 'Vayne dá uma cambalhota, equilibrando-se para efetuar seu próximo disparo. Seu próximo ataque causará dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VayneTumble.png'),
('Vayne_P', 144, 'P', 'Caçadora Noturna', 'Vayne caça implacavelmente os malfeitores, ganhando 45 de Velocidade de Movimento ao se deslocar em direção a Campeões inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Vayne_NightHunter.png'),
('VeigarBalefulStrike', 145, 'Q', 'Golpe Maligno', 'Veigar faz um disparo de energia das trevas que causa Dano Mágico aos dois primeiros inimigos atingidos. Unidades abatidas por este disparo concedem a ele um pouco de Poder de Habilidade permanentemente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VeigarBalefulStrike.png'),
('VeigarDarkMatter', 145, 'W', 'Matéria Escura', 'Veigar invoca uma grande massa de Matéria Escura que cai do céu sobre o local-alvo, causando Dano Mágico ao chegar no chão. Os acúmulos de Poder Maligno Fenomenal reduzem o Tempo de Recarga de Matéria Escura.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VeigarDarkMatter.png'),
('VeigarEventHorizon', 145, 'E', 'Horizonte de Eventos', 'Veigar distorce os limites do espaço, criando uma prisão que Atordoa os inimigos que a atravessam.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VeigarEventHorizon.png'),
('VeigarR', 145, 'R', 'Explosão Primordial', 'Explode o Campeão-alvo inimigo, causando uma grande quantia de Dano Mágico, que aumenta com base na Vida perdida do alvo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VeigarR.png'),
('Veigar_P', 145, 'P', 'Poder Maligno Fenomenal', 'Veigar é o maior ser maligno a chegar ao coração de Runeterra - e vai ficar cada vez maior! Atingir um Campeão inimigo com uma habilidade ou executar um golpe final concede a Veigar um aumento permanente de Poder de Habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/VeigarEntropy.png'),
('VelkozE', 146, 'E', 'Ruptura Tectônica', 'Vel\'Koz faz com que uma área exploda, arremessando inimigos ao ar e afastando inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VelkozE.png'),
('VelkozQ', 146, 'Q', 'Fissão Plasmática', 'Vel\'Koz dispara um projétil de plasma que se divide em dois ao ser reativado ou ao atingir um inimigo. O projétil causa dano e redução de velocidade a inimigos ao contato.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VelkozQ.png'),
('VelkozR', 146, 'R', 'Raio Desintegrador de Formas de Vida', 'Vel\'Koz desfere um raio canalizado que segue o cursor por 2,5s, causando Dano Mágico. Desconstrução Orgânica pesquisa Campeões inimigos, fazendo com que recebam Dano Verdadeiro em vez de Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VelkozR.png'),
('VelkozW', 146, 'W', 'Fenda do Vazio', 'Vel\'Koz abre uma fenda ao Vazio que causa uma rajada inicial de dano, explodindo em seguida para causar mais dano após um breve intervalo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VelkozW.png'),
('Velkoz_P', 146, 'P', 'Desconstrução Orgânica', 'As habilidades de Vel\'Koz aplicam Desconstrução Orgânica nos inimigos ao contato. Ao chegar a 3 acúmulos, o inimigo receberá uma rajada de Dano Verdadeiro.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/VelKoz_Passive.png'),
('VexE', 147, 'E', 'Penumbra Iminente', 'Invoca uma área que causa dano e Lentidão aos inimigos, além de aplicar Escuridão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VexE.png'),
('VexQ', 147, 'Q', 'Rajada Mistral', 'Lança um projétil que causa dano e acelera no meio do trajeto.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VexQ.png'),
('VexR', 147, 'R', 'Onda Sombria', 'Dispara um projétil que marca um Campeão inimigo.  Reconjure para avançar até o alvo e causar dano.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VexR.png'),
('VexW', 147, 'W', 'Espaço Pessoal', 'Recebe um Escudo e causa dano a inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VexW.png'),
('Vex_P', 147, 'P', 'Destruição e Escuridão', 'Periodicamente, Vex é fortalecida, fazendo com que a próxima Habilidade básica dela cause Temor aos inimigos e interrompa avanços. Sempre que um inimigo próximo avança, Vex aplica uma marca que é consumida para causar dano adicional, além de reduzir o Tempo de Recarga do estado fortalecido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Icons_Vex_Passive.png'),
('ViE', 148, 'E', 'Força Implacável', 'O próximo ataque de Vi atravessará seu alvo, causando dano aos inimigos atrás dele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViE.png'),
('ViegoE', 149, 'E', 'Domínio Atormentado', 'Viego ordena que a Névoa Negra assombre e cerque uma porção de terreno. Ele pode se esconder na Névoa como um Espectro, recebendo Camuflagem, Velocidade de Movimento e Velocidade de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViegoE.png'),
('ViegoQ', 149, 'Q', 'Espada do Rei Destruído', 'A lâmina espectral de Viego causa uma porcentagem da Vida atual do alvo como dano adicional ao contato de forma passiva e atinge duas vezes os inimigos recentemente afetados por uma Habilidade, roubando Vida.Viego pode ativar essa Habilidade para golpear, perfurando inimigos à frente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViegoQ.png'),
('ViegoR', 149, 'R', 'Destruidor de Corações', 'Viego teleporta-se para um local próximo e executa um Campeão inimigo ao chegar, atravessando seu coração e liberando uma onda de choque destrutiva que empurra os inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViegoR.png'),
('ViegoW', 149, 'W', 'Posse Espectral', 'Viego carrega antes de avançar, lançando uma esfera de Névoa Negra concentrada que atordoa o primeiro inimigo atingido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViegoW.png'),
('Viego_P', 149, 'P', 'Dominação Monárquica', 'Inimigos derrotados por Viego se tornam Espectros. Ao atacá-los, Viego toma controle do corpo do inimigo morto temporariamente, curando-se em um percentual da Vida máxima do alvo e ganhando acesso a seus itens e habilidades básicas. Ele substitui a ultimate da vítima por uma conjuração gratuita de sua própria ultimate.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Viego_Passive.png'),
('ViktorChaosStorm', 150, 'R', 'Tempestade do Caos', 'Viktor conjura uma singularidade no campo que causa Dano Mágico e interrompe canalizações de inimigos. Em seguida, a singularidade causa Dano Mágico periodicamente a todos os inimigos próximos. Viktor pode redirecionar a singularidade.Aprimoramento: a Tempestade do Caos se move 25% mais rápido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViktorChaosStorm.png'),
('ViktorDeathRay', 150, 'E', 'Raio da Morte', 'Viktor usa seu braço robótico para disparar um feixe caótico que corta o campo em linha reta, causando dano a todos os inimigos no trajeto.Aprimoramento: Uma explosão segue o rastro de Raio da Morte, causando Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViktorDeathRay.png'),
('ViktorGravitonField', 150, 'W', 'Campo Gravítico', 'Viktor conjura um campo gravitacional pesado que causa Lentidão a inimigos em seu raio de ação. Inimigos que permanecerem no dispositivo por tempo demais são Atordoados.Aprimoramento: habilidades não periódicas de Viktor causam Lentidão aos inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViktorGravitonField.png'),
('ViktorPowerTransfer', 150, 'Q', 'Poder do Sifão', 'Viktor explode uma unidade inimiga, causando Dano Mágico, recebendo um escudo e fortalecendo seu próximo ataque básico.Aprimoramento: O escudo de Poder do Sifão aumenta em 60% e Viktor recebe Velocidade de Movimento adicional na conjuração.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViktorPowerTransfer.png'),
('Viktor_P', 150, 'P', 'Gloriosa Evolução', 'Viktor pode aprimorar suas habilidades básicas quando abater inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Viktor_Passive.png'),
('ViQ', 148, 'Q', 'Quebra-Cofres', 'Vi carrega suas manoplas e desfere um soco capaz de quebrar cofres, empurrando-a para frente. Os inimigos que ela atingir são empurrados para trás e recebem um acúmulo de Pancada Certeira.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViQ.png'),
('ViR', 148, 'R', 'Saque e Enterrada', 'Vi persegue um inimigo em alta velocidade, empurrando para longe qualquer um em seu trajeto. Ao alcançar o alvo, ela o arremessa ao ar, salta atrás dele e o golpeia de volta ao chão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViR.png'),
('ViW', 148, 'W', 'Pancada Certeira', 'Os socos de Vi quebram a Armadura de seu oponente, causando dano adicional e concedendo a ela Velocidade de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ViW.png'),
('Vi_P', 148, 'P', 'Blindagem', 'Vi carrega um escudo ao longo do tempo que pode ser ativado ao atingir um inimigo com uma habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/ViPassive.png'),
('VladimirE', 151, 'E', 'Maré de Sangue', 'Vladimir paga com a própria Vida para carregar uma reserva de sangue que, quando desferida, causa dano em área ao seu redor, mas pode ser bloqueada por unidades inimigas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VladimirE.png'),
('VladimirHemoplague', 151, 'R', 'Hemopraga', 'Vladimir infecta uma área com uma praga virulenta. Inimigos afetados recebem dano crescente enquanto durar o efeito. Depois de alguns segundos, Hemopraga causa Dano Mágico aos inimigos infectados e cura Vladimir a cada Campeão inimigo atingido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VladimirHemoplague.png'),
('VladimirQ', 151, 'Q', 'Transfusão', 'Vladimir rouba vida do inimigo-alvo. Quando sua reserva estiver cheia, Transfusão terá os benefícios de dano e cura drasticamente aumentados por um breve período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VladimirQ.png'),
('VladimirSanguinePool', 151, 'W', 'Poça de Sangue', 'Vladimir mergulha numa poça de sangue, tornando-se inalvejável por 2s. Além disso, inimigos na poça sofrem redução de Velocidade de Movimento e Vladimir drena Vida deles.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VladimirSanguinePool.png'),
('Vladimir_P', 151, 'P', 'Pacto Vermelho', 'Cada 30 pontos de Vida adicional concedem 1 de Poder de Habilidade a Vladimir, e cada 1 ponto de Poder de Habilidade concede a ele 1,6 de Vida adicional (não cumulativos entre si).', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/VladimirP.png'),
('VolibearE', 152, 'E', 'Divisor de Céus', 'Volibear invoca um relâmpago em um local, causando dano e Lentidão aos inimigos. Ele também ganhará um Escudo se estiver no raio da explosão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VolibearE.png'),
('VolibearQ', 152, 'Q', 'Esmagamento Trovejante', 'Volibear ganha velocidade ao correr na direção dos inimigos, Atordoando e causando dano ao primeiro que Atacar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VolibearQ.png'),
('VolibearR', 152, 'R', 'Emissário da Tempestade', 'Volibear salta até um local-alvo, causando dano e Lentidão aos inimigos sob ele, além de receber Vida adicional.  Torres inimigas próximas ao local de pouso são temporariamente Desabilitadas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VolibearR.png'),
('VolibearW', 152, 'W', 'Fúria Selvagem', 'Volibear causa dano a um inimigo, marcando-o e aplicando efeitos ao contato.  Conjurar a habilidade novamente no mesmo alvo causa dano adicional e cura Volibear.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VolibearW.png'),
('Volibear_P', 152, 'P', 'A Tempestade Implacável', 'Os Ataques e habilidades de Volibear concedem Velocidade de Ataque e, às vezes, fazem com que seus Ataques causem Dano Mágico adicional a inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Volibear_Icon_P.png'),
('Volley', 10, 'W', 'Rajada', 'Ashe dispara flechas em cone, causando dano aumentado. Também aplica Tiro Congelado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/Volley.png'),
('VorpalSpikes', 22, 'E', 'Espinhos Vorpais', 'Os ataques de Cho\'Gath lançam espinhos letais, causando dano e reduzindo a velocidade de unidades inimigas à sua frente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/VorpalSpikes.png'),
('WarwickE', 153, 'E', 'Uivo Primitivo', 'Warwick recebe redução de dano por 2,5 segundos. Ao fim do efeito, ou caso seja reativado, ele uiva, fazendo com que inimigos próximos fujam por 1 segundo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/WarwickE.png'),
('WarwickQ', 153, 'Q', 'Presas da Fera', 'Warwick lança-se à frente e morde seu alvo, causando dano com base em sua Vida máxima e curando a si mesmo com o dano causado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/WarwickQ.png'),
('WarwickR', 153, 'R', 'Coerção Infinita', 'Warwick salta em uma direção (escalando com a Velocidade de Movimento adicional dele), suprimindo o primeiro Campeão atingido por 1,5s.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/WarwickR.png'),
('WarwickW', 153, 'W', 'Caçada Sangrenta', 'Warwick percebe inimigos com menos de 50% Vida, recebendo Velocidade de Movimento ao movimentar-se na direção deles e Velocidade de Ataque ao afastar-se deles. Se ficarem com menos de 20% de Vida, ele entra em frenesi e os efeitos são triplicados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/WarwickW.png'),
('Warwick_P', 153, 'P', 'Fome Eterna', 'Os ataques básicos de Warwick causam Dano Mágico adicional. Se ele estiver com menos de 50% de Vida, cura a si mesmo com a mesma quantia. Se ele estiver com menos de 25% de Vida, a cura é triplicada.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/WarwickP.png'),
('WildCards', 139, 'Q', 'Curingas', 'Twisted Fate arremessa três cartas, causando dano a cada inimigo que elas atravessam.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/WildCards.png'),
('WujuStyle', 79, 'E', 'Estilo Wuju', 'Concede Dano Verdadeiro adicional em ataques básicos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/WujuStyle.png'),
('XayahE', 154, 'E', 'Invocadora das Lâminas', 'Xayah recolhe todas as Plumas que caíram, causando dano e enraizando os inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XayahE.png'),
('XayahQ', 154, 'Q', 'Punhais Duplos', 'Xayah arremessa dois punhais que causam dano e deixam cair Plumas que podem retornar para ela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XayahQ.png'),
('XayahR', 154, 'R', 'Tempestade de Plumas', 'Xayah salta pelo ar, ficando inalvejável e arremessando um leque de punhais, além de deixar cair Plumas que podem voltar para ela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XayahR.png'),
('XayahW', 154, 'W', 'Plumagem Mortífera', 'Xayah cria uma tempestade de lâminas que aumenta seu dano e sua Velocidade de Ataque, além de conceder Velocidade de Movimento ao atacar um Campeão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XayahW.png'),
('Xayah_P', 154, 'P', 'Cortes Certeiros', 'Depois de usar uma habilidade, os próximos ataques básicos de Xayah acertam todos os alvos pelo caminho e deixam uma Pluma.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/XayahPassive.png'),
('XerathArcaneBarrage2', 155, 'W', 'Olho da Destruição', 'Invoca uma barragem de energia arcana, causando Dano Mágico e redução de Velocidade de Movimento a todos os inimigos em uma área. Alvos no centro recebem dano adicional e uma redução de velocidade mais forte.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XerathArcaneBarrage2.png'),
('XerathArcanopulseCha', 155, 'Q', 'Pulso Arcano', 'Dispara um raio de energia de longo alcance, causando Dano Mágico a todos os alvos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XerathArcanopulseChargeUp.png'),
('XerathLocusOfPower2', 155, 'R', 'Ritual Arcano', 'Xerath imobiliza a si mesmo e dispara diversas barragens de longa distância.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XerathLocusOfPower2.png'),
('XerathMageSpear', 155, 'E', 'Orbe Eletrizante', 'Causa Dano Mágico a um inimigo e o atordoa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XerathMageSpear.png'),
('Xerath_P', 155, 'P', 'Oscilação de Mana', 'Os ataques básicos de Xerath restauram Mana periodicamente. Sempre que Xerath abate uma unidade, esse Tempo de Recarga é reduzido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Xerath_Passive1.png'),
('XinZhaoE', 156, 'E', 'Investida Audaciosa', 'Xin Zhao avança na direção de um inimigo, ganhando Velocidade de Ataque e causando dano e Lentidão a todos os inimigos na área temporariamente. Investida Audaciosa recebe alcance aumentado contra alvos Desafiados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XinZhaoE.png'),
('XinZhaoQ', 156, 'Q', 'Golpe de Três Garras', 'O próximos 3 ataques normais de Xin Zhao causam mais dano. O último arremessa o oponente ao ar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XinZhaoQ.png'),
('XinZhaoR', 156, 'R', 'Guarda Crescente', 'Xin Zhao desafia um inimigo a quem tiver causado dano recentemente. Ele causa dano a inimigos próximos com base na Vida atual deles e Arremessa alvos não Desafiados para trás, tornando-se imune a qualquer dano causado por Campeões fora do círculo criado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XinZhaoR.png'),
('XinZhaoW', 156, 'W', 'Vento Vira Relâmpago', 'Xin Zhao golpeia à frente com a lança, causando Lentidão e marcando os inimigos atingidos como Desafiados.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/XinZhaoW.png'),
('XinZhao_P', 156, 'P', 'Determinação', 'Cada terceiro ataque básico causa dano adicional e cura Xin Zhao.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/XinZhaoP.png'),
('YasuoE', 157, 'E', 'Espada Ágil', 'Avança e atravessa o inimigo-alvo, causando Dano Mágico. Cada conjuração aumenta o dano do próximo avanço, até um limite máximo.Não pode ser conjurada novamente no mesmo inimigo por alguns segundos.Se Tempestade de Aço for conjurada durante o avanço, o Ataque será circular.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YasuoE.png'),
('YasuoQ1Wrapper', 157, 'Q', 'Tempestade de Aço', 'Golpeia à frente, causando dano a todos os inimigos em linha reta.Ao contato, Tempestade de Aço concede um acúmulo de Tempestade Crescente por alguns segundos. Com 2 acúmulos, Tempestade de Aço desfere um tornado que arremessa inimigos ao ar.Tempestade de Aço é tratada como ataque básico e escala com as mesmas coisas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YasuoQ1Wrapper.png'),
('YasuoR', 157, 'R', 'Último Suspiro', 'Teletransporta-se para um Campeão inimigo arremessado ao ar, causando Dano Físico e mantendo no ar todos os inimigos da área que foram arremessados ao ar. Concede o máximo de Fluxo, mas zera todos os acúmulos de Tempestade CrescentePor um período moderado a seguir, os Acertos Críticos de Yasuo recebem Penetração de Armadura adicional significativa.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YasuoR.png'),
('YasuoW', 157, 'W', 'Parede de Vento', 'Cria uma parede movediça que bloqueia todos os projéteis inimigos por 4 segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YasuoW.png'),
('Yasuo_P', 157, 'P', 'Estilo do Errante', 'A Chance de Acerto Crítico do Yasuo é aumentada. Além disso, Yasuo vai gerando um Escudo sempre que se movimenta. O Escudo é ativado quando Yasuo sofre dano de um Campeão ou monstro.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Yasuo_Passive.png'),
('YoneE', 158, 'E', 'Desatar da Alma', 'O espírito de Yone deixa seu corpo para trás e recebe Velocidade de Movimento. Quando essa habilidade termina, o espírito de Yone volta ao corpo e ele repete parte do dano causado na forma espiritual.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YoneE.png'),
('YoneQ', 158, 'Q', 'Aço Mortal', 'Golpeia à frente, causando dano a todos os inimigos em linha reta.Ao contato, ganha um acúmulo de Tempestade Crescente por alguns segundos. Com 2 acúmulos, Aço Mortal faz com que Yone avance com o vento, arremessando ao ar os inimigos.Aço Mortal é tratada como ataque básico e escala da mesma forma.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YoneQ.png'),
('YoneR', 158, 'R', 'Destino Selado', 'Yone teleporta-se para trás do último Campeão em uma linha, desferindo um golpe tão poderoso que puxa na direção dele todos os inimigos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YoneR.png'),
('YoneW', 158, 'W', 'Fenda Espiritual', 'Ataca à frente, causando dano a todos os inimigos em uma área de cone. Concede um escudo a Yone. O valor do escudo aumenta com base no número de Campeões atingidos pelo golpe.O Tempo de Recarga e o tempo de conjuração de Fenda Espiritual escalam com Velocidade de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YoneW.png'),
('Yone_P', 158, 'P', 'Estilo do Caçador', 'Yone causa Dano Mágico a cada segundo Ataque. Além disso, sua Chance de Acerto Crítico é aumentada.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/YonePassive.png'),
('YorickE', 159, 'E', 'Névoa dos Lamentos', 'Yorick arremessa um glóbulo de Névoa Negra que causa dano, redução de velocidade e marca inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YorickE.png'),
('YorickQ', 159, 'Q', 'Extrema-Unção', 'Yorick causa dano adicional em seu próximo ataque, além de curar a si mesmo. Se o alvo for abatido, uma cova será aberta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YorickQ.png'),
('YorickR', 159, 'R', 'Louvor das Ilhas', 'Yorick invoca a Donzela da Névoa, que faz com que seus ataques contra os alvos dela causem dano adicional. A Donzela também faz surgir Andarilhos automaticamente a partir de inimigos mortos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YorickR.png'),
('YorickW', 159, 'W', 'Procissão Sombria', 'Yorick invoca uma parede destrutível no local-alvo, que bloqueará a movimentação de inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YorickW.png'),
('Yorick_P', 159, 'P', 'Pastor de Almas', 'A Horda Maldita: Yorick pode invocar Andarilhos da Névoa e atacar inimigos próximos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Yorick_P.png'),
('YuumiE', 160, 'E', 'Frenética', 'Protege Yuumi com um Escudo e aumenta a Velocidade de Movimento e a Velocidade de Ataque. Se ela estiver conectada, isso afetará o aliado em vez dela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YuumiE.png'),
('YuumiQ', 160, 'Q', 'Projétil Errante', 'Yuumi dispara um projétil, causando dano e Lentidão ao primeiro alvo que atingir. O projétil causa dano adicional e a Lentidão é fortalecida se demorar pelo menos 1,35s para chegar até o alvo. Enquanto Yuumi estiver com o Melhor Amigo, a Lentidão sempre será fortalecida e a Campeã concederá dano adicional ao contato para o aliado.Enquanto ela estiver Conectada, o projétil poderá ser controlado pelo cursor do mouse por um breve período.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YuumiQ.png'),
('YuumiR', 160, 'R', 'Capítulo Final', 'Yuumi canaliza cinco ondas que causam dano a inimigos e curam aliados. Ela também pode se mover, se conectar e conjurar Frenética! durante a canalização. Enquanto estiver com o Melhor Amigo, esta Habilidade também seguirá o cursor do mouse.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YuumiR.png'),
('YuumiW', 160, 'W', 'Você e Eu!', 'Yuumi avança em direção a um aliado-alvo, tornando-se inalvejável por qualquer ataque, exceto de torres. Enquanto Conectada ao Melhor Amigo, ela recebe Resistência do Escudo e Cura, e concede cura ao contato para o aliado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/YuumiW.png'),
('Yuumi_P', 160, 'P', 'Amizade Felina', 'Periodicamente, quando Yuumi atinge um Campeão com um Ataque ou Habilidade, ela restaura Vida para si e para o próximo aliado a quem ela se Conectar.Enquanto Conectada, Yuumi cria um laço especial com os aliados. O aliado com o laço mais forte aprimora as Habilidades de Yuumi enquanto ela estiver Conectada a ele.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/YuumiP.png'),
('ZacE', 161, 'E', 'Estilingue Elástico', 'Zac segura o chão com seus braços e se estica para trás, lançando-se para frente.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZacE.png'),
('ZacQ', 161, 'Q', 'Esticada', 'Zac estica um braço, agarrando um inimigo. Atacar um inimigo diferente o fará arremessar ambos os alvos na direção um do outro.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZacQ.png'),
('ZacR', 161, 'R', 'Vamos pular!', 'Zac pula quatro vezes, arremessando inimigos atingidos ao ar e reduzindo a velocidade deles.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZacR.png'),
('ZacW', 161, 'W', 'Matéria Instável', 'Zac explode para fora em direção a inimigos próximos, causando um percentual de suas Vidas máximas como Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZacW.png'),
('Zac_P', 161, 'P', 'Divisão Celular', 'Sempre que Zac atinge um inimigo com uma habilidade, ele perde parte de si mesmo que pode ser reabsorvida para restaurar Vida. Ao receber dano letal, Zac divide-se em 4 pedaços que tentam se recombinar. Se qualquer pedaço permanecer, ele ressuscitará uma quantia de Vida, dependendo da vida dos pedaços sobreviventes. Cada pedaço tem um percentual da Vida máxima de Zac, de sua Armadura e de Resistência Mágica. Essa habilidade tem 5 minutos de Tempo de Recarga.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/ZacPassive.png'),
('ZedE', 162, 'E', 'Corte Sombrio', 'Zed e as Sombras dele atacam, causando dano a inimigos próximos. Inimigos atingidos pelo corte de uma Sombra sofrem Lentidão.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZedE.png'),
('ZedQ', 162, 'Q', 'Shuriken Laminado', 'Zed e suas sombras arremessam seus shurikens.Cada shuriken causa dano em todos os inimigos atingidos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZedQ.png'),
('ZedR', 162, 'R', 'Marca Fatal', 'Zed se torna inalvejável e avança contra um Campeão inimigo para marcá-lo. Após 3 segundos, a marca é ativada, repetindo parte de todo o dano que Zed causou ao alvo enquanto ele estava marcado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZedR.png'),
('ZedW', 162, 'W', 'Sombra Viva', 'Efeito passivo: Zed recebe energia sempre que ele e suas sombras atingem um inimigo com a mesma habilidade. A energia só pode ser recebida uma vez a cada conjuração de habilidade.Ativo: A sombra de Zed avança e fica no mesmo lugar por alguns segundos. Quando Sombra Viva é reativada, Zed troca de posição com sua sombra.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZedW.png'),
('Zed_P', 162, 'P', 'Desprezo pelos Fracos', 'Os ataques básicos de Zed contra alvos com pouca Vida causam Dano Mágico adicional. Esse efeito pode ocorrer contra o mesmo Campeão inimigo apenas uma vez a cada poucos segundos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/ZedP.png'),
('ZeriE', 163, 'E', 'Faísca Acelerada', 'Zeri avança por uma curta distância e energiza os próximos 3 disparos de Rajada Reluzente, fazendo com que atravessem os inimigos. Ela pode saltar e deslizar por qualquer terreno que tocar.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZeriE.png'),
('ZeriQ', 163, 'Q', 'Rajada Reluzente', 'Rajada Reluzente dispara 7 projéteis que causam Dano de Ataque ao primeiro inimigo atingido. Esta Habilidade é considerada um Ataque.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZeriQ.png'),
('ZeriR', 163, 'R', 'Impacto Eletrizante', 'Zeri descarrega uma grande explosão elétrica e se sobrecarrega, recebendo dano aumentado e Velocidade de Movimento cumulativa que se redefine e aumenta sempre que atinge um Campeão inimigo. Durante esse período, Rajada Reluzente se transforma em um disparo triplo mais rápido que faz ricochetear relâmpagos entre os inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZeriR.png'),
('ZeriW', 163, 'W', 'Laser de Ultrachoque', 'Zeri dispara um pulso elétrico que causa dano e Lentidão ao primeiro inimigo atingido. Se o pulso atingir uma parede, ele se transforma em um laser de longo alcance.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZeriW.png'),
('Zeri_P', 163, 'P', 'Bateria Viva', 'Os Ataques de Zeri causam Dano Mágico e são considerados Habilidades. Mover-se e conjurar Rajada Reluzente armazena energia na Eletrobolsa. Quando estiver totalmente carregada, o próximo Ataque da Campeã causará dano adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/ZeriP.png'),
('ZiggsE', 164, 'E', 'Campo Minado de Hexplosivos', 'Ziggs espalha minas de proximidade que detonam ao contato com inimigos, causando Dano Mágico e redução de velocidade. Várias detonações de minas no mesmo alvo causam dano reduzido.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZiggsE.png'),
('ZiggsQ', 164, 'Q', 'Bomba Saltitante', 'Ziggs arremessa uma bomba que causa Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZiggsQ.png'),
('ZiggsR', 164, 'R', 'Bomba Megainfernal', 'Ziggs põe para funcionar sua maior criação, a Bomba Megainfernal, arremessando-a de uma enorme distância. Inimigos no centro da detonação recebem mais dano do que aqueles mais distantes.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZiggsR.png'),
('ZiggsW', 164, 'W', 'Carga Concentrada', 'Ziggs arremessa uma carga explosiva que detona depois de 4s ou quando a habilidade é ativada novamente. A explosão causa Dano Mágico a inimigos, arremessando-os para longe. Ziggs também é empurrado, mas não recebe dano, além de poder usar Carga para Hexplodir torres inimigas vulneráveis.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZiggsW.png'),
('Ziggs_P', 164, 'P', 'Pavio Curto', 'Periodicamente, o próximo ataque básico de Ziggs causa Dano Mágico adicional. Esse Tempo de Recarga é reduzido sempre que Ziggs usa uma habilidade.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/ZiggsPassiveReady.png'),
('ZileanQ', 165, 'Q', 'Bomba-relógio', 'Arremessa uma bomba no local-alvo, que gruda em unidades que se aproximarem (priorizando Campeões). Ela detona após 3 segundos, causando dano em área. Se uma Bomba-relógio for detonada antecipadamente por outra, o efeito também atordoa inimigos.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZileanQ.png'),
('ZileanW', 165, 'W', 'Retroceder', 'Zilean pode se preparar para confrontos futuros, reduzindo o Tempo de Recarga de suas outras habilidades básicas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZileanW.png'),
('Zilean_P', 165, 'P', 'Tempo Engarrafado', 'Zilean armazena tempo como Experiência, podendo concedê-la aos aliados. Quando tiver Experiência o suficiente para completar o nível de um aliado, Zilean pode clicar com o botão direito nele para conceder os pontos. Zilean recebe a mesma quantidade de Experiência que concede.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Zilean_Passive.png'),
('ZoeE', 166, 'E', 'Bolha do Soninho', 'Faz com que o alvo fique sonolento e depois adormeça. Enquanto estiver adormecido, a Resistência Mágica do alvo é reduzida. A primeira fonte de dano que interromper o sono é dobrada, até determinado limite.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZoeE.png'),
('ZoeQ', 166, 'Q', 'Estrela Desviada!', 'Zoe dispara um projétil que pode ser redirecionado durante o percurso. Causa mais dano quanto maior for a distância percorrida em linha reta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZoeQ.png'),
('ZoeR', 166, 'R', 'Salto Dimensional', 'Teleporta-se para uma posição próxima por 1s, depois se teleporta de volta.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZoeR.png'),
('ZoeW', 166, 'W', 'Roubo Arcano', 'Zoe pode apanhar os vestígios das conjurações de Feitiço de Invocador ou de itens ativos do inimigo para que ela mesma os conjure. Sempre que ela conjura um Feitiço de Invocador, ela ganha 3 projéteis que são disparados contra o alvo mais próximo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZoeW.png'),
('Zoe_P', 166, 'P', 'Brililim!', 'O próximo ataque básico após Zoe conjurar uma habilidade causa Dano Mágico adicional.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/Zoe_P.png'),
('ZyraE', 167, 'E', 'Pântano das Raízes', 'Zyra lança vinhas pelo chão para prenderem seu alvo, causando dano e enraizando inimigos atingidos. Se conjurada próxima a uma semente, Pântano das Raízes faz surgir Vinhas Ásperas com ataques de curta distância que reduzem a Velocidade de Movimento do inimigo.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZyraE.png'),
('ZyraQ', 167, 'Q', 'Farpas Mortais', 'Vinhas espessas se espalham pelo chão e explodem em farpas, causando Dano Mágico a inimigos dentro da área. Se conjurada perto de uma semente, Farpas Mortais faz surgir uma planta Cospe-Espinhos, que dispara contra inimigos distantes.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZyraQ.png'),
('ZyraR', 167, 'R', 'Espinhos Sufocantes', 'Zyra invoca raízes retorcidas no local-alvo, causando dano a inimigos conforme elas se expandem e arremessando-os ao ar quando se contraem. Plantas ao alcance das raízes ficam enfurecidas.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZyraR.png'),
('ZyraW', 167, 'W', 'Crescimento Desenfreado', 'Zyra planta uma semente com duração de 60s. Conjurar Farpas Mortais e Pântano das Raízes perto das sementes fará surgir plantas que lutam por Zyra. Zyra pode armazenar várias sementes ao mesmo tempo, e abater inimigos reduz o tempo de recarga de Crescimento Desenfreado.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/spell/ZyraW.png'),
('Zyra_P', 167, 'P', 'Jardim de Espinhos', 'Sementes surgem periodicamente ao redor de Zyra, mais rapidamente dependendo do nível. Zyra pode conjurar Farpas Mortais ou Pântano das Raízes próximo a sementes para fazer surgir plantas que lutarão por ela.', 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/passive/ZyraP.png');
INSERT INTO `itens` (`ID_riot`, `nome`, `descricao`, `preco`, `imagem_url`) VALUES
(1001, 'Botas', '25 de Velocidade de Movimento', 300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1001.png'),
(1004, 'Amuleto da Fada', '50% de Regeneração de Mana base', 250, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1004.png'),
(1006, 'Pérola do Rejuvenescimento', '100% de Regeneração de Vida base', 300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1006.png'),
(1011, 'Cinto do Gigante', '350 de Vida', 900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1011.png'),
(1018, 'Capa da Agilidade', '15% de Chance de Acerto Crítico', 600, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1018.png'),
(1026, 'Varinha Explosiva', '45 de Poder de Habilidade', 850, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1026.png'),
(1027, 'Cristal de Safira', '250 de Mana', 350, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1027.png'),
(1028, 'Cristal de Rubi', '150 de Vida', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1028.png'),
(1029, 'Couraça de Pano', '15 de Armadura', 300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1029.png'),
(1031, 'Cota de Malha', '40 de Armadura', 800, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1031.png'),
(1033, 'Manto Anula-Magia', '25 de Resistência Mágica', 450, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1033.png'),
(1035, 'Lâmina Cálida', 'Cauterizar: causar dano a monstros os queima ao longo do tempo.Caminho Desafiador: usar Golpear 5 vezes consome este item, aprimora Golpear para Golpe Desafiador e aumenta o dano causado a monstros. Golpe Desafiador marca Campeões. Durante esse período, você causa Dano Verdadeiro adicional ao contato e sofre dano reduzido do alvo.Caçador: abater monstros grandes concede experiência adicional.Restauração: regenera Mana enquanto estiver na selva ou no rio. Consumir este item concede todos os efeitos dele permanentemente e aumenta o dano causado a monstros por Golpear. Ao ganhar mais ouro de tropas do que de monstros, o ouro e a experiência de tropas são reduzidos drasticamente. Cura não reduzida em Ataques em área. Se o Campeão estiver 2 níveis abaixo do nível médio da partida, abater monstros concederá EXP adicional. Apenas Ataques e Habilidades aplicam a queima do Golpe Desafiador.', 350, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1035.png'),
(1036, 'Espada Longa', '10 de Dano de Ataque', 350, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1036.png'),
(1037, 'Picareta', '25 de Dano de Ataque', 875, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1037.png'),
(1038, 'Espada G. p. C.', '40 de Dano de Ataque', 1300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1038.png'),
(1039, 'Lâmina Álgida', 'Cauterizar: causar dano a monstros os queima ao longo do tempo.Caminho Congelante: usar Golpear 5 vezes consome este item, aprimora Golpear para Golpe Congelante e aumenta o dano causado a monstros. Ao Golpear Campeões, Golpe Congelante causa Dano Verdadeiro e rouba a Velocidade de Movimento do alvo.Caçador: abater monstros grandes concede experiência adicional.Restauração: regenera Mana enquanto estiver na selva ou no rio. Consumir este item concede todos os efeitos dele permanentemente e aumenta o dano causado a monstros por Golpear. Ao ganhar mais ouro de tropas do que de monstros, o ouro e a experiência de tropas são reduzidos drasticamente. Cura não reduzida em Ataques em área. Se o Campeão estiver 2 níveis abaixo do nível médio da partida, abater monstros concederá EXP adicional. ', 350, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1039.png'),
(1040, 'Lâmina de Obsidiana', 'Cauterizar: causar dano a monstros os queima ao longo do tempo.Caminho Automático: usar Golpear 5 vezes consome este item e aprimora Atacar-Golpear, aumentando o dano causado a monstros.Caçador: abater monstros grandes concede experiência adicional.Restauração: regenera Mana enquanto estiver na selva ou no rio. Consumir este item concede todos os efeitos dele permanentemente e aumenta o dano causado a monstros por Golpear. Ao ganhar mais ouro de tropas do que de monstros, o ouro e a experiência de tropas são reduzidos drasticamente. Cura não reduzida em Ataques em área. Se o Campeão estiver 2 níveis abaixo do nível médio da partida, abater monstros concederá EXP adicional. ', 350, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1040.png'),
(1042, 'Adaga', '12% de Velocidade de Ataque', 300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1042.png'),
(1043, 'Arco Recurvo', '15% de Velocidade de AtaqueAtaques causam Dano Mágico adicional ao contato.', 700, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/1043.png'),
