(2003, 'Poção de Vida', 'Ativo – Consumir: Beba a poção para restaurar 120 de Vida ao longo de 15s.Você pode levar consigo até 5 unidades de Poções de Vida.', 50, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2003.png'),
(2010, 'Biscoito Total da Determinação Eterna', 'Ativo – Consumir: Coma o biscoito para restaurar 8% da Vida e do Mana perdidos ao longo de 5s. Consumir ou vender um biscoito concede 40 de Mana máximo permanentemente. ', 50, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2010.png'),
(2015, 'Estilhaço de Kircheis', '15 de Dano de AtaqueChoqueAtaques Energizados causam 50 de Dano Mágico adicional.', 700, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2015.png'),
(2019, 'Sigilo de Aço', '15 de Dano de Ataque30 de Armadura', 1100, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2019.png'),
(2020, 'Brutalizador', '25 de Dano de Ataque10 de Aceleração de Habilidade5 de Letalidade', 1337, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2020.png'),
(2021, 'Tunelizador', '15 de Dano de Ataque250 de Vida', 1150, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2021.png'),
(2022, 'Partícula Brilhante', '5 de Aceleração de Habilidade', 250, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2022.png'),
(2031, 'Poção com Refil', 'Ativo – Consumir: Consome uma carga para restaurar 100 de Vida ao longo de 12s. Armazena até 2 cargas que são recarregadas ao visitar a loja.', 150, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2031.png'),
(2033, 'Poção Corrupta', 'Ativo – Consumir: Consome uma carga para restaurar 100 de Vida e 75 de Mana ao longo de 12s. Durante esse período, Ataques e Habilidades de dano queimam Campeões inimigos, causando 15 (20 se você não puder ganhar Mana) de Dano Mágico ao longo de 3s. Armazena até 3 cargas que são repostas ao visitar a loja.O dano de Corrupção é reduzido para 50% ao ser ativado por habilidades de área de ação ou de dano periódico.', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2033.png'),
(2049, 'Amuleto do Guardião', '20% de Cura e Resistência do Escudo20 de Poder de Habilidade20 de Aceleração de HabilidadeRecuperaçãoRestaura 10 de Mana a cada 5s. Caso você não possa receber Mana, restaura 0.6 de Vida.', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2049.png'),
(2050, 'Proteção do Guardião', '350 de Vida35 de Poder de Habilidade15 de Aceleração de Habilidade', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2050.png'),
(2051, 'Berrante do Guardião', '150 de VidaRecuperação: restaura Vida ao longo do tempo.Impassível: bloqueia o dano sofrido de Ataques e Habilidades de Campeões.Lendário: este item conta como um item Lendário.', 950, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2051.png'),
(2052, 'Poritos', 'Esta saborosa mistura de galinhas caipiras criadas nos pastos de Avarosa e ervas orgânicas e livres de transgênicos de Freljord contém os nutrientes necessários para fazer o seu Poro ronronar de felicidade.Toda a arrecadação será doada no combate à crueldade contra animais de Noxus. Ativo – Consumir: Serve uma porção generosa a um Poro próximo, fazendo com que ele aumente de tamanho.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2052.png'),
(2055, 'Sentinela de Controle', 'Ativo – Consumir: Posiciona uma poderosa Sentinela de Controle que concede visão da área ao redor. Esse dispositivo também revela armadilhas Invisíveis e inimigos Camuflados, além de revelar e desabilitar Sentinelas Invisíveis inimigas.Você pode levar consigo até 2 Sentinelas de Controle. Sentinelas de Controle não são desabilitadas por outras Sentinelas de Controle.', 75, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2055.png'),
(2056, 'Sentinela Invisível', 'Ativo – Consumir: Posiciona uma Sentinela Invisível no chão que dura 60s. Ela permanece Invisível para os inimigos e concede visão da área ao redor à sua equipe. ', 40, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2056.png'),
(2065, 'Hino Bélico de Shurelya', '55 de Poder de Habilidade15 de Aceleração de Habilidade8% de Velocidade de Movimento125% de Regeneração de Mana baseATIVOS (0s)Discurso InspiradorConcede Velocidade de Movimento aos aliados próximos.', 2200, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2065.png'),
(2138, 'Elixir de Ferro', 'Ativo – Consumir: Beba para receber 300 de Vida, 25% de Tenacidade e aumentar o tamanho do Campeão por 3min. Enquanto ativo, movimentar-se deixa um rastro atrás de você que aumenta a Velocidade de Movimento dos Campeões aliados em 15%.Beber um elixir diferente substituirá os efeitos do atual', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2138.png'),
(2139, 'Elixir da Feitiçaria', 'O Campeão precisa chegar pelo menos ao nível 9 para comprar esse item. O efeito de Dano Verdadeiro do Elixir da Feitiçaria não tem Tempo de Recarga ao atacar torres. Beber um elixir diferente substituirá os efeitos do atual.Ativo – Consumir: Beba para receber 50 de Poder de Habilidade e 15% de Regeneração de Mana por 3min. Enquanto ativo, causar dano a um Campeão ou torre causa 25 de Dano Verdadeiro adicional (5s de Tempo de Recarga).', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2139.png'),
(2140, 'Elixir da Ira', 'Ativo – Consumir: Beba para receber 30 de Dano de Ataque e 12% de Vampirismo Físico (contra Campeões) por 3min.Beber um elixir diferente substituirá os efeitos do atual.', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2140.png'),
(2141, 'Suco de Chapéu', 'Faz bem pra cabeça.Ativo – Consumir: Este suco não faz nada.', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2141.png'),
(2142, 'Suco de Poder', 'Os sucos não acumulam, mas você pode ter vários diferentes ativados.Ativo – Consumir: Ativa automaticamente no início do combate. Beba para receber 30+ 10% de Poder de Habilidade adicional ou 18+ 10% de Dano de Ataque adicional pela próxima rodada.Feito 100% de cerejas. Cuidado: pode viciar em causar toneladas de dano.', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2142.png'),
(2143, 'Suco de Vigor', 'Os sucos não acumulam, mas você pode ter vários diferentes ativados.Ativo – Consumir: Ativa automaticamente no início do combate. Beba para receber 300+ 10% de Vida pela próxima rodada.Nossa mistura especial de vegetais é capaz de endurecer sua pele para resistir até aos ataques mais fortes!', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2143.png'),
(2144, 'Suco de Aceleração', 'Os sucos não acumulam, mas você pode ter vários diferentes ativados.Ativo – Consumir: Ativa automaticamente no início do combate. Beba para receber 20+ 15% de Aceleração de Habilidade pela próxima rodada.Para quem gosta de ir RÁPIDO. Feito com relâmpago. Relâmpago DE VERDADE!', 500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2144.png'),
(2145, 'Dado da Sorte', 'Ativo – Consumir: Atualize para ganhar uma atualização adicional.Vender este item ou usar todas as suas atualizações irá consumi-lo automaticamente.Serve para casos em que só habilidade não é o bastante.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2145.png'),
(2150, 'Elixir da Habilidade', 'Ativo – Consumir: Concede 1 Ponto de Habilidade.Este item não aumenta seu nível ou permite realocar Pontos de Habilidade além do valor máximo normal.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2150.png'),
(2151, 'Elixir da Avareza', 'Ativo – Consumir: Beba para receber 5 de Dano Verdadeiro ao contato contra tropas por 60s. Quando o efeito expirar, receba 40 de ouro. ', 50, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2151.png'),
(2152, 'Elixir da Força', 'Ativo – Consumir: Beba para receber 20 de Força Adaptativa por 60s. ', 50, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2152.png'),
(2403, 'Pulverizador de Tropas', 'Ativo – Consumir: Abate a tropa-alvo. (0s)', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2403.png'),
(2419, 'Cronômetro Inicial', 'Transforma-se em um Cronômetro depois de 14min. Eliminações reduzem esse tempo em 2min. Esse Cronômetro contribui com 250 de ouro para os itens no qual pode se transformar.O Cronômetro normalmente contribui com 750 de ouro.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2419.png'),
(2420, 'Armaguarda da Caçadora', '45 de Poder de Habilidade25 de ArmaduraATIVOSTempo Paralisado (Uso único)Entra em Estase por 2.5s.', 1600, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2420.png'),
(2421, 'Armaguarda Despedaçada', '45 de Poder de Habilidade25 de ArmaduraTempo EstilhaçadoA Armaguarda está quebrada, mas ainda pode ser aprimorada.Após quebrar uma Armaguarda, a loja venderá apenas Armaguarda Despedaçada.', 1600, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2421.png'),
(2422, 'Botas Levemente Mágicas', '25 de Velocidade de MovimentoConcede 10 de Velocidade de Movimento adicional. Botas feitas com as Botas Levemente Mágicas mantêm a Velocidade de Movimento adicional.', 300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2422.png'),
(2423, 'Cronômetro Perfeitamente Calculado', '45 de Poder de Habilidade25 de ArmaduraATIVOSTempo Paralisado (Uso único)Entra em Estase por 2.5s.', 1600, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2423.png'),
(2502, 'Desespero Eterno', '400 de Vida55 de Armadura10 de Aceleração de HabilidadeAngústiaEnquanto estiver em combate contra Campeões, a cada poucos segundos, causa Dano Mágico a Campeões inimigos próximos, curando com base no dano causado.', 2800, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2502.png'),
(2504, 'Rookern Lamúrico', '400 de Vida80 de Resistência Mágica150% de Regeneração de Vida basePerdição dos MagosDepois de não sofrer Dano Mágico por 15s, recebe 0 de Escudo Mágico. ', 2900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/2504.png'),
(3001, 'Proteção Imutável', '200 de Vida30 de Armadura30 de Resistência Mágica20 de Aceleração de HabilidadeOfuscante: depois de Imobilizar Campeões ou de ser Imobilizado, faz com que o alvo e todos os Campeões inimigos próximos sofram dano aumentado.Passivo Mítico: concede a todos os outros itens Lendários  de Armadura e de Resistência Mágica', 2300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3001.png'),
(3002, 'Desbravador', '200 de Vida40 de Armadura5% de Velocidade de MovimentoLiderançaRecebe 20 de Velocidade de Movimento adicional enquanto se move. Com o máximo de velocidade, cria uma trilha que aumenta a Velocidade de Movimento de Campeões aliados em 15% da sua. Seu próximo Ataque descarrega a Velocidade de Movimento adicional, e Campeões corpo a corpo causam 50% de Lentidão ao alvo por 1s.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3002.png'),
(3003, 'Cajado do Arcanjo', '80 de Poder de Habilidade600 de Mana25 de Aceleração de HabilidadeFascínioRecebe Poder de Habilidade igual ao seu Mana adicional.Fluxo de ManaAtinja um alvo com uma Habilidade para consumir uma carga e receber Mana adicional. Este item se transformará em Abraço de Seraph após conceder um máximo de 360 de Mana.', 2900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3003.png'),
(3004, 'Manamune', '35 de Dano de Ataque500 de Mana15 de Aceleração de HabilidadeFascínioRecebe Dano de Ataque adicional com base no Mana.Fluxo de ManaAtinja um alvo com uma Habilidade ou Ataque para receber Mana adicional. Este item se transformará em Muramana após conceder um máximo de Mana.', 2900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3004.png'),
(3005, 'Ghostcrawlers', '45 de Velocidade de MovimentoAtivo – Atravessar Paredes: recebe a habilidade de atravessar paredes por 6s. Enquanto estiver dentro de paredes, recebe 125 de Velocidade de Movimento. Conjurar uma Habilidade ou atacar encerrará este efeito (0s).', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3005.png'),
(3006, 'Grevas do Berserker', '35% de Velocidade de Ataque45 de Velocidade de Movimento', 1100, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3006.png'),
(3009, 'Botas da Rapidez', '60 de Velocidade de MovimentoA força dos efeitos de Lentidão é reduzida em 25%.', 900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3009.png'),
(3011, 'Putrificador Quimtec', '35 de Poder de Habilidade10% de Cura e Resistência do Escudo75% de Regeneração de Mana base15 de Aceleração de HabilidadeToxina de Cogumelo: causar dano aplica 40% de Feridas Dolorosas aos Campeões por 3s.Feridas Dolorosas reduz a eficácia de efeitos de cura e Regeneração.', 2100, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3011.png'),
(3012, 'Cálice da Bênção', '200 de Vida50% de Regeneração de Mana baseHarmonia: recebe 25% de Regeneração de Vida base para cada 25% de Regeneração de Mana base.\'\'Essas águas abençoadas ainda carregam poder para os dignos.\'\'', 950, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3012.png'),
(3020, 'Sapatos do Feiticeiro', '18 de Penetração Mágica45 de Velocidade de Movimento', 1100, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3020.png'),
(3023, 'Pingente da Vida Abundante', '150 de Vida25 de Armadura5 de Aceleração de Habilidade\'\'Estiloso e funcional.\'\'', 1050, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3023.png'),
(3024, 'Broquel Glacial', '20 de Armadura250 de Mana10 de Aceleração de Habilidade', 950, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3024.png'),
(3026, 'Anjo Guardião', '55 de Dano de Ataque45 de ArmaduraRenascimentoAo sofrer dano letal, ressuscita após um breve intervalo.', 3200, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3026.png'),
(3031, 'Gume do Infinito', '65 de Dano de Ataque20% de Chance de Acerto Crítico50% de Dano de Acerto Crítico', 3300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3031.png'),
(3033, 'Lembrete Mortal', '40 de Dano de Ataque35% de Penetração de Armadura20% de Chance de Acerto CríticoFeridas DolorosasCausar Dano Físico aplica 40% de Feridas Dolorosas a Campeões inimigos por 3s.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3033.png'),
