(3161, 'Lança de Shojin', '55 de Dano de Ataque300 de Vida20 de Aceleração de HabilidadeForça Dracônica Suas Habilidades, exceto a ultimate, recebem Aceleração de Habilidade.Determinação Concentrada Acertar Habilidades concede acúmulos. Suas Habilidades causam dano aumentado para cada acúmulo.', 3100, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3161.png'),
(3165, 'Morellonomicon', '90 de Poder de Habilidade15 de Aceleração de HabilidadeFeridas DolorosasCausar Dano Mágico aplica 40% de Feridas Dolorosas a Campeões inimigos por 3s.', 2200, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3165.png'),
(3172, 'Zéfiro', '50 de Dano de Ataque40% de Velocidade de Ataque10% de Velocidade de Movimento35% de TenacidadeTenacidade reduz a duração de Atordoamento, Lentidão, Provocação, Temor, Silenciamento, Cegueira, Polimorfia e efeitos Imobilizadores. Não afeta Arremesso ao ar e Supressão.', 2800, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3172.png'),
(3177, 'Lâmina do Guardião', '30 de Dano de Ataque150 de Vida15 de Aceleração de HabilidadeLendário: este item conta como um item Lendário.', 950, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3177.png'),
(3179, 'Glaive Sombria', '50 de Dano de Ataque15 de Letalidade15 de Aceleração de HabilidadeBlecauteRevela armadilhas e desarma sentinelas ao seu redor. Seus Ataques causam dano aumentado a Sentinelas.', 2600, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3179.png'),
(3181, 'Quebracascos', '65 de Dano de Ataque350 de Vida5% de Velocidade de MovimentoMarujoTodo quinto Ataque contra Campeões e monstros épicos causa Dano Físico adicional, aumentado contra estruturas.Invasão PirataTropas de cerco e supertropas aliadas próximas recebem Armadura e Resistência Mágica. ', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3181.png'),
(3184, 'Martelo do Guardião', '25 de Dano de Ataque150 de Vida7% de Roubo de VidaLendário: este item conta como um item Lendário.', 950, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3184.png'),
(3190, 'Medalhão dos Solari de Ferro', '200 de Vida30 de Armadura30 de Resistência Mágica10 de Aceleração de HabilidadeAtivo –DevoçãoConcede aos aliados próximos um Escudo, decaindo ao longo do tempo.', 2200, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3190.png'),
(3193, 'Placa Gargolítica', '60 de Armadura60 de Resistência Mágica15 de Aceleração de HabilidadeFortificar: sofrer dano de um Campeão concede um acúmulo de Armadura e Resistência Mágica adicionais.Máximo de 5 acúmulos, 1 por Campeão.Ativo – Inquebrável: recebe um Escudo que decai e cresce em tamanho.', 3200, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3193.png'),
(3211, 'Capuz do Espectro', '200 de Vida25 de Resistência Mágica100% de Regeneração de Vida base', 1250, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3211.png'),
(3222, 'Bênção de Mikael', '250 de Vida100% de Regeneração de Mana base12% de Cura e Resistência do Escudo15 de Aceleração de HabilidadeATIVOSPurificar(0s)Remove todos os efeitos de Controle de Grupo de um Campeão aliado e restaura Vida.', 2300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3222.png'),
(3302, 'Terminus', '40 de Dano de Ataque30% de Velocidade de AtaqueSombraAtaques aplicam Dano Mágico ao contato.JustaposiçãoAlterna entre Luz e Sombra ao contato ao atacar Campeões: ataques de Luz concedem Armadura e Resistência Mágica.Ataques de Sombra concedem Penetração de Armadura e Penetração Mágica.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3302.png'),
(3330, 'Efígie do Espantalho', 'Ativo – Amuleto: Posiciona uma efígie que aparece exatamente como Fiddlesticks para os inimigos. Armazena até 2 cargas.A efígie será ativada quando Campeões inimigos se aproximarem, simulando uma ação aleatória. Depois disso, ela se destruirá.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3330.png'),
(3340, 'Sentinela Invisível', 'Ativo – Amuleto: Posiciona uma Sentinela Invisível no chão. Ela permanece Invisível para os inimigos e concede visão da área ao redor à sua equipe. Armazena até 2 Sentinelas Invisíveis.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3340.png'),
(3348, 'Analisador Arcano', 'Ativo ÚNICO – Visão do Caçador: uma névoa arcana que concede visão da área-alvo por 5s, revelando Campeões inimigos e concedendo Visão Mágica das armadilhas na área por 3s (30s de Tempo de Recarga).', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3348.png'),
(3349, 'Singularidade Lucente', 'Singularidade Lucente', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3349.png');
INSERT INTO `itens` (`ID_riot`, `nome`, `descricao`, `preco`, `imagem_url`) VALUES
(3363, 'Alteração Vidente', 'Ativo – Amuleto: Posiciona uma Sentinela frágil e visível em até 4000 unidades de distância.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3363.png'),
(3364, 'Lente do Oráculo', 'Ativo – Amuleto: Realiza uma varredura ao seu redor, alertando caso haja unidades inimigas ocultas por perto, mostrando armadilhas invisíveis e revelando/desarmando temporariamente as Sentinelas Invisíveis próximas. Tem 2 recargas.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3364.png'),
(3400, 'Sua Parte', 'Ativo – Consumir: Recebe 0 de ouro.Ouro adicional concedido a aliados quando Pyke abater um Campeão inimigo utilizando a ultimate. Se nenhum aliado participar do abate, Pyke fica com a Parte para si mesmo!', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3400.png'),
(3430, 'Ritual da Ruína', '50 de Poder de Habilidade15 de Aceleração de Habilidade20% de Chance de Acerto CríticoIra e RuínaAo conjurar uma Habilidade, recebe 2.5% de Chance de Acerto Crítico por 6s, acumulando até 20%.Recuperando os DestroçosSuas Habilidades têm chance equivalente à sua Chance de Acerto Crítico de conceder a você ou ao aliado-alvo um Escudo de 0 por 3s.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3430.png'),
(3504, 'Turíbulo Ardente', '50 de Poder de Habilidade8% de Cura e Resistência do Escudo125% de Regeneração de Mana base8% de Velocidade de MovimentoSantificarCurar ou conceder Escudo a um aliado fortalece vocês dois por 6s, concedendo 25% de Velocidade de Ataque e 20 de Dano Mágico ao contato.', 2300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3504.png'),
(3508, 'Colhedor de Essência', '60 de Dano de Ataque20% de Chance de Acerto Crítico20 de Aceleração de HabilidadeLâmina ArcanaDepois de usar uma Habilidade, seu próximo Ataque causa dano adicional e restaura Mana.', 2900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3508.png'),
(3513, 'Olho do Arauto', 'Ativo – Consumir: Esmaga o Olho do Arauto, iniciando o ritual para invocar o Arauto do Vale. Você pode clicar no Arauto do Vale depois que ele for invocado para controlar a investida. Esse efeito de controle pode ser realizado uma vez ao ser invocado e mais uma vez sempre que uma estrutura inimiga próxima for destruída.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3513.png'),
(3599, 'Lança Negra da Kalista', 'Ativo – Consumir: Vincula-se a um aliado até o fim da partida, o que os torna aliados em Juramento. O Juramento fortalece tanto você quanto o aliado quando estiverem próximos.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3599.png'),
(3600, 'Lança Negra da Kalista', 'Ativo – Consumir: Vincula-se a um aliado até o fim da partida, o que os torna aliados em Juramento. O Juramento fortalece tanto você quanto o aliado quando estiverem próximos.Necessária para utilizar a ultimate da Kalista.', 0, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3600.png'),
(3742, 'Couraça do Defunto', '300 de Vida45 de Armadura5% de Velocidade de MovimentoNaufrágioEnquanto estiver se movendo, acumula Velocidade de Movimento adicional. Seu próximo Ataque descarrega a Velocidade de Movimento acumulada para causar Dano Físico.InafundávelA força dos efeitos de Lentidão é reduzida.', 2900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3742.png'),
(3748, 'Hidra Titânica', '50 de Dano de Ataque550 de VidaFendaAtaques causam 0 de Dano Físico adicional ao contato e 0 de Dano Físico aos inimigos atrás do alvo.ATIVOSCrescente TitânicaNo seu próximo ataque, Fenda causará Dano Físico adicional ao alvo e em uma onda de choque próxima.', 3300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3748.png'),
(3801, 'Braçadeira Cristalina', '200 de Vida100% de Regeneração de Vida base', 800, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3801.png'),
(3802, 'Capítulo Perdido', '40 de Poder de Habilidade300 de Mana10 de Aceleração de HabilidadeIluminarAo subir de nível, restaura 20% do Mana máximo ao longo de 3s.', 1200, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3802.png'),
(3803, 'Catalisador das Eras', '350 de Vida300 de ManaEternidadeSofrer dano de Campeões restaura Mana. Conjurar uma habilidade cura ao longo do tempo.', 1300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3803.png'),
(3814, 'Limiar da Noite', '50 de Dano de Ataque15 de Letalidade250 de VidaAnularRecebe um Escudo de Feitiço.', 2800, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3814.png'),
(3850, 'Gume do Ladrão Arcano', '10 de Poder de Habilidade25 de Vida25% de Regeneração de Mana base2 de ouro a cada 10sTributo: enquanto estiver perto de um Campeão aliado, Ataques e Habilidades de dano contra Campeões ou estruturas concedem 20 de ouro. Isso pode ocorrer até 3 vezes a cada 36s.Missão: consiga 500 de ouro com esse item para transformá-lo em Presas Gélidas, recebendo Ativo – Vigilante.Se qualquer pessoa na sua equipe com este item já tiver abatido muitas tropas, ele concederá menos ouro proveniente delas.', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3850.png'),
(3851, 'Presas Gélidas', '15 de Poder de Habilidade70 de Vida50% de Regeneração de Mana base3 de ouro a cada 10sAtivo – Sentinela: posiciona uma Sentinela Invisível no chão. Ela permanece Invisível para os inimigos e concede visão da área ao redor à sua equipe. Armazena até 3 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. Tributo: enquanto estiver perto de um Campeão aliado, Ataques e Habilidades de dano contra Campeões ou estruturas concedem 20 de ouro. Isso pode ocorrer até 3 vezes a cada 30s.Missão: consiga 1000 de ouro com esse item para transformá-lo em Estilhaço de Gelo Verdadeiro.ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3851.png'),
(3853, 'Estilhaço de Gelo Verdadeiro', '40 de Poder de Habilidade75 de Vida100% de Regeneração de Mana base3 de ouro a cada 10sAtivo – Sentinela: posiciona uma Sentinela Invisível no chão. Ela permanece Invisível para os inimigos e concede visão da área ao redor à sua equipe. Armazena até 4 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3853.png'),
(3854, 'Guarda-ombros de Aço', '4 de Dano de Ataque50 de Vida50% de Regeneração de Vida base2 de ouro a cada 10sDespojos de Guerra: enquanto estiver perto de um Campeão aliado, Ataques executam tropas com menos de 50% da Vida máxima (usuários de ataque corpo a corpo) | 30% da Vida máxima (usuários de ataque à distância). Abater uma tropa concede o mesmo ouro do abate ao Campeão aliado mais próximo. Esses efeitos recarregam a cada 35s (máximo de 3 cargas).Missão: consiga 500 de ouro com esse item para transformá-lo em Espaldeiras de Aço Rúnico, recebendo Ativo – Vigilante.Se qualquer pessoa na sua equipe com este item já tiver abatido muitas tropas, ele concederá menos ouro proveniente delas.', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3854.png'),
(3855, 'Espaldeiras de Aço Rúnico', '6 de Dano de Ataque100 de Vida75% de Regeneração de Vida base3 de ouro a cada 10sAtivo – Sentinela: posiciona uma Sentinela Invisível no chão. Ela permanece Invisível para os inimigos e concede visão da área ao redor à sua equipe. Armazena até 3 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. Despojos de Guerra: enquanto estiver perto de um Campeão aliado, Ataques executam tropas com menos de 50% da Vida máxima delas. Abater uma tropa concede o mesmo ouro do abate ao Campeão aliado mais próximo. Esses efeitos recarregam a cada 35s (máximo de 3 cargas).Missão: consiga 1000 de ouro com esse item para transformá-lo em Bastião da Montanha. ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3855.png'),
(3857, 'Ombreiras de Pedralva', '15 de Dano de Ataque250 de Vida100% de Regeneração de Vida base3 de ouro a cada 10sAtivo – Sentinela: posiciona uma Sentinela Invisível no chão. Ela permanece Invisível para os inimigos e concede visão da área ao redor à sua equipe. Armazena até 4 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3857.png'),
(3858, 'Escudo Relicário', '7 de Poder de Habilidade50 de Vida50% de Regeneração de Vida base2 de ouro a cada 10sDespojos de Guerra: enquanto estiver perto de um Campeão aliado, Ataques executam tropas com menos de 50% da Vida máxima (usuários de ataque corpo a corpo) | 30% da Vida máxima (usuários de ataque à distância). Abater uma tropa concede o mesmo ouro do abate ao Campeão aliado mais próximo. Esses efeitos recarregam a cada 35s (máximo de 3 cargas).Missão: consiga 500 de ouro com esse item para transformá-lo em Broquel de Targon, recebendo Ativo – Vigilante.Se qualquer pessoa na sua equipe com este item já tiver abatido muitas tropas, ele concederá menos ouro proveniente delas.', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3858.png'),
(3859, 'Broquel de Targon', '10 de Poder de Habilidade100 de Vida75% de Regeneração de Vida base3 de ouro a cada 10sAtivo – Sentinela: posiciona uma Sentinela Invisível no chão. Ela permanece Invisível para os inimigos e concede visão da área ao redor à sua equipe. Armazena até 3 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. Despojos de Guerra: enquanto estiver perto de um Campeão aliado, Ataques executam tropas com menos de 50% da Vida máxima delas. Abater uma tropa concede o mesmo ouro do abate ao Campeão aliado mais próximo. Esses efeitos recarregam a cada 35s (máximo de 3 cargas).Missão: consiga 1000 de ouro com esse item para transformá-lo em Bastião da Montanha. ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3859.png'),
(3860, 'Bastião da Montanha', '20 de Poder de Habilidade250 de Vida100% de Regeneração de Vida base3 de ouro a cada 10sAtivo – Sentinela: posiciona uma Sentinela Invisível no chão. Ela permanece Invisível para os inimigos e concede visão da área ao redor à sua equipe. Armazena até 4 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3860.png'),
(3862, 'Foice Espectral', '6 de Dano de Ataque25 de Vida25% de Regeneração de Mana base2 de ouro a cada 10sTributo: enquanto estiver perto de um Campeão aliado, Ataques e Habilidades de dano contra Campeões ou estruturas concedem 20 de ouro. Isso pode ocorrer até 3 vezes a cada 30s.Missão: consiga 500 de ouro com esse item para transformá-lo em Tormento Crescente, recebendo Ativo – Vigilante.Se qualquer pessoa na sua equipe com este item já tiver abatido muitas tropas, ele concederá menos ouro proveniente delas.', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3862.png'),
(3863, 'Tormento Crescente', '10 de Dano de Ataque60 de Vida50% de Regeneração de Mana base3 de ouro a cada 10sTributo: enquanto estiver perto de um Campeão aliado, Ataques e Habilidades de dano contra Campeões ou estruturas concedem 20 de ouro. Isso pode ocorrer até 3 vezes a cada 36s.Missão: consiga 1000 de ouro com esse item para transformá-lo em Foice da Névoa Negra.Se qualquer pessoa na sua equipe com este item já tiver abatido muitas tropas, ele concederá menos ouro proveniente delas.ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3863.png'),
(3864, 'Foice da Névoa Negra', '20 de Dano de Ataque75 de Vida100% de Regeneração de Mana base3 de ouro a cada 10sAtivo – Sentinela: posiciona uma Sentinela Invisível no chão. Ela permanece Invisível para os inimigos e concede visão da área ao redor à sua equipe. Armazena até 4 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3864.png'),
(3865, 'Atlas Mundial', '', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3865.png'),
(3866, 'Bússola Rúnica', '100 de Vida50% de Regeneração de Vida base50% de Regeneração de Mana base5 de ouro a cada 10sATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. Missão Consiga 800 de ouro com esse item para transformá-lo em Bússola Rúnica. Recebe uma carga a cada 20s, até o máximo de 3 cargas. Enquanto estiver perto de um Campeão aliado, consome uma carga para obter ouro: Ataques e Habilidades de dano contra Campeões ou estruturas concedem 24 (corpo a corpo)/22 (à distância) de ouro;Abater uma tropa, de qualquer maneira, concede 20 de ouro e o ouro do abate do Campeão aliado mais próximo.ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3866.png'),
(3867, 'Dádiva dos Mundos', '5 de ouro a cada 10s75% de Regeneração de Vida base75% de Regeneração de Mana base200 de VidaAprimorarEste item pode ser aprimorado gratuitamente para Canção de Sangue, Oposição Celestial, Criassonhos, Invadomínio de Zaz\'Zak ou Trenó do Solstício.ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3867.png'),
(3869, 'Oposição Celestial', '200 de Vida75% de Regeneração de Vida base75% de Regeneração de Mana base5 de ouro a cada 10sBênção da Montanha: você obtém o status Abençoado, reduzindo o dano sofrido por Campeões. O efeito dura 2s após sofrer dano de um Campeão.ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3869.png'),
(3870, 'Criassonhos', '200 de Vida75% de Regeneração de Vida base75% de Regeneração de Mana base5 de ouro a cada 10sCriassonhosRecebe uma Bolha de Sonho Azul e uma Bolha de Sonho Roxa ao longo do tempo. Conceder cura ou Escudo a um aliado sopra ambas as Bolhas do Sonho em direção a ele, fortalecendo-o, reduzindo o dano sofrido e concedendo dano causado.ATIVOSSentinela Posicione uma Sentinela Invisível que concede visão. Armazena 0 Sentinelas Invisíveis que são reabastecidas ao visitar a loja. ', 400, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/3870.png'),
