(6673, 'Arco-escudo Imortal', '50 de Dano de Ataque20% de Chance de Acerto Crítico12% de Roubo de VidaSalva-VidasAo sofrer dano que deixaria sua Vida inferior a certo valor, recebe um Escudo.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6673.png'),
(6675, 'Adagas Rápidas Navori', '65 de Dano de Ataque20% de Chance de Acerto Crítico15 de Aceleração de HabilidadeTranscendênciaSeus Ataques reduzem o Tempo de Recarga das Habilidades (exceto da ultimate).ImpermanênciaSuas Habilidades causam dano aumentado com base na Chance de Acerto Crítico. ', 3300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6675.png'),
(6676, 'A Coletora', '55 de Dano de Ataque20% de Chance de Acerto Crítico16 de LetalidadeMorteSeu dano executa Campeões com menos de 5% de Vida.AbruptaAbates de Campeões concedem 25 de ouro adicional.', 3100, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6676.png'),
(6677, 'Faca da Fúria', '25% de Velocidade de AtaqueIra: Ataques causam 20 de Dano Mágico ao contato.Golpe Fervente: ataques básicos concedem 5% de Velocidade de Ataque, acumulando até 3 vezes.', 1200, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6677.png'),
(6690, 'Retriz', '20 de Dano de Ataque4% de Velocidade de Movimento', 900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6690.png'),
(6691, 'Crepúsculo de Draktharr', '60 de Dano de Ataque18 de Letalidade15 de Aceleração de HabilidadePredador Noturno: suas Habilidades causam uma porcentagem de dano adicional com base na Vida perdida do alvo. Se um Campeão a quem você tenha causado dano nos últimos 3s for abatido, você fica Inalvejável para não estruturas por 1.5s (30(0s)).Passivo Mítico: concede a todos os outros itens Lendários Aceleração de Habilidade e Velocidade de Movimento.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6691.png'),
(6692, 'Eclipse', '70 de Dano de Ataque15 de Aceleração de HabilidadeLua Sempre CrescenteAtingir um Campeão com 3 Ataques ou Habilidades separados dentro de 2s causa dano adicional e concede um Escudo ao usuário.', 2800, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6692.png'),
(6693, 'Garra do Espreitador', '55 de Dano de Ataque22 de Letalidade15 de Aceleração de HabilidadeEminênciaQuando um Campeão a quem você tenha causado dano for abatido, recebe Dano de Ataque.EgoRecebe uma estátua de si ao abater Campeões. Se você já tiver uma estátua, ela é aprimorada.', 2900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6693.png'),
(6694, 'Rancor de Serylda', '45 de Dano de Ataque15 de Letalidade15 de Aceleração de HabilidadeRancorRecebe 0 de Penetração de Armadura.Frio AgonizanteHabilidades de dano causam 30% de Lentidão a inimigos com menos de 50% de Vida por 1s.', 3200, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6694.png'),
(6695, 'Presa da Serpente', '55 de Dano de Ataque15 de LetalidadeCeifador de EscudosCausar dano a um Campeão inimigo reduz quaisquer Escudos que ele receba. Ao causar dano a um inimigo que não esteja afetado por Ceifador de Escudos, reduz todos os Escudos dele.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6695.png'),
(6696, 'Arco do Axioma', '55 de Dano de Ataque18 de Letalidade25 de Aceleração de HabilidadeFluxoSempre que um Campeão morre em até 3s depois de sofrer dano vindo de você, restitui parte do Tempo de Recarga total da sua ultimate.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6696.png'),
(6697, 'Húbris', '60 de Dano de Ataque18 de Letalidade15 de Aceleração de HabilidadeEminênciaRecebe DdA temporário com base nos Campeões abatidos.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6697.png'),
(6698, 'Hidra Profana', '60 de Dano de Ataque18 de Letalidade20 de Aceleração de HabilidadeFendaAtaques causam dano adicional ao contato, criando uma onda de choque que causa dano aos inimigos atrás do alvo.ATIVOSFenda HeregeCausa Dano Físico a inimigos próximos. Esse dano aumenta contra inimigos com pouca Vida.', 3300, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6698.png'),
(6699, 'Cicloespada Voltaica', '55 de Dano de Ataque18 de Letalidade15 de Aceleração de HabilidadeGalvanizarAvanços e Furtividade acumulam Energizado mais rápido.FirmamentoSeu Ataque Energizado causa Dano Físico adicional e Lentidão aos inimigos.', 2900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6699.png'),
(6700, 'Escudo dos Rakkor', '50 de Dano de Ataque30 de Armadura5% de Velocidade de MovimentoÉgide: bloqueia o primeiro Ataque que atingiria você a cada 8(0s). Quando o Escudo é quebrado, seu primeiro Ataque contra um Campeão restitui 50% do Tempo de Recarga atual e concede 20% de Velocidade de Movimento por um curto período.', 2800, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6700.png'),
(6701, 'Oportunidade', '55 de Dano de Ataque18 de Letalidade5% de Velocidade de MovimentoEminênciaQuando um Campeão a quem você tenha causado dano for abatido, recebe Dano de Ataque.EgoRecebe uma estátua de si ao abater Campeões. Se você já tiver uma estátua, ela é aprimorada.', 2700, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/6701.png'),
(7000, 'Garra da Ave de Areia', '75 de Dano de Ataque26 de Letalidade25 de Aceleração de HabilidadeEminênciaQuando um Campeão a quem você tenha causado dano for abatido, recebe Dano de Ataque.EgoRecebe uma estátua de si ao abater Campeões. Se você já tiver uma estátua, ela é aprimorada.', 2900, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/7000.png'),
