(226665, 'Jak\'Sho, o Inconstante', '300 de Vida35 de Armadura35 de Resistência MágicaResiliência do VazioDurante combate contra Campeões, você se fortalece, aumentando sua Armadura e Resistência Mágica adicionais até o fim do combate.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226665.png'),
(226667, 'Virtude Radiante', '350 de Vida30 de Armadura30 de Resistência Mágica10 de Aceleração de HabilidadeLuz-guia: ao conjurar a ultimate, você Transcende, aumentando sua Vida máxima. No estado Transcendido, você e seus aliados se curam ao longo do tempo.Passivo Mítico: concede a todos os outros itens Lendários de Vida.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226667.png'),
(226671, 'Força do Vendaval', '60 de Dano de Ataque40% de Velocidade de Ataque20% de Chance de Acerto Crítico7% de Velocidade de MovimentoPassivo Mítico: concede a todos os outros itens Lendários 5 de Dano de Ataque.O dano máximo do projétil é causado quando a Vida do inimigo estiver abaixo de 25%.O avanço de Erupção das Brumas não pode atravessar terrenos.Ativo – Erupção das Brumas: avança na direção-alvo, disparando três projéteis no inimigo com a Vida mais baixa que estiver próximo ao destino do avanço. Causa Dano Físico, aumentado contra alvos com a Vida baixa.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226671.png'),
(226672, 'Mata-Cráquens', '30 de Dano de Ataque35% de Velocidade de Ataque20% de Chance de Acerto CríticoDerrubar: todo terceiro ataque básico causa Dano Físico adicional ao contato, aumentado ao atingir o mesmo alvo repetidamente.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226672.png');
INSERT INTO `itens` (`ID_riot`, `nome`, `descricao`, `preco`, `imagem_url`) VALUES
(226673, 'Arco-escudo Imortal', '40 de Dano de Ataque20% de Chance de Acerto Crítico10% de Roubo de VidaSalva-VidasAo sofrer dano que deixaria sua Vida inferior a 30%, recebe um Escudo.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226673.png'),
(226675, 'Adagas Rápidas Navori', '45 de Dano de Ataque20% de Chance de Acerto Crítico15 de Aceleração de HabilidadeTranscendência: seus Ataques reduzem o Tempo de Recarga das Habilidades (exceto da ultimate).Impermanência: suas Habilidades causam dano aumentado com base na Chance de Acerto Crítico.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226675.png'),
(226676, 'A Coletora', '45 de Dano de Ataque20% de Chance de Acerto Crítico18 de LetalidadeMorte AbruptaSe você causar dano o bastante para deixar um Campeão inimigo com menos de 5% de Vida, ele é executado.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226676.png'),
(226691, 'Crepúsculo de Draktharr', '60 de Dano de Ataque22 de Letalidade15 de Aceleração de HabilidadePredador Noturno: suas Habilidades causam dano adicional com base na Vida perdida do alvo. Se um Campeão a quem você tenha causado dano nos últimos 3s for abatido, você fica Inalvejável para não estruturas por 1.5s (10(0s)).Passivo Mítico: concede a todos os outros itens Lendários Aceleração de Habilidade e Velocidade de Movimento.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226691.png'),
(226692, 'Eclipse', '60 de Dano de Ataque10 de Aceleração de HabilidadeLua Sempre CrescenteAtingir um Campeão com 2 Ataques ou Habilidades separados dentro de 2s causa dano adicional, concedendo a você Velocidade de Movimento e um Escudo.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226692.png'),
(226693, 'Garra do Espreitador', '55 de Dano de Ataque22 de Letalidade15 de Aceleração de HabilidadeAtaque de Areia: depois de usar um avanço, teleporte ou sair de Furtividade, seu próximo Ataque contra um Campeão causa Dano Físico adicional. Se for desferido por um Campeão corpo a corpo, este Ataque também causa Lentidão ao alvo.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226693.png'),
(226694, 'Rancor de Serylda', '40 de Dano de Ataque18 de Letalidade10 de Aceleração de HabilidadeRancorRecebe 0 de Penetração de Armadura.Frio AgonizanteHabilidades de dano causam 30% de Lentidão a inimigos com menos de 50% de Vida por 1s.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226694.png'),
(226695, 'Presa da Serpente', '55 de Dano de Ataque19 de LetalidadeCeifador de EscudosCausar dano a um Campeão inimigo reduz quaisquer Escudos que ele receba. Ao causar dano a um inimigo que não esteja afetado por Ceifador de Escudos, reduz todos os Escudos dele.O desempenho do item é diferente para usuários de ataque corpo a corpo e usuários de ataque à distância.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226695.png'),
(226696, 'Arco do Axioma', '45 de Dano de Ataque22 de Letalidade25 de Aceleração de HabilidadeApotegmaSuas ultimates causam 20% de dano aumentado.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226696.png'),
(226697, 'Húbris', '50 de Dano de Ataque18 de Letalidade10 de Aceleração de HabilidadeEminênciaRecebe DdA temporário com base nos Campeões abatidos.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226697.png'),
(226698, 'Hidra Profana', '50 de Dano de Ataque18 de Letalidade15 de Aceleração de HabilidadeFendaAtaques causam dano adicional ao contato, criando uma onda de choque que causa dano aos inimigos atrás do alvo.ATIVOSFenda HeregeCausa Dano Físico a inimigos próximos. Esse dano aumenta contra inimigos com pouca Vida.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226698.png'),
(226699, 'Cicloespada Voltaica', '45 de Dano de Ataque18 de Letalidade15 de Aceleração de HabilidadeGalvanizarAvanços e Furtividade acumulam Energizado mais rápido.FirmamentoSeu Ataque Energizado causa Dano Físico adicional e Lentidão aos inimigos.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226699.png'),
(226701, 'Oportunidade', '50 de Dano de Ataque18 de Letalidade5% de Velocidade de MovimentoEminênciaQuando um Campeão a quem você tenha causado dano for abatido, recebe Dano de Ataque.EgoRecebe uma estátua de si ao abater Campeões. Se você já tiver uma estátua, ela é aprimorada.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/226701.png'),
(227001, 'Sizígia', '90 de Dano de Ataque20 de Aceleração de HabilidadeLua Sempre CrescenteAtingir um Campeão com 2 Ataques ou Habilidades separados dentro de 20s causa dano adicional, concedendo a você Velocidade de Movimento e um Escudo.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227001.png'),
(227002, 'Escultor Sombrio de Draktharr', '75 de Dano de Ataque26 de Letalidade25 de Aceleração de HabilidadePredador Noturno: suas Habilidades causam dano adicional com base na Vida perdida do alvo. Se um Campeão a quem você tenha causado dano nos últimos 3s for abatido, você fica Inalvejável para não estruturas por 1.5s (10(0s)).Passivo Mítico: concede a todos os outros itens Lendários Aceleração de Habilidade e Velocidade de Movimento.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227002.png'),
(227005, 'Punho Congelado', '550 de Vida70 de Armadura15 de Aceleração de HabilidadeLâmina ArcanaDepois de usar uma Habilidade, seu próximo Ataque é fortalecido com dano adicional e cria um campo congelado por 2s. Inimigos que se moverem pelo campo sofrerão Lentidão.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227005.png'),
(227006, 'Tufão', '80 de Dano de Ataque55% de Velocidade de Ataque20% de Chance de Acerto Crítico10% de Velocidade de MovimentoPassivo Mítico: concede a todos os outros itens Lendários 5 de Dano de Ataque.O dano máximo do projétil é causado quando a Vida do inimigo estiver abaixo de 25%.O avanço de Erupção das Brumas não pode atravessar terrenos.Ativo – Erupção das Brumas: avança na direção-alvo, disparando três projéteis no inimigo com a Vida mais baixa que estiver próximo ao destino do avanço. Causa Dano Físico, aumentado contra alvos com a Vida baixa.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227006.png'),
(227009, 'Maldição de Icathia', '90 de Poder de Habilidade600 de Vida20 de Aceleração de HabilidadeCorrupção do VazioPara cada segundo em combate com Campeões inimigos, causa dano adicional. Com força máxima, recebe Vampirismo Universal.Infusão do VazioRecebe uma porcentagem da sua Vida adicional como Poder de Habilidade. ', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227009.png'),
(227010, 'Vesperal', '120 de Poder de Habilidade500 de Vida50 de Aceleração de HabilidadeLaceração EspiritualCausar dano a um Campeão com Ataques ou Habilidades causa Dano Mágico adicional e concede Velocidade de Movimento a você.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227010.png'),
(227011, 'Aeropropulsor Aprimorado', '120 de Poder de Habilidade15 de Penetração Mágica500 de VidaAtivo – Supersônico: avança na direção-alvo, disparando um arco de mísseis mágicos que causa dano. Depois, recebe Velocidade de Movimento em direção a Campeões inimigos.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227011.png'),
(227012, 'Lamento de Liandry', '100 de Poder de Habilidade800 de ManaTormentoCausar Dano de Habilidade faz com que os inimigos sofram queimaduras.SofrimentoPara cada segundo em combate com Campeões inimigos, recebe dano aumentado. ', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227012.png'),
(227013, 'Potência Bélica', '100 de Poder de Habilidade13 de Penetração Mágica800 de ManaCarregarRecebe uma Carga de Disparo a cada poucos segundos.DispararHabilidades de dano consomem todas as Cargas de Disparo para causar Dano Mágico adicional ao alvo e a um alvo próximo adicional para cada carga. Se não houver alvos suficientes dentro do alcance, para cada carga restante, repete o dano no alvo primário.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227013.png'),
(227014, 'Inverno Eterno', '100 de Poder de Habilidade650 de Vida800 de Mana25 de Aceleração de HabilidadeATIVOS (0s)GeleiraCausa dano em uma área de cone e Lentidão aos inimigos atingidos. Inimigos no centro do cone são Enraizados.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227014.png'),
(227015, 'Fome Incessante', '65 de Dano de Ataque600 de Vida25 de Aceleração de Habilidade12% de Vampirismo UniversalHemodrenárioAtivo – Corte Sedento: cause dano a inimigos próximos. Restaura Vida para cada Campeão atingido.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227015.png'),
(227016, 'Assolador de Sonhos', '60 de Dano de Ataque30% de Velocidade de Ataque400 de VidaFendaAtaques causam Dano Físico a inimigos próximos.RaivaCausar Dano Físico concede Velocidade de Movimento.ATIVOSOnda de Choque EstonteanteCausa Dano Físico e Lentidão a inimigos próximos e recebe Velocidade de Movimento a cada Campeão atingido. É possível se mover durante a conjuração.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227016.png'),
(227017, 'Deicídio', '55 de Dano de Ataque350 de Vida25 de Aceleração de HabilidadeLâmina ArcanaDepois de usar uma Habilidade, seu próximo Ataque é fortalecido e causa dano adicional ao contato. Se o alvo for um Campeão, também se cura.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227017.png'),
(227018, 'Força do Infinito', '45 de Dano de Ataque45% de Velocidade de Ataque445 de Vida25 de Aceleração de HabilidadeLâmina ArcanaDepois de usar uma Habilidade, seu próximo Ataque é fortalecido e causa Dano Físico adicional.ApressarAtaques básicos concedem Velocidade de Movimento.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227018.png'),
(227019, 'Relicário do Alvorecer Dourado', '600 de Vida35 de Aceleração de Habilidade40 de Armadura40 de Resistência MágicaATIVOS (0s)DevoçãoConcede aos aliados próximos um Escudo que decai ao longo do tempo.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227019.png'),
(227020, 'Réquiem de Shurelya', '75 de Poder de Habilidade600 de Vida200% de Regeneração de Mana base200% de Regeneração de Mana baseATIVOS (0s)Discurso InspiradorConcede Velocidade de Movimento aos aliados próximos por alguns segundos.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227020.png'),
(227021, 'Conjurador Estelar', '80 de Poder de Habilidade300 de Vida35 de Aceleração de Habilidade200% de Regeneração de Mana baseGraça EstreladaCurar ou conceder Escudo a um aliado ativa um efeito em cadeia no Campeão aliado mais próximo (menos em si), curando ou concedendo Escudo com base na quantidade original.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227021.png'),
(227023, 'Equinócio', '600 de Vida40 de Armadura40 de Resistência Mágica25 de Aceleração de HabilidadeOfuscante: depois de Imobilizar Campeões ou de ser Imobilizado, faz com que o alvo e todos os Campeões inimigos próximos sofram dano aumentado.Passivo Mítico: concede a todos os outros itens Lendários  de Armadura e de Resistência Mágica', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227023.png'),
(227024, 'Cesura', '100 de Poder de Habilidade350 de Vida800 de Mana25 de Aceleração de HabilidadeProteçãoVocê recebe Proteção e sofre menos dano de Campeões. A Proteção permanece por 2.5s depois de sofrer dano de Campeões. ', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227024.png'),
(227025, 'Leviatã', '1050 de Vida300% de Regeneração de Vida baseDevastação Colossal (0s) por alvoCarrega um ataque poderoso contra um Campeão ao longo de 0s enquanto estiver a até 700 de alcance dele. O ataque carregado causa 125 + 12% da Vida do item como Dano Físico adicional, além de conceder 12% desse dano como Vida máxima permanente.GoliasPara cada 1000 de Vida máxima, recebe 3% de aumento de tamanho, chegando a até 30%. ', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227025.png'),
(227026, 'O Parasita Silencioso', '450 de Vida40 de Armadura40 de Resistência MágicaResiliência do VazioDurante combate contra Campeões, você se fortalece, aumentando sua Armadura e Resistência Mágica adicionais até o fim do combate.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227026.png'),
(227027, 'Amanhecer Primordial', '550 de Vida40 de Armadura40 de Resistência Mágica25 de Aceleração de HabilidadeLuz-guia: ao conjurar a ultimate, você Transcende, aumentando sua Vida máxima. No estado Transcendido, você e seus aliados se curam ao longo do tempo.Passivo Mítico: concede a todos os outros itens Lendários de Vida.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227027.png'),
(227028, 'Convergência Infinita', '90 de Poder de Habilidade550 de Vida550 de ManaAtemporalDepois de 2 rodadas de combate, este item recebe 0 de Poder de Habilidade adicional, 0 de Vida e 0 de Mana, além de um nível.EternidadeSofrer dano de Campeões restaura 7% do dano pré-mitigação como Mana. Conjurar uma Habilidade cura em 25% do Mana gasto, até um máximo de 20 de Vida por conjuração por segundo.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227028.png'),
(227029, 'Velório de Youmuu', '75 de Dano de Ataque26 de Letalidade20 de Aceleração de HabilidadeAssombrar Recebe Velocidade de Movimento fora de combate.ATIVOS (0s)Passo EspectralRecebe Velocidade de Movimento e efeito Fantasma.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227029.png'),
(227030, 'Sofrimento Fervente', '35 de Dano de Ataque35 de Poder de Habilidade40% de Velocidade de AtaqueIraAtaques causam 30 de Dano Mágico ao contato.Golpe FerventeAtaques básicos concedem 8% de Velocidade de Ataque, acumulando até 4 vezes, chegando a um máximo de 0 de Velocidade de Ataque. Enquanto estiver com o máximo de acúmulos, cada terceiro Ataque aplica efeitos ao contato duas vezes.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227030.png'),
(227031, 'Gume da Finalidade', '105 de Dano de Ataque20% de Chance de Acerto Crítico50% de Dano de Acerto Crítico', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227031.png'),
(227032, 'Cintilação', '90 de Dano de Ataque20% de Chance de Acerto Crítico25 de Aceleração de HabilidadeTranscendênciaSeus Ataques reduzem o Tempo de Recarga das Habilidades (exceto da ultimate).ImpermanênciaSuas Habilidades causam dano aumentado com base na Chance de Acerto Crítico. ', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227032.png'),
(227033, 'Choro da Cidade Estridente', '60 de Poder de Habilidade500 de Vida45 de Aceleração de Habilidade225% de Regeneração de Mana baseSifão da Alma: causar dano a um Campeão concede um Fragmento de Espírito. Conceder curas ou Escudos a um aliado consome todos os Fragmentos de Espírito para restaurar Vida e causar Dano Mágico por cada Fragmento ao Campeão inimigo mais próximo.Dissonância: recebe Poder de Habilidade com base na Regeneração de Mana base. Desabilita Harmonia.Passivo Mítico: concede a todos os outros itens Lendários Aceleração de Habilidade.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/227033.png'),
(228001, 'Correntes de Anathema', '600 de Vida15 de Aceleração de HabilidadeVendeta:sofre dano reduzido do seu Nêmesis. Ele tem Tenacidade reduzida enquanto estiver perto de você.O efeito ativo pode ser conjurado com alcance global.\'\'Ela jurou dedicar a própria vida a destrui-lo...\'\'ATIVOS (0s)JuramentoEscolhe um Nêmesis.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/228001.png'),
(228002, 'Chapéu Mágico de Wooglet', '300 de Poder de Habilidade50 de Armadura20 de Aceleração de HabilidadeApogeu MágicoAumenta o Poder de Habilidade total em 50%.Aprimoramento necessário: Missão: Chapéu Mágico de WoogletTempo ParalisadoEntra em Estase por 2,5s.', 6000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/228002.png'),
(228003, 'Lâmina Mortal', '150 de Dano de Ataque20% de Chance de Acerto Crítico45% de Dano de Acerto Crítico20 de LetalidadeMorte Abrupta: se você causar dano o bastante para deixar um Campeão inimigo com menos de 7% de Vida, ele é executado. Abates de Campeões concedem 250 de ouro adicional e curam você em 30% da Vida máxima do alvo.', 9000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/228003.png'),
(228004, 'Elmo Adaptativo', '800 de Vida50 de Armadura100 de Resistência MágicaResiliência do Vazio: para cada segundo em combate contra Campeões, recebe um acúmulo que concede 2 de Armadura e Resistência Mágica (máximo de 8 acúmulos). Com o máximo de acúmulos, você se fortalece, drenando instantaneamente cada inimigo ao redor em Dano Mágico, curando-se pelo mesmo valor e aumentando suas resistências adicionais em 20% até o fim do combate. A drenagem se repete a cada 4s enquanto você permanecer em combate.Absorção: sofrer Dano Mágico de Campeões inimigos concede um acúmulo de Impassível (máximo de 8) por 7s. Efeitos Imobilizadores inimigos concedem 2 acúmulos adicionais.Dissipar: enquanto estiver com 8 acúmulos de Impassível, recebe 50 de Resistência Mágica e 14% de Velocidade de Movimento aumentada.Uma Habilidade pode adicionar um novo acúmulo de Impassível a cada 1s.', 6000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/228004.png'),
(228005, 'Cutelo Obsidiano', '70 de Dano de Ataque700 de Vida40 de Aceleração de HabilidadeTalharCausar Dano Físico a um Campeão aplica um acúmulo de redução de Armadura.FervorCausar Dano Físico concede Velocidade de Movimento.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/228005.png'),
(228006, 'Lâmina Sanguinária', '130 de Dano de Ataque40% de Velocidade de Ataque20 de Aceleração de Habilidade30% de Roubo de VidaFenda: Ataques e Habilidades causam {{ Item_Melee_Ranged_Split }} de Dano Físico aos outros inimigos dentro de 600 unidades do alvo atingido e acionam efeitos ao contato.Gume da Névoa: Ataques aplicam {{ Item_Melee_Ranged_Split_B }} da Vida atual do inimigo como Dano Físico {{ Item_Keyword_OnHit }}.Sifão: Atacar um Campeão 3 vezes causa 0 de Dano Mágico e rouba 25% de Velocidade de Movimento por 2s (30{{ Item_Cooldown }}).O dano máximo de Gume da Névoa causado a tropas e monstros da selva é 60. {{ Item_Melee_Ranged_Rules }}{{ Item_OnActivation }} {{ Item_Cooldown }}Crescente RaivosaCausa Dano Físico a inimigos ao seu redor e aplica Roubo de Vida.', 3000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/228006.png'),
(228008, 'Glaive Rúnica', '65 de Dano de Ataque85 de Poder de Habilidade33% de Velocidade de Ataque25 de Aceleração de Habilidade600 de Vida50 de Armadura10% de Velocidade de Movimento20% de Chance de Acerto Crítico', 9000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/228008.png'),
(228020, 'Máscara Abissal', '300 de Vida50 de Resistência Mágica10 de Aceleração de HabilidadeDestroçarReduz a Resistência Mágica de Campeões inimigos próximos. Para cada inimigo afetado, recebe Resistência Mágica.', 2500, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/228020.png'),
(443054, 'Garras de Aço Sombrio', '60% de Velocidade de Ataque65 de Armadura10% de Velocidade de MovimentoTalhoAtaques aplicam Dano Verdadeiro ao contato.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443054.png'),
(443055, 'Fulminação', '55 de Dano de Ataque45% de Velocidade de Ataque15% de Velocidade de MovimentoPolaridadeAo Atacar, se o alvo não for o mesmo que você atingiu recentemente com um Ataque Energizado, prepara Energizado. DínamoAtaques Energizados causam Dano Mágico adicional com base na Vida atual do alvo.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443055.png'),
(443056, 'Coroa do Rei Demoníaco', 'SupremaciaAumenta Vida, Armadura, Resistência Mágica, Dano de Ataque, Poder de Habilidade, Velocidade de Ataque e Aceleração de Habilidade em 26%. O valor aumenta em 0% a cada rodada vencida e em -3% a cada rodada perdida após a aquisição do item.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443056.png'),
(443058, 'Escudo de Rocha Fundida', '300 de Vida100 de ArmaduraInabalável como a TerraAumenta sua Armadura em 20% e concede Chance de Bloqueio com base na sua Armadura.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443058.png'),
(443059, 'Manto da Noite Estrelada', '300 de Vida100 de Resistência MágicaInesgotável como as EstrelasAumenta sua Resistência Mágica em 20%. Reduz todo o dano sofrido de fontes que não são ataques básicos em uma porcentagem, escalando com sua Resistência Mágica até 50%.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443059.png'),
(443060, 'Espada do Divino', '100 de Força Adaptativa40% de Chance de Acerto CríticoTrucidarCada Acerto Crítico causa Dano de Acerto Crítico adicional aleatório, escalando até 50% da sua Chance de Acerto Crítico.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443060.png'),
(443061, 'Força da Entropia', '900 de Vida30 de Aceleração de Habilidade30% de Chance de Acerto CríticoAtrofiaEfeitos de Controles de Grupo Imobilizadores aplicados por você atualizam sua Chance de Crítico, aumentando a duração deles em 0.25s + 33%.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443061.png'),
(443062, 'Presente Sanguinário', '90 de Poder de Habilidade25 de Aceleração de Habilidade15% de Cura e Resistência do EscudoPatronagemArmazena 10% do dano total que você causar a inimigos. Sempre que o valor exceder 333, consuma-o para curar você e o aliado mais próximo pela mesma quantidade.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443062.png'),
(443063, 'Milagre de Eleisa', '70 de Armadura70 de Resistência Mágica25 de Aceleração de HabilidadeVitalidade DuradouraRecebe +1% de cura e Resistência do Escudo a cada 100 de Vida perdida, até 40%.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443063.png'),
(443064, 'Talismã da Ascensão', '? Dano de Ataque? Velocidade de Ataque? Chance de Acerto Crítico? Dano de Acerto Crítico?  Poder de Habilidade? Aceleração de Habilidade? Vida?% Regeneração de Vida base? Mana?% Regeneração de Mana base? Armadura? Resistência Mágica? || ?% Letalidade e Penetração de Armadura? || ?% Penetração Mágica?% Roubo de Vida?% Vampirismo Universal? || ?% Velocidade de Movimento?% Cura e Resistência do EscudoATIVOSSobreposição Atualiza os atributos do Talismã da Ascensão. Os atributos ficam mais fortes sempre que você faz isso. Duas vezes por rodada (três com o Inventor Apex).', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443064.png'),
(443069, 'Debilitador', '50 de Dano de Ataque40% de Velocidade de Ataque20% de Chance de Acerto CríticoErosãoAo causar Acerto Crítico:aplica Queimadura, causando 0 de Dano Físico ao longo de 2s. Não há limite de acúmulos para esse efeito.Aplica 7% de Lentidão por 2s. Este efeito acumula até 35%.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443069.png'),
(443079, 'Quimiotanque Turbo', '1100 de Vida15% de Velocidade de MovimentoCarregadoA força dos efeitos de Lentidão é reduzida em 30%.ATIVOS (0s)SobrecarregadoPor 4s, recebe 60% de Velocidade de Movimento ao enfrentar Campeões inimigos visíveis. Quando um Campeão inimigo estiver próximo ou ao terminar a duração, libera uma onda de choque, causando 50% de Lentidão a inimigos próximos por 2s.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443079.png'),
(443193, 'Placa Gargolítica', '90 de Armadura90 de Resistência Mágica15 de Aceleração de Habilidade10% de Velocidade de MovimentoATIVOS (0s)InquebrávelRecebe um Escudo que decai e cresce em tamanho.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/443193.png'),
(444636, 'Colhedor Noturno', '90 de Poder de Habilidade400 de Vida40 de Aceleração de HabilidadeLaceração EspiritualCausar dano a um Campeão com Ataques ou Habilidades causa Dano Mágico adicional e concede Velocidade de Movimento a você.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/444636.png'),
(444637, 'Abraço Demoníaco', '70 de Poder de Habilidade600 de Vida20 de Aceleração de HabilidadePacto SinistroRecebe +4% de Poder de Habilidade a cada 300 de Vida perdida, até 40%.ATIVOS (0s)Preço do PoderSacrifica 300 de Vida para receber 100% de Velocidade de Movimento que decai ao longo de 2s. Não é fatal.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/444637.png'),
(444644, 'Coroa da Rainha Despedaçada', '85 de Poder de Habilidade300 de Vida600 de Mana25 de Aceleração de HabilidadeProteçãoVocê recebe Proteção e sofre menos dano de Campeões. A Proteção permanece por 3s depois de sofrer dano de Campeões.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/444644.png'),
(446632, 'Ruptor Divino', '55 de Dano de Ataque350 de Vida20 de Aceleração de HabilidadeLâmina ArcanaDepois de usar uma Habilidade, seu próximo Ataque é fortalecido e causa dano adicional ao contato. Se o alvo for um Campeão, também se cura.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/446632.png'),
(446656, 'Glacieterno', '100 de Poder de Habilidade500 de Vida600 de Mana20 de Aceleração de HabilidadeATIVOS (0s)GeleiraCausa dano em uma área de cone e Lentidão aos inimigos atingidos. Inimigos no centro do cone são Enraizados.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/446656.png'),
(446667, 'Virtude Radiante', '400 de Vida35 de Armadura35 de Resistência Mágica12% de Cura e Resistência do EscudoLuz-guiaAo conjurar a ultimate, você Transcende, aumentando sua Vida máxima. No estado Transcendido, você e seus aliados se curam ao longo do tempo.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/446667.png'),
(446671, 'Força do Vendaval', '60 de Dano de Ataque30% de Velocidade de Ataque20% de Chance de Acerto Crítico12% de Velocidade de MovimentoATIVOS (0s)Erupção das Brumas IIAvança na direção-alvo sobre o terreno, disparando três projéteis no inimigo com a Vida mais baixa que estiver próximo ao destino do avanço. Causa Dano Físico, aumentado contra alvos com a Vida baixa.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/446671.png'),
(446691, 'Crepúsculo de Draktharr', '60 de Dano de Ataque22 de Letalidade20 de Aceleração de HabilidadePredador NoturnoSuas Habilidades causam uma porcentagem de dano adicional com base na Vida perdida do alvo. Se um Campeão a quem você tenha causado dano nos últimos 3s for abatido, você fica Inalvejável para não estruturas por 1.5s (0s).', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/446691.png'),
(446693, 'Garra do Espreitador', '70 de Dano de Ataque22 de Letalidade25 de Aceleração de HabilidadeAtaque de Areia: depois de usar um avanço, teleporte ou sair de Furtividade, seu próximo Ataque contra um Campeão causa Dano Físico adicional. Se for desferido por um Campeão corpo a corpo , este Ataque também causa Lentidão ao alvo.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/446693.png'),
(447100, 'Espada da Miragem', '55 de Força Adaptativa60% de Velocidade de Ataque10% de Velocidade de MovimentoBorrãoEfeitos ao contato reduzem o Tempo de Recarga restante das suas habilidades de Avanço e Teleporte em 12% (redução de 4% para ultimates).', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447100.png'),
(447101, 'Lâmina do Apostador', '60% de Velocidade de Ataque40 de Aceleração de Habilidade8% de Velocidade de MovimentoDinheiro no BancoSeus Ataques e Habilidades têm 10% de chance de armazenar 30 - 240 de ouro ao atingir um inimigo. Ao vencer uma rodada, recebe o ouro. Ao perder uma rodada, perde 25% do ouro armazenado.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447101.png'),
(447102, 'Fenda Dimensional', '80 de Poder de Habilidade40% de Velocidade de Ataque300 de VidaZz\'Rot (0s)Ao Atacar ou ao causar dano a um inimigo com uma Habilidade, invoca 3 Vastilarvas para Atacar o alvo. Vastilarvas causam 0 de Dano Mágico e vivem por até 5s.Ao morrer, você invoca 6 delas.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447102.png'),
(447103, 'Elmo do Hemomante', '60 de Dano de Ataque30 de Aceleração de Habilidade10% de Vampirismo UniversalLealdade CarmesimLimiar de 30% de Roubo de Vida/Vampirismo Universal: recebe 500 de Vida máxima. Drena 12% de todo o dano que inimigos próximos sofrerem.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447103.png'),
(447104, 'Medalhão Enervante', '80 de Poder de Habilidade25 de Aceleração de Habilidade200 de VidaPreenchimento da AlmaQualquer Habilidade conjurada a 800 de distância concede uma carga.Com 30 cargas, recebe 0 de Escudo, 0 de Poder de Habilidade e 0 de Velocidade de Movimento pelo resto da rodada.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447104.png'),
(447105, 'Promessa Empírea', '60 de Poder de Habilidade18% de Cura e Resistência do Escudo30 de Aceleração de Habilidade125% de Regeneração de Mana baseATIVOS (0s)VigilânciaTeleporta até o seu aliado e concede 0 de Escudo por 5s ao aterrissar. Pode ser utilizado quando o Aliado estiver caído.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447105.png'),
(447106, 'Coração Dracônico', 'Chama InteriorAumenta sua Vida, Armadura, Resistência Mágica, Dano de Ataque, Poder de Habilidade, Velocidade de Ataque e Aceleração de Habilidade em 5%, aumentados em 5% para cada Alma de Dragão que você tiver.A cada 2 rodadas, recebe uma Alma de Dragão.Se já tiver todas as almas elementais, um poder ancestral despertará em você...Ao adquirir, se tiver passado da rodada 5, recebe imediatamente 1 alma, com mais 1 para cada 2 rodadas além da rodada 5.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447106.png'),
(447107, 'Decapitador', '70 de Força Adaptativa50% de Velocidade de Ataque12% de Velocidade de MovimentoAtaques e Habilidades concedem acúmulos (exceto ultimate). Recebe dano de ultimate e Aceleração de Habilidade de ultimate por acúmulo.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447107.png'),
(447108, 'Criarrunas', '80 de Poder de Habilidade20 de Aceleração de Habilidade8% de Velocidade de MovimentoHélixCausar dano com uma habilidade concede 40 acúmulos de Energizar e aciona Ataques Energizados se estiverem prontos.DetonarAo usar um Ataque Energizado, recebe um acúmulo de Runa pelo resto da rodada. Depois, dispara um projétil no alvo para cada acúmulo de Runa, causando 0 de Dano Mágico por projétil.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447108.png'),
(447109, 'Crueldade', '100 de Poder de Habilidade30 de Armadura30 de Resistência MágicaTestemunhe a QuedaAo Imobilizar um Campeão inimigo, invoca um cometa sobre ele. O cometa atinge o alvo após 1s, causando 0 de Dano Mágico adicional na área. O efeito tem um Tempo de Recarga de 5s por alvo por conjuração.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447109.png'),
(447110, 'Lâmina Enfeitiçada Moonflair', '70 de Poder de Habilidade350 de Vida30% de TenacidadeImplacávelAo usar uma Habilidade, redefine seu temporizador de ataque básico e recebe 90% de Velocidade de Ataque nos próximos 2 Ataques.Ao Atacar, reduz o Tempo de Recarga das Habilidades em 0.5s.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447110.png'),
(447111, 'Armadura Sangrenta do Suserano', '45 de Dano de Ataque500 de VidaTiraniaRecebe 0 de DdA equivalente a 3% da Vida adicional.VingançaRecebe até 12% de DdA aumentado com base no percentual de Vida perdida.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447111.png'),
(447112, 'Comecarne', '70 de Força Adaptativa18 de Letalidade18 de Penetração MágicaCarne DespedaçadaCausar dano fragmenta 2 de Armadura e Resistência Mágica por 5s, acumulando até 10 vezes. A aplicação de acúmulos tem 1s de Tempo de Recarga por alvo.CanibalizarAo eliminar um Campeão, cura você e um aliado em 12% da Vida máxima do alvo.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447112.png'),
(447113, 'Orbe de Detonação', '100 de Poder de Habilidade15 de Penetração Mágica400 de Mana20 de Aceleração de HabilidadeA BombaHabilidades de dano marcam o alvo, armazenando 20% do dano causado (aumentado para 30% contra inimigos Imobilizados). 3s depois de ter causado dano ao alvo com uma habilidade, detona o dano armazenado nele. Se, em algum momento, o dano for suficiente para matá-lo, detona imediatamente.', 1000, 'https://ddragon.leagueoflegends.com/cdn/16.9.1/img/item/447113.png');
INSERT INTO `runas` (`ID_runa`, `nome_runa`, `nome_arvore`, `descricao`, `imagem_url`, `slot`) VALUES
(8005, 'Pressione o Ataque', 'Precisão', 'Atingir um Campeão 3 vezes consecutivas o deixa vulnerável, causando dano adicional e fazendo com que ele receba mais dano de todas as fontes por 6s.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/PressTheAttack/PressTheAttack.png', 0),
(8008, 'Ritmo Fatal', 'Precisão', 'Recebe Velocidade de Ataque ao atacar um Campeão inimigo, acumulando até 6 vezes. Com o máximo de acúmulos, recebe Alcance de Ataque e remove seu limite de Velocidade de Ataque.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/LethalTempo/LethalTempoTemp.png', 0),
(8009, 'Presença de Espírito', 'Precisão', 'Aumenta sua Regeneração de Mana ou de Energia quando causar dano a um Campeão inimigo. Eliminações restauram Mana ou Energia.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/PresenceOfMind/PresenceOfMind.png', 1),
(8010, 'Conquistador', 'Precisão', 'Ganha acúmulos de Força Adaptativa ao atacar Campeões inimigos. Após alcançar 12 acúmulos, cura uma parte do dano causado a Campeões.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/Conqueror/Conqueror.png', 0),
(8014, 'Golpe de Misericórdia', 'Precisão', 'Causa mais dano a Campeões inimigos com pouca Vida.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/CoupDeGrace/CoupDeGrace.png', 3),
(8017, 'Dilacerar', 'Precisão', 'Causa mais dano a Campeões que tenham mais Vida máxima do que você.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/CutDown/CutDown.png', 3),
(8021, 'Agilidade nos Pés', 'Precisão', 'Atacar e se movimentar geram acúmulos de Energia. Com 100 acúmulos, seu próximo ataque cura você e concede um aumento de VdM.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/FleetFootwork/FleetFootwork.png', 0),
(8105, 'Caça Incansável', 'Dominação', 'Abates únicos concedem VdM permanente fora de combate. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/RelentlessHunter/RelentlessHunter.png', 3),
(8106, 'Caça Suprema', 'Dominação', 'Abates únicos concedem Redução de Tempo de Recarga permanente para a ultimate. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/UltimateHunter/UltimateHunter.png', 3),
(8112, 'Eletrocutar', 'Dominação', 'Acertar um Campeão com 3 ataques ou habilidades separadas em 3s causa Dano Adaptativo adicional.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/Electrocute/Electrocute.png', 0),
(8120, 'Poro Fantasma', 'Dominação', 'Quando suas sentinelas expiram, elas deixam para trás um Poro Fantasma, que concede visão até ser descoberto. Você recebe permanentemente DdA ou PdH adaptativos por cada Poro Fantasma e quando ele avi', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/GhostPoro/GhostPoro.png', 2),
(8124, 'Predador', 'Dominação', 'Adiciona um efeito ativo às suas botas que concede um enorme aumento de VdM e faz com que seu próximo ataque ou habilidade cause Dano Adaptativo adicional.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/Predator/Predator.png', 0),
(8126, 'Golpe Desleal', 'Dominação', 'Causa Dano Verdadeiro adicional a Campeões inimigos com mobilidade ou ações debilitadas. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/CheapShot/CheapShot.png', 1),
(8128, 'Colheita Sombria', 'Dominação', 'Causar dano a um Campeão que está com pouca Vida inflige Dano Adaptativo e colhe a alma de sua vítima.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/DarkHarvest/DarkHarvest.png', 0),
(8134, 'Caça Ardilosa', 'Dominação', 'Eliminações únicas  concedem Aceleração de Item permanente (inclui Amuletos).', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/IngeniousHunter/IngeniousHunter.png', 3),
(8135, 'Caçador de Tesouros', 'Dominação', 'Eliminações únicas concedem ouro adicional na primeira vez que são coletadas. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/TreasureHunter/TreasureHunter.png', 3),
(8136, 'Sentinela Zumbi', 'Dominação', 'Abates de sentinelas inimigas fazem com que unidades de Sentinela Zumbi aliadas cresçam do cadáver. Recebe permanentemente DdA ou PdH adaptativo por cada Sentinela Zumbi posicionada, além de adicionai', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/ZombieWard/ZombieWard.png', 2),
(8137, 'Sexto Sentido', 'Dominação', 'Com um longo Tempo de Recarga, detecta automaticamente uma sentinela oculta próxima, rastreando-a para a equipe. Nível 11: também revela a sentinela por 10s.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/SixthSense/SixthSense.png', 0),
(8138, 'Globos Oculares', 'Dominação', 'Coleta Globos Oculares ao abater Campeões e recebe permanentemente DdA ou PdH adaptativos por cada Globo Ocular coletado, além de adicionais ao completar a coleção.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/EyeballCollection/EyeballCollection.png', 2),
(8139, 'Gosto de Sangue', 'Dominação', 'Cura ao causar dano a um Campeão inimigo.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/TasteOfBlood/GreenTerror_TasteOfBlood.png', 1),
(8140, 'Lembranças Aterrorizantes', 'Dominação', 'Colete 1 Lembranças ao eliminar Campeões, até um máximo de 18.Recebe 6 de Aceleração de Amuleto para cada Lembrança coletada.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/GrislyMementos/GrislyMementos.png', 0),
(8141, 'Sentinela Profunda', 'Dominação', 'Suas sentinelas na selva inimiga são Profundas, recebendo Vida e Duração.Nível 9: As sentinelas no rio também são Profundas.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/DeepWard/DeepWard.png', 0),
(8143, 'Impacto Repentino', 'Dominação', 'Depois de usar um avanço, salto, teletransporte, teleporte ou ao sair da furtividade, você ganha uma quantidade súbita de Letalidade e Penetração Mágica.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/SuddenImpact/SuddenImpact.png', 1),
(8210, 'Transcendência', 'Feitiçaria', 'Recebe efeitos adicionais ao atingir os seguintes níveis:Nível 5: +5 de Aceleração de Habilidade Nível 8: +5 de Aceleração de Habilidade Nível 11: ao eliminar um Campeão inimigo, reduz o Tempo de Reca', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/Transcendence/Transcendence.png', 2),
(8214, 'Invocar Aery', 'Feitiçaria', 'Seus ataques e habilidades enviam Aery até um alvo, causando dano a inimigos ou protegendo aliados com um escudo.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/SummonAery/SummonAery.png', 0),
(8224, 'Arcanista do Axioma', 'Feitiçaria', 'Recebe um escudo de Dano Mágico quando ficar com pouca Vida ao ser atingido por Dano Mágico.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/NullifyingOrb/Pokeshield.png', 1),
(8226, 'Faixa de Fluxo de Mana', 'Feitiçaria', 'Atingir um Campeão inimigo com uma habilidade aumenta permanentemente seu Mana máximo em 25, até o total de 250 de Mana.Após atingir 250 de Mana adicional, 1% da seu Mana perdido é restaurado a cada 5', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/ManaflowBand/ManaflowBand.png', 1),
(8229, 'Cometa Arcano', 'Feitiçaria', 'Ao causar dano a um Campeão com uma habilidade, um cometa é lançado onde ele estiver.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/ArcaneComet/ArcaneComet.png', 0),
(8230, 'Avanço da Tempestade', 'Feitiçaria', 'Atingir um Campeão inimigo com 3 Ataques ou Habilidades diferentes concede um impulso de VdM. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/PhaseRush/PhaseRush.png', 0),
(8232, 'Caminhar Sobre as Águas', 'Feitiçaria', 'Concede VdM e PdH ou DdA Adaptativos no rio.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/Waterwalking/Waterwalking.png', 3),
(8233, 'Foco Absoluto', 'Feitiçaria', 'Acima de 70% de Vida, recebe Dano Adaptativo adicional.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/AbsoluteFocus/AbsoluteFocus.png', 2),
(8234, 'Celeridade', 'Feitiçaria', 'Todos os efeitos de Velocidade de Movimento adicional são 7% mais eficazes em você, além de conceder 1% de Velocidade de Movimento.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/Celerity/CelerityTemp.png', 2),
(8236, 'Tempestade Crescente', 'Feitiçaria', 'Recebe quantidades crescentes de DdA ou PdH Adaptativo ao longo da partida.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/GatheringStorm/GatheringStorm.png', 3),
(8237, 'Chamuscar', 'Feitiçaria', 'Sua primeira habilidade de dano a atingir o alvo a cada 10s incinerará Campeões.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/Scorch/Scorch.png', 3),
(8242, 'Inabalável', 'Determinação', 'Ganha um pouco de Tenacidade que aumenta de acordo com a Vida perdida. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/Unflinching/Unflinching.png', 3),
(8275, 'Manto de Nimbus', 'Feitiçaria', 'Após conjurar um Feitiço de Invocador, concede um breve aumento de Velocidade de Movimento que permite atravessar unidades.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/NimbusCloak/6361.png', 1),
(8299, 'Até a Morte', 'Precisão', 'Cause mais dano a Campeões enquanto estiver com pouca Vida.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/LastStand/LastStand.png', 3),
(8304, 'Calçados Mágicos', 'Inspiração', 'Concede botas gratuitamente aos 12 mins, mas não é possível comprar botas antes disso. Cada abate bem-sucedido faz suas botas virem 45s mais cedo.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/MagicalFootwear/MagicalFootwear.png', 1),
(8306, 'Flashtração Hextec', 'Inspiração', 'Enquanto o Flash estiver em Tempo de Recarga, ele é substituído pelo Flash Hextec.Flash Hextec: canalize e depois se teletransporte para um novo local.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/HextechFlashtraption/HextechFlashtraption.png', 1),
(8313, 'Tônico Triplo', 'Inspiração', 'Ao alcançar o nível 3, recebe um Elixir da Avareza.Ao alcançar o nível 6, recebe um Elixir da Força.Ao alcançar o nível 9, recebe um Elixir da Habilidade. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/PerfectTiming/AlchemistCabinet.png', 1),
(8316, 'Quebra-galho', 'Inspiração', 'Inicia a partida com 3 unidades de Pulverizador de Tropas. Abater tropas com este item concede dano adicional permanente contra o tipo de tropa abatido.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/MinionDematerializer/MinionDematerializer.png', 2),
(8321, 'Reembolso', 'Inspiração', 'Você pode ficar em débito para comprar itens.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/FuturesMarket/FuturesMarket.png', 2),
(8345, 'Entrega de Biscoitos', 'Inspiração', 'Ganha um Biscoito grátis a cada 2min, até o minuto 6. Consumir ou vender Biscoitos aumenta permanentemente seu Mana máximo e restaura Vida e Mana.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/BiscuitDelivery/BiscuitDelivery.png', 2),
(8347, 'Perspicácia Cósmica', 'Inspiração', '+18 de Aceleração de Feitiço de Invocador+10 de Aceleração de Item', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/CosmicInsight/CosmicInsight.png', 3),
(8351, 'Aprimoramento Glacial', 'Inspiração', 'Imobilizar um Campeão inimigo invocará 3 raios glaciais que causam Lentidão a inimigos próximos e reduzem o dano deles contra seus aliados.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/GlacialAugment/GlacialAugment.png', 0),
(8352, 'Tônico de Distorção no Tempo', 'Inspiração', 'Poções e biscoitos concedem um pouco de restauração imediatamente. Recebe VdM enquanto sob seus efeitos.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/TimeWarpTonic/TimeWarpTonic.png', 3),
(8360, 'Livro de Feitiços Deslacrado', 'Inspiração', 'Troque Feitiços de Invocador enquanto estiver fora de combate. Trocar para Feitiços de Invocador únicos aumentará a frequência com que você poderá fazer trocas futuras.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/UnsealedSpellbook/UnsealedSpellbook.png', 0),
(8369, 'Primeiro Ataque', 'Inspiração', 'Ao iniciar um combate contra um Campeão, você causa 7% de dano adicional por 3s e recebe ouro com base no dano causado.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Inspiration/FirstStrike/FirstStrike.png', 0),
(8401, 'Golpe de Escudo', 'Determinação', 'Sempre que receber um escudo, seu próximo ataque básico contra um Campeão causará Dano Adaptativo adicional.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/MirrorShell/MirrorShell.png', 1),
(8410, 'Velocidade de Aproximação', 'Inspiração', 'VdM adicional em direção a Campeões inimigos próximos com movimento debilitado, aumentada em Campeões inimigos cujo movimento você debilitou.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/ApproachVelocity/ApproachVelocity.png', 3),
(8429, 'Condicionamento', 'Determinação', 'Depois de 12min, recebe +8 de Armadura e +8 de Resistência Mágica, e aumenta sua Armadura e Resistência Mágica em 3%.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/Conditioning/Conditioning.png', 2),
(8437, 'Aperto dos Mortos-Vivos', 'Determinação', 'A cada 4s, seu próximo ataque contra um Campeão causa Dano Mágico adicional, cura você e aumenta permanentemente sua Vida.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/GraspOfTheUndying/GraspOfTheUndying.png', 0),
(8439, 'Pós-choque', 'Determinação', 'Após imobilizar um Campeão inimigo, ganha defesas e depois causa um ataque de Dano Mágico explosivo ao seu redor.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/VeteranAftershock/VeteranAftershock.png', 0),
(8444, 'Ventos Revigorantes', 'Determinação', 'Após receber dano de um Campeão inimigo, um pouco da Vida perdida é restaurada ao longo do tempo. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/SecondWind/SecondWind.png', 2),
(8446, 'Demolir', 'Determinação', 'Carrega um poderoso ataque contra uma torre enquanto estiver perto dela.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/Demolish/Demolish.png', 1),
(8451, 'Crescimento Excessivo', 'Determinação', 'Recebe Vida máxima permanente quando tropas inimigas ou monstros são abatidos perto de você.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/Overgrowth/Overgrowth.png', 3),
(8453, 'Revitalizar', 'Determinação', 'Recebe 5% de Cura e Resistência do Escudo.Curas e Escudos conjurados ou recebidos são 10% mais fortes em alvos com menos de 40% de Vida.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/Revitalize/Revitalize.png', 3),
(8463, 'Fonte da Vida', 'Determinação', 'Debilitar o movimento de um Campeão inimigo o deixa marcado. Seus aliados são curados quando atacam Campeões marcados por você. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/FontOfLife/FontOfLife.png', 1),
(8465, 'Guardião', 'Determinação', 'Protege aliados nos quais você conjurou habilidades e aliados muito próximos a você. Se você ou um Campeão aliado protegido sofrer dano com base no nível, ambos recebem um escudo.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/Guardian/Guardian.png', 0),
(8473, 'Osso Revestido', 'Determinação', 'Após sofrer dano de um Campeão inimigo, os próximos 3 ataques ou habilidades que você sofrer dele causarão de 30 a 60 a menos de dano.Duração: 1.5sTempo de Recarga: 55s', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Resolve/BonePlating/BonePlating.png', 2),
(8992, 'Toque Ígneo', 'Feitiçaria', 'Causar dano a um Campeão com uma habilidade o queima ao longo do tempo.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Sorcery/DeathfireTouch/DEATHFIRE_TOUCH_KEYSTONE.png', 0),
(9101, 'Absorção Vital', 'Precisão', 'A cura excedente sobre você é convertida em um escudo.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/Overheal.png', 1),
(9103, 'Lenda: Linhagem', 'Precisão', 'Abates de inimigos concedem Roubo de Vida permanente até um limite. Quando o limite é atingido, aumentam sua Vida máxima. Fraco no começo mas fica mais forte do que as outras runas Lenda no fim de jog', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/LegendBloodline/LegendBloodline.png', 2),
(9104, 'Lenda: Espontaneidade', 'Precisão', 'Abates em inimigos concedem Velocidade de Ataque permanente. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/LegendAlacrity/LegendAlacrity.png', 2),
(9105, 'Lenda: Aceleração', 'Precisão', 'Abates em inimigos concedem Tenacidade permanente. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/LegendTenacity/LegendTenacity.png', 2),
(9111, 'Triunfo', 'Precisão', 'Abates restauram 5% da sua Vida perdida e concedem 20 de ouro adicional. ', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Precision/Triumph.png', 1),
(9923, 'Chuva de Lâminas', 'Dominação', 'Concede uma grande quantidade de Velocidade de Ataque pelos primeiros 3 ataques contra Campeões inimigos.', 'https://ddragon.leagueoflegends.com/cdn/img/perk-images/Styles/Domination/HailOfBlades/HailOfBlades.png', 0);
