INSERT INTO `spells` (`ID_spell`, `nome`, `descricao`, `cooldown`, `imagem_url`) VALUES
(1, 'Purificar', 'Remove todos os desarmes (menos supressão e arremessos ao ar) e efeitos negativos de Feitiços de Invocador que afetam seu Campeão, além de reduzir a duração de outros desarmes em 65% por 3s.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerBoost.png'),
(3, 'Exaustão', 'Exaure o Campeão-alvo inimigo, causando 30% de Lentidão e reduzindo o dano causado por ele em 35% por 3s.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerExhaust.png'),
(4, 'Flash', 'Teleporta seu Campeão por uma curta distância em direção ao seu cursor.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerFlash.png'),
(6, 'Fantasma', 'Seu Campeão pode atravessar unidades e recebe 24% - 48% de Velocidade de Movimento (com base no nível do Campeão) por 15s.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerHaste.png'),
(7, 'Curar', 'Cura 80 - 318 de Vida e concede 30% de Velocidade de Movimento por 1s a você e ao Campeão-alvo aliado. Essa cura é reduzida pela metade para unidades afetadas recentemente pelo Feitiço de Invocador de Cura.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerHeal.png'),
(11, 'Golpear', 'Causa 600 - 1.200 de Dano Verdadeiro a um alvo monstro.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerSmite.png'),
(12, 'Teleporte', 'Após canalizar por 4s, teleporta seu Campeão para a estrutura-alvo aliada. Aprimora para Teleporte Irrestrito aos 10min, levando o Campeão para a estrutura, tropa ou sentinela-alvo aliada.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerTeleport.png'),
(13, 'Clareza', 'Restaura 50% da Mana máxima do seu Campeão. Também restaura 25% da Mana máxima de aliados.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerMana.png'),
(14, 'Incendiar', 'Incendeia o Campeão-alvo inimigo, causando 70 - 410 de Dano Verdadeiro (dependendo do nível do Campeão) ao longo de 5s, concedendo visão do alvo e reduzindo os efeitos de cura dele enquanto durar o efeito.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerDot.png'),
(21, 'Barreira', 'Protege seu Campeão contra 105 - 411 de dano (dependendo do nível do Campeão) por 2s.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerBarrier.png'),
(30, 'Ao Rei!', 'Faz rapidamente o trajeto em direção ao Rei Poro.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerPoroRecall.png'),
(31, 'Arremesso de Poro', 'Arremessa um Poro em seus inimigos. Caso atinja alguém, você pode deslocar-se rapidamente até seu alvo na sequência.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerPoroThrow.png'),
(32, 'Marca', 'Arremessa uma bola de neve em linha reta. Se atingir um inimigo, ele fica marcado, sendo revelado por Visão Mágica, e seu Campeão pode se deslocar rapidamente na direção dele logo em seguida.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerSnowball.png'),
(39, 'Marca', 'Arremessa uma bola de neve em linha reta. Se atingir um inimigo, ele fica marcado, sendo revelado por Visão Mágica, e seu Campeão pode se deslocar rapidamente na direção dele logo em seguida.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerSnowURFSnowball_Mark.png'),
(54, 'A definir', 'Este espaço será substituído pela ultimate de outro Campeão (selecionada no início da partida). Você terá 30s para selecionar uma ultimate. Prepare-se!', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/Summoner_UltBookPlaceholder.png'),
(55, 'Placeholder e Atacar', 'Este espaço será substituído pela ultimate de outro Campeão e você receberá Atacar-Golpear. Você terá 30s para selecionar uma ultimate. Prepare-se!', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/Summoner_UltBookSmitePlaceholder.png'),
(255, 'Flash', 'Teleporta seu Campeão por uma curta distância na direção do cursor.', 0, 'https://ddragon.leagueoflegends.com/cdn/14.1.1/img/spell/SummonerCherryFlash.png');
